  series: MultiAreaChartSeries[]
  className?: string
  showGrid?: boolean
  showTooltip?: boolean
  showCursor?: boolean
  showLegend?: boolean
  valueFormatter?: (value: number) => string
  labelFormatter?: (label: string) => string
  yAxisDomain?: [number, number]
  yAxisTicks?: number[]
  animate?: boolean
  strokeWidth?: number
  xAxisAngle?: number
  aspectRatio?: number
  curveType?: "linear" | "monotone" | "step"
  stacked?: boolean
  gradientOpacity?: [number, number]
