  yAxisTicks,
  animate = true,
  strokeWidth = 2,
  xAxisAngle = 0,
  aspectRatio = 2,
  curveType = "monotone",
  stacked = false,
  gradientOpacity = [0.6, 0.1],
}: MultiAreaChartProps) {
  const baseId = React.useId().replace(/:/g, "")

  // Calculate domain from all series data
  const calculatedDomain = React.useMemo(() => {
    if (yAxisDomain) return yAxisDomain
    const allValues = data.flatMap((d) =>
      series.map((s) => (d[s.dataKey] as number) || 0)
    )
    const min = Math.min(...allValues)
    const max = Math.max(...allValues)
    const padding = (max - min) * 0.1
    return [
      Math.max(0, Math.floor((min - padding) / 10) * 10),
      Math.ceil((max + padding) / 10) * 10,
    ] as [number, number]
  }, [data, series, yAxisDomain])

  const calculatedTicks = React.useMemo(() => {
    if (yAxisTicks) return yAxisTicks
    const [min, max] = calculatedDomain
    const step = (max - min) / 4
    return Array.from({ length: 5 }, (_, i) => Math.round(min + step * i))
  }, [calculatedDomain, yAxisTicks])

  return (
    <div className={cn("w-full", className)}>
      <ResponsiveContainer width="100%" aspect={aspectRatio}>
        <ComposedChart
          data={data}
          margin={{
            top: 20,
            right: 30,
            left: 10,
            bottom: xAxisAngle === 0 ? 20 : 60,
          }}
        >
          <defs>
            {series.map((s, i) => (
              <linearGradient
                key={s.dataKey}
                id={`gradient-${baseId}-${i}`}
                x1="0"
                y1="0"
                x2="0"
                y2="1"
              >
                <stop
                  offset="0%"
                  stopColor={s.gradientFrom || s.color}
                  stopOpacity={gradientOpacity[0]}
                />
                <stop
                  offset="100%"
                  stopColor={s.gradientTo || s.color}
                  stopOpacity={gradientOpacity[1]}
                />
              </linearGradient>
            ))}
            {/* Dot pattern overlay */}
            <pattern
              id={`pattern-${baseId}`}
              x="0"
              y="0"
              width="6"
              height="6"
              patternUnits="userSpaceOnUse"
            >
              <circle
                cx="1.5"
                cy="1.5"
                r="0.75"
                fill="rgba(255,255,255,0.25)"
              />
            </pattern>
          </defs>

          {showGrid && (
            <CartesianGrid
              strokeDasharray="3 3"
              vertical={true}
              horizontal={true}
              stroke="hsl(var(--border))"
              strokeOpacity={0.5}
            />
          )}

          <YAxis
            domain={calculatedDomain}
            ticks={calculatedTicks}
            tickFormatter={valueFormatter}
            axisLine={false}
            tickLine={false}
            tick={({ x, y, payload }) => (
              <text
                x={x}
                y={y}
                dy={4}
                textAnchor="end"
                className="fill-muted-foreground text-xs"
              >
                {valueFormatter(payload.value)}
              </text>
            )}
            width={50}
          />

          <XAxis
            dataKey="label"
            axisLine={false}
            tickLine={false}
            tick={({ x, y, payload }) => (
              <text
                x={x}
                y={y}
                dy={16}
                textAnchor="middle"
                className="fill-muted-foreground text-xs"
              >
                {labelFormatter(payload.value)}
              </text>
            )}
            height={xAxisAngle === 0 ? 30 : 60}
            interval={0}
          />

          {showTooltip && (
            <Tooltip
              cursor={
                showCursor
                  ? {
                      stroke: "hsl(var(--muted-foreground))",
                      strokeWidth: 1,
                      strokeDasharray: "4 4",
                    }
                  : false
              }
              content={({ active, payload, label }) => {
                if (!active || !payload?.length) return null
                return (
                  <div className="bg-background rounded-lg border px-3 py-2 shadow-lg">
                    <p className="text-foreground mb-1 text-sm font-medium">
                      {labelFormatter(label)}
                    </p>
                    {payload.map((entry, index) => (
                      <div
                        key={index}
                        className="flex items-center gap-2 text-sm"
                      >
                        <div
                          className="size-2 rounded-full"
                          style={{ backgroundColor: entry.color }}
                        />
                        <span className="text-muted-foreground">
                          {entry.name}:
                        </span>
                        <span style={{ color: entry.color }}>
                          {valueFormatter(entry.value as number)}
                        </span>
                      </div>
                    ))}
                  </div>
                )
              }}
            />
          )}

          {/* Render areas in reverse order so first series is on top */}
          {[...series].reverse().map((s, i) => (
            <Area
              key={`${s.dataKey}-fill`}
              type={curveType}
              dataKey={s.dataKey}
              name={s.name}
              stroke={s.color}
              strokeWidth={strokeWidth}
              fill={`url(#gradient-${baseId}-${series.length - 1 - i})`}
              fillOpacity={1}
              stackId={stacked ? "stack" : undefined}
              isAnimationActive={animate}
              animationBegin={i * 100}
              animationDuration={1500}
              animationEasing="ease-out"
              activeDot={{
                r: 4,
                fill: s.color,
                stroke: "hsl(var(--background))",
                strokeWidth: 2,
              }}
            />
          ))}

          {/* Dot pattern overlay for each series */}
          {[...series].reverse().map((s, i) => (
            <Area
              key={`${s.dataKey}-pattern`}
              type={curveType}
              dataKey={s.dataKey}
              stroke="none"
              fill={`url(#pattern-${baseId})`}
              fillOpacity={1}
              stackId={stacked ? "stack-pattern" : undefined}
              isAnimationActive={animate}
              animationBegin={i * 100}
              animationDuration={1500}
              animationEasing="ease-out"
              legendType="none"
              tooltipType="none"
            />
          ))}
        </ComposedChart>
      </ResponsiveContainer>

      {/* Legend */}
      {showLegend && (
        <div className="mt-4 flex flex-wrap items-center justify-center gap-4">
          {series.map((s) => (
            <div key={s.dataKey} className="flex items-center gap-2 text-sm">
              <div
                className="size-3 rounded-sm"
                style={{ backgroundColor: s.color }}
              />
              <span className="text-muted-foreground">{s.name}</span>
            </div>
          ))}
        </div>
      )}
    </div>
  )
}

"use client"

import * as React from "react"
import { scaleLinear } from "d3-scale"

import { cn } from "@/lib/utils"

import { ChartAxis } from "../chart-axis"
import type { BaseChartProps, ChartConfig } from "../chart-config"
import { ChartContainer } from "../chart-container"
import { ChartGrid } from "../chart-grid"
import { ChartLegend, type LegendItem } from "../chart-legend"
import { ChartTooltipContent } from "../chart-tooltip"

export interface ScatterChartDataPoint {
  x: number
  y: number
  size?: number
  label?: string
  [key: string]: unknown
}

export interface ScatterChartSeries {
  name: string
  data: ScatterChartDataPoint[]
  color?: string
  symbol?: "circle" | "square" | "triangle" | "diamond" | "cross"
  size?: number
}

export interface ScatterChartProps extends Omit<BaseChartProps, "config"> {
  data: ScatterChartSeries[]
  xAxisLabel?: string
  yAxisLabel?: string
  sizeRange?: [number, number]
  symbol?: "circle" | "square" | "triangle" | "diamond" | "cross"
  size?: number
  showTrendLine?: boolean
  config?: ChartConfig
}

// SVG path generators for different symbols
const symbolPaths: Record<string, (size: number) => string> = {
  circle: (s) => {
    const r = s / 2
    return `M 0,${-r} A ${r},${r} 0 1,1 0,${r} A ${r},${r} 0 1,1 0,${-r}`
  },
  square: (s) => {
    const h = s / 2
    return `M ${-h},${-h} L ${h},${-h} L ${h},${h} L ${-h},${h} Z`
  },
  triangle: (s) => {
    const h = s / 2
    return `M 0,${-h} L ${h},${h} L ${-h},${h} Z`
  },
  diamond: (s) => {
    const h = s / 2
    return `M 0,${-h} L ${h},0 L 0,${h} L ${-h},0 Z`
  },
  cross: (s) => {
    const h = s / 2
    const w = s / 6
    return `M ${-w},${-h} L ${w},${-h} L ${w},${-w} L ${h},${-w} L ${h},${w} L ${w},${w} L ${w},${h} L ${-w},${h} L ${-w},${w} L ${-h},${w} L ${-h},${-w} L ${-w},${-w} Z`
  },
}

export function ScatterChart({
  data,
  config,
  className,
  width = 600,
  height = 400,
  margin = { top: 20, right: 20, bottom: 50, left: 60 },
  showGrid = true,
  showTooltip = true,
  showLegend = true,
  xAxisLabel,
  yAxisLabel,
  sizeRange = [6, 20],
  symbol = "circle",
  size = 8,
  showTrendLine = false,
}: ScatterChartProps) {
  const [hoveredPoint, setHoveredPoint] = React.useState<{
    seriesIndex: number
    pointIndex: number
    x: number
    y: number
  } | null>(null)
  const [hoveredSeries, setHoveredSeries] = React.useState<string | null>(null)

  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom

  // Flatten all data points for scales
  const allPoints = data.flatMap((series) => series.data)

  // Scales
  const xScale = React.useMemo(() => {
    const xValues = allPoints.map((d) => d.x)
    const xMin = Math.min(...xValues)
    const xMax = Math.max(...xValues)
    const padding = (xMax - xMin) * 0.1
    return scaleLinear()
      .domain([xMin - padding, xMax + padding])
      .range([0, innerWidth])
      .nice()
  }, [allPoints, innerWidth])

  const yScale = React.useMemo(() => {
    const yValues = allPoints.map((d) => d.y)
    const yMin = Math.min(...yValues)
    const yMax = Math.max(...yValues)
    const padding = (yMax - yMin) * 0.1
    return scaleLinear()
      .domain([yMin - padding, yMax + padding])
      .range([innerHeight, 0])
      .nice()
  }, [allPoints, innerHeight])

  // Size scale for bubble chart
  const sizeScale = React.useMemo(() => {
    const sizeValues = allPoints.map((d) => d.size ?? 1)
    const sizeMin = Math.min(...sizeValues)
    const sizeMax = Math.max(...sizeValues)
    return scaleLinear().domain([sizeMin, sizeMax]).range(sizeRange)
  }, [allPoints, sizeRange])

  // Calculate trend line (simple linear regression)
  const trendLine = React.useMemo(() => {
    if (!showTrendLine) return null

    const n = allPoints.length
    if (n < 2) return null

    const sumX = allPoints.reduce((acc, d) => acc + d.x, 0)
    const sumY = allPoints.reduce((acc, d) => acc + d.y, 0)
    const sumXY = allPoints.reduce((acc, d) => acc + d.x * d.y, 0)
    const sumX2 = allPoints.reduce((acc, d) => acc + d.x * d.x, 0)

    const slope = (n * sumXY - sumX * sumY) / (n * sumX2 - sumX * sumX)
    const intercept = (sumY - slope * sumX) / n

    const xDomain = xScale.domain()
    return {
      x1: xDomain[0],
      y1: slope * xDomain[0] + intercept,
      x2: xDomain[1],
      y2: slope * xDomain[1] + intercept,
    }
  }, [allPoints, showTrendLine, xScale])

  // Legend items
  const legendItems: LegendItem[] = data.map((series) => ({
    name: series.name,
    color: series.color ?? "hsl(var(--foreground))",
  }))

  return (
    <ChartContainer
      config={config}
      className={cn("!aspect-auto flex-col", className)}
    >
      <svg
        viewBox={`0 0 ${width} ${height}`}
        className="w-full overflow-visible"
      >
        <g transform={`translate(${margin.left}, ${margin.top})`}>
          {/* Grid */}
          {showGrid && (
            <ChartGrid
              xScale={xScale}
              yScale={yScale}
              width={innerWidth}
              height={innerHeight}
            />
          )}

          {/* Trend line */}
          {trendLine && (
            <line
              x1={xScale(trendLine.x1)}
              y1={yScale(trendLine.y1)}
              x2={xScale(trendLine.x2)}
              y2={yScale(trendLine.y2)}
              stroke="currentColor"
              strokeWidth={2}
              strokeDasharray="6,4"
              className="text-muted-foreground/50"
            />
          )}

          {/* Points */}
          {data.map((series, seriesIndex) => {
            const seriesColor = series.color ?? "hsl(var(--foreground))"
            const seriesSymbol = series.symbol ?? symbol
            const isSeriesHovered =
              hoveredSeries === null || hoveredSeries === series.name

            return series.data.map((point, pointIndex) => {
              const pointSize =
                point.size !== undefined
                  ? sizeScale(point.size)
                  : (series.size ?? size)
              const isHovered =
                hoveredPoint?.seriesIndex === seriesIndex &&
                hoveredPoint?.pointIndex === pointIndex

              return (
                <g
                  key={`${seriesIndex}-${pointIndex}`}
                  transform={`translate(${xScale(point.x)}, ${yScale(point.y)})`}
                  className={cn(
                    "cursor-pointer transition-all duration-200",
                    !isSeriesHovered && "opacity-30"
                  )}
                  onMouseEnter={() =>
                    setHoveredPoint({
                      seriesIndex,
                      pointIndex,
                      x: xScale(point.x),
                      y: yScale(point.y),
                    })
                  }
                  onMouseLeave={() => setHoveredPoint(null)}
                >
                  <path
                    d={symbolPaths[seriesSymbol](
                      isHovered ? pointSize * 1.3 : pointSize
                    )}
                    fill={seriesColor}
                    stroke="white"
                    strokeWidth={1}
                  />
                </g>
              )
            })
          })}

          {/* X Axis */}
          <ChartAxis
            scale={xScale}
            orientation="bottom"
            transform={`translate(0, ${innerHeight})`}
            label={xAxisLabel}
          />

          {/* Y Axis */}
          <ChartAxis scale={yScale} orientation="left" label={yAxisLabel} />
        </g>
      </svg>

      {/* Tooltip */}
      {showTooltip && hoveredPoint && (
        <div
          className="pointer-events-none absolute z-50"
          style={{
            left: margin.left + hoveredPoint.x + 15,
            top: margin.top + hoveredPoint.y - 10,
          }}
        >
          <div className="border-border/50 bg-background rounded-lg border px-2.5 py-1.5 text-xs shadow-xl">
            <div className="mb-1 font-medium">
              {data[hoveredPoint.seriesIndex].data[hoveredPoint.pointIndex]
                .label ?? data[hoveredPoint.seriesIndex].name}
            </div>
            <div className="text-muted-foreground">
              x:{" "}
              {data[hoveredPoint.seriesIndex].data[
                hoveredPoint.pointIndex
              ].x.toLocaleString()}
            </div>
            <div className="text-muted-foreground">
              y:{" "}
              {data[hoveredPoint.seriesIndex].data[
                hoveredPoint.pointIndex
              ].y.toLocaleString()}
            </div>
          </div>
        </div>
      )}

      {/* Legend */}
      {showLegend && data.length > 1 && (
        <ChartLegend items={legendItems} onItemHover={setHoveredSeries} />
      )}
    </ChartContainer>
  )
}

"use client"

import * as React from "react"
import { arc, pie, type PieArcDatum } from "d3-shape"

import { cn } from "@/lib/utils"

import type { BaseChartProps, ChartConfig } from "../chart-config"
import { ChartContainer } from "../chart-container"
import { ChartLegend, type LegendItem } from "../chart-legend"

// ============================================================================
// Types & Interfaces
// ============================================================================

export interface PieChartDataPoint {
  label: string
  value: number
  color?: string
  [key: string]: unknown
}

export interface PieChartProps extends BaseChartProps {
  /** Data points for the pie chart */
  data: PieChartDataPoint[]
  /** Inner radius (0 for pie, > 0 for donut) */
  innerRadius?: number
  /** Outer radius */
  outerRadius?: number
  /** Padding angle between segments */
  padAngle?: number
  /** Corner radius for rounded segments */
  cornerRadius?: number
  /** Starting angle in radians */
  startAngle?: number
  /** Ending angle in radians */
  endAngle?: number
  /** Sort values by size */
  sortValues?: boolean
  /** Show labels on segments */
  showLabels?: boolean
  /** Label display type */
  labelType?: "percent" | "value" | "label"
  /** Chart variant */
  variant?:
    | "default"
    | "donut"
    | "donut-active"
    | "donut-text"
    | "label"
    | "interactive"
  /** Active segment index (for donut-active variant) */
  activeIndex?: number
  /** Center label text (for donut-text variant) */
  centerLabel?: React.ReactNode
  /** Center value text (for donut-text variant) */
  centerValue?: React.ReactNode
  /** Show total in center (for donut-text variant) */
  showTotal?: boolean
  /** Value formatter */
  valueFormatter?: (value: number, total: number) => string
  /** Callback when segment is clicked */
  onSegmentClick?: (data: PieChartDataPoint, index: number) => void
  /** Interactive selection options (for interactive variant) */
  selectionOptions?: { key: string; label: string }[]
  /** Selected key (for interactive variant) */
  selectedKey?: string
  /** On selection change (for interactive variant) */
  onSelectionChange?: (key: string) => void
}

// ============================================================================
// Constants
// ============================================================================

const DEFAULT_COLORS = [
  "hsl(var(--chart-1))",
  "hsl(var(--chart-2))",
  "hsl(var(--chart-3))",
  "hsl(var(--chart-4))",
  "hsl(var(--chart-5))",
]

// ============================================================================
// Component
// ============================================================================

export function PieChart({
  data,
  config,
  className,
  width = 400,
  height = 400,
  margin: marginProp,
  showTooltip = true,
  showLegend: showLegendProp,
  innerRadius: innerRadiusProp,
  outerRadius: outerRadiusProp,
  padAngle: padAngleProp,
  cornerRadius: cornerRadiusProp,
  startAngle = 0,
  endAngle = 2 * Math.PI,
  sortValues = false,
  showLabels: showLabelsProp,
  labelType = "percent",
  variant = "default",
  activeIndex: activeIndexProp,
  centerLabel,
  centerValue,
  showTotal = true,
  valueFormatter = (value, total) => `${((value / total) * 100).toFixed(1)}%`,
  onSegmentClick,
  selectionOptions,
  selectedKey,
  onSelectionChange,
}: PieChartProps) {
  const [hoveredIndex, setHoveredIndex] = React.useState<number | null>(null)
  const [internalActiveIndex, setInternalActiveIndex] = React.useState(0)
  const [internalSelectedKey, setInternalSelectedKey] = React.useState(
    selectedKey ?? selectionOptions?.[0]?.key ?? ""
  )

  // Variant-specific defaults
  const getVariantDefaults = () => {
    switch (variant) {
      case "donut":
        return {
          innerRadius: 60,
          padAngle: 0.02,
          cornerRadius: 0,
          showLabels: false,
          showLegend: true,
          margin: { top: 20, right: 20, bottom: 20, left: 20 },
        }
      case "donut-active":
        return {
          innerRadius: 60,
          padAngle: 0.02,
          cornerRadius: 0,
          showLabels: false,
          showLegend: true,
          margin: { top: 20, right: 20, bottom: 20, left: 20 },
        }
      case "donut-text":
        return {
          innerRadius: 60,
          padAngle: 0.02,
          cornerRadius: 0,
          showLabels: false,
          showLegend: true,
          margin: { top: 20, right: 20, bottom: 20, left: 20 },
        }
      case "label":
        return {
          innerRadius: 0,
          padAngle: 0.02,
          cornerRadius: 0,
          showLabels: true,
          showLegend: true,
          margin: { top: 40, right: 40, bottom: 40, left: 40 },
        }
      case "interactive":
        return {
          innerRadius: 60,
          padAngle: 0.02,
          cornerRadius: 0,
          showLabels: false,
          showLegend: false,
          margin: { top: 20, right: 20, bottom: 20, left: 20 },
        }
      default:
        return {
          innerRadius: 0,
          padAngle: 0.02,
          cornerRadius: 4,
          showLabels: false,
          showLegend: true,
          margin: { top: 20, right: 20, bottom: 20, left: 20 },
        }
    }
  }

  const defaults = getVariantDefaults()
  const margin = marginProp ?? defaults.margin
  const innerRadius = innerRadiusProp ?? defaults.innerRadius
  const padAngle = padAngleProp ?? defaults.padAngle
  const cornerRadius = cornerRadiusProp ?? defaults.cornerRadius
  const showLabels = showLabelsProp ?? defaults.showLabels
  const showLegend = showLegendProp ?? defaults.showLegend

  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom
  const radius = Math.min(innerWidth, innerHeight) / 2
  const outerRadius = outerRadiusProp ?? radius

  // Handle interactive variant selection
  const effectiveSelectedKey = selectedKey ?? internalSelectedKey
  const handleSelectionChange = (key: string) => {
    setInternalSelectedKey(key)
    onSelectionChange?.(key)
    // Update active index when selection changes in interactive mode
    const newIndex = data.findIndex(
      (d) => d.label.toLowerCase() === key.toLowerCase()
    )
    if (newIndex >= 0) {
      setInternalActiveIndex(newIndex)
    }
  }

  // Calculate total
  const total = data.reduce((sum, d) => sum + d.value, 0)

  // Active index handling
  const activeIndex =
    variant === "donut-active" || variant === "interactive"
      ? (activeIndexProp ?? internalActiveIndex)
      : hoveredIndex

  // Create pie generator
  const pieGenerator = React.useMemo(() => {
    const gen = pie<PieChartDataPoint>()
      .value((d) => d.value)
      .padAngle(padAngle)
      .startAngle(startAngle)
      .endAngle(endAngle)

    if (sortValues) {
      return gen.sort((a, b) => b.value - a.value)
    }
    return gen.sort(null)
  }, [padAngle, startAngle, endAngle, sortValues])

  // Arc datum type
  type ArcDatum = PieArcDatum<PieChartDataPoint>

  // Create arc generators
  const arcGenerator = arc<ArcDatum>()
    .innerRadius(innerRadius)
    .outerRadius(outerRadius)
    .cornerRadius(cornerRadius)

  // Active arc (slightly larger)
  const activeArcGenerator = arc<ArcDatum>()
    .innerRadius(innerRadius)
    .outerRadius(outerRadius + 10)
    .cornerRadius(cornerRadius)

  // Interactive double-ring arc for active segment
  const interactiveOuterArcGenerator = arc<ArcDatum>()
    .innerRadius(outerRadius + 12)
    .outerRadius(outerRadius + 25)
    .cornerRadius(cornerRadius)

  // Label arc (for positioning external labels)
  const labelArcGenerator = arc<ArcDatum>()
    .innerRadius(outerRadius * 0.7)
    .outerRadius(outerRadius * 0.7)

  // External label arc (for label variant)
  const externalLabelArcGenerator = arc<ArcDatum>()
    .innerRadius(outerRadius + 15)
    .outerRadius(outerRadius + 15)

  const arcs = pieGenerator(data)

  // Get color for segment
  const getColor = (d: PieChartDataPoint, index: number): string => {
    if (d.color) return d.color
    const configItem = config?.[d.label]
    if (configItem && "color" in configItem && configItem.color) {
      return configItem.color
    }
    return DEFAULT_COLORS[index % DEFAULT_COLORS.length]
  }

  // Format label
  const formatLabel = (d: PieChartDataPoint): string => {
    switch (labelType) {
      case "percent":
        return valueFormatter(d.value, total)
      case "value":
        return d.value.toLocaleString()
      case "label":
        return d.label
      default:
        return ""
    }
  }

  // Legend items
  const legendItems: LegendItem[] = data.map((d, i) => ({
    name: d.label,
    color: getColor(d, i),
    value: d.value,
  }))

  // Center content for donut-text variant
  const displayedCenterValue = React.useMemo(() => {
    if (variant === "donut-text" || variant === "interactive") {
      if (activeIndex !== null) {
        return data[activeIndex]?.value.toLocaleString() ?? ""
      }
      return centerValue ?? (showTotal ? total.toLocaleString() : null)
    }
    return null
  }, [variant, activeIndex, data, centerValue, showTotal, total])

  const displayedCenterLabel = React.useMemo(() => {
    if (variant === "donut-text" || variant === "interactive") {
      if (activeIndex !== null) {
        return data[activeIndex]?.label ?? ""
      }
      return centerLabel ?? (showTotal ? "Total" : null)
    }
    return null
  }, [variant, activeIndex, data, centerLabel, showTotal])

  // Handle segment interaction
  const handleSegmentEnter = (index: number) => {
    if (variant === "donut-active" || variant === "interactive") {
      setInternalActiveIndex(index)
    }
    setHoveredIndex(index)
  }

  const handleSegmentLeave = () => {
    setHoveredIndex(null)
  }

  const handleSegmentClick = (d: PieChartDataPoint, index: number) => {
    onSegmentClick?.(d, index)
    if (variant === "interactive" && selectionOptions) {
      const option = selectionOptions.find(
        (o) => o.label.toLowerCase() === d.label.toLowerCase()
      )
      if (option) {
        handleSelectionChange(option.key)
      }
    }
  }

  return (
    <ChartContainer
      config={config}
      className={cn("relative !aspect-auto flex-col", className)}
    >
      {/* Interactive selector dropdown */}
      {variant === "interactive" && selectionOptions && (
        <div className="absolute top-4 right-4 z-10">
          <select
            value={effectiveSelectedKey}
            onChange={(e) => handleSelectionChange(e.target.value)}
            className="bg-background border-input text-foreground focus:ring-ring rounded-lg border px-3 py-1.5 text-sm shadow-sm focus:ring-2 focus:outline-none"
          >
            {selectionOptions.map((option) => (
              <option key={option.key} value={option.key}>
                {option.label}
              </option>
            ))}
          </select>
        </div>
      )}

      <div className="relative mx-auto aspect-square w-full max-w-[280px]">
        <svg
          viewBox={`0 0 ${width} ${height}`}
          className="h-full w-full overflow-visible"
        >
          <g
            transform={`translate(${margin.left + innerWidth / 2}, ${margin.top + innerHeight / 2})`}
          >
            {arcs.map((arcData, index) => {
              const isActive = activeIndex === index
              const isHovered = hoveredIndex === index
              const color = getColor(data[index], index)
              const shouldExpand =
                (variant === "donut-active" && isActive) ||
                (variant === "interactive" && isActive) ||
                (variant !== "donut-active" &&
                  variant !== "interactive" &&
                  isHovered)

              return (
                <g key={index}>
                  {/* Pie segment */}
                  <path
                    d={
                      (shouldExpand ? activeArcGenerator : arcGenerator)(
                        arcData
                      ) ?? ""
                    }
                    fill={color}
                    stroke="hsl(var(--background))"
                    strokeWidth={variant === "label" ? 0 : 2}
                    className={cn(
                      "cursor-pointer transition-all duration-200",
                      (activeIndex !== null || hoveredIndex !== null) &&
                        !isActive &&
                        !isHovered &&
                        "opacity-50"
                    )}
                    onMouseEnter={() => handleSegmentEnter(index)}
                    onMouseLeave={handleSegmentLeave}
                    onClick={() => handleSegmentClick(data[index], index)}
                  />

                  {/* Interactive outer ring for active segment */}
                  {variant === "interactive" && isActive && (
                    <path
                      d={interactiveOuterArcGenerator(arcData) ?? ""}
                      fill={color}
                      className="pointer-events-none"
                    />
                  )}

                  {/* Internal labels (for label variant) */}
                  {showLabels && variant === "label" && (
                    <text
                      transform={`translate(${labelArcGenerator.centroid(arcData)})`}
                      textAnchor="middle"
                      dominantBaseline="middle"
                      className="fill-foreground pointer-events-none text-[11px] font-medium"
                    >
                      {data[index].value}
                    </text>
                  )}

                  {/* External labels with lines (for label variant) */}
                  {variant === "label" && (
                    <g className="pointer-events-none">
                      {/* Label line */}
                      <polyline
                        points={(() => {
                          const posA = arcGenerator.centroid(arcData)
                          const posB =
                            externalLabelArcGenerator.centroid(arcData)
                          const midAngle =
                            (arcData.startAngle + arcData.endAngle) / 2
                          const posC = [
                            posB[0] + (midAngle < Math.PI ? 8 : -8),
                            posB[1],
                          ]
                          return `${posA[0]},${posA[1]} ${posB[0]},${posB[1]} ${posC[0]},${posC[1]}`
                        })()}
                        fill="none"
                        stroke="hsl(var(--muted-foreground))"
                        strokeWidth={1}
                        strokeOpacity={0.5}
                      />
                      {/* External label text */}
                      <text
                        transform={`translate(${externalLabelArcGenerator.centroid(arcData)})`}
                        textAnchor={
                          (arcData.startAngle + arcData.endAngle) / 2 < Math.PI
                            ? "start"
                            : "end"
                        }
                        dx={
                          (arcData.startAngle + arcData.endAngle) / 2 < Math.PI
                            ? 12
                            : -12
                        }
                        dominantBaseline="middle"
                        className="fill-muted-foreground text-[10px]"
                      >
                        {data[index].label}
                      </text>
                    </g>
                  )}
                </g>
              )
            })}

            {/* Center text for donut-text and interactive variants */}
            {(variant === "donut-text" || variant === "interactive") && (
              <g className="pointer-events-none">
                {displayedCenterValue && (
                  <text
                    textAnchor="middle"
                    dominantBaseline="middle"
                    y={displayedCenterLabel ? -8 : 0}
                    className="fill-foreground text-3xl font-bold"
                  >
                    {displayedCenterValue}
                  </text>
                )}
                {displayedCenterLabel && (
                  <text
                    textAnchor="middle"
                    dominantBaseline="middle"
                    y={displayedCenterValue ? 20 : 0}
                    className="fill-muted-foreground text-sm"
                  >
                    {displayedCenterLabel}
                  </text>
                )}
              </g>
            )}
          </g>
        </svg>

        {/* Tooltip */}
        {showTooltip && hoveredIndex !== null && variant !== "interactive" && (
          <div className="pointer-events-none absolute top-1/2 left-1/2 z-50 -translate-x-1/2 -translate-y-1/2">
            <div className="border-border/50 bg-background rounded-lg border px-3 py-2 text-sm shadow-xl">
              <div className="flex items-center gap-2">
                <div
                  className="h-3 w-3 rounded-sm"
                  style={{
                    backgroundColor: getColor(data[hoveredIndex], hoveredIndex),
                  }}
                />
                <span className="font-medium">{data[hoveredIndex].label}</span>
              </div>
              <div className="text-muted-foreground mt-1">
                {data[hoveredIndex].value.toLocaleString()} (
                {valueFormatter(data[hoveredIndex].value, total)})
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Legend */}
      {showLegend && (
        <ChartLegend
          items={legendItems}
          onItemHover={(name) => {
            const index = data.findIndex((d) => d.label === name)
            if (index >= 0) {
              handleSegmentEnter(index)
            } else {
              handleSegmentLeave()
            }
          }}
        />
      )}
    </ChartContainer>
  )
}

"use client"

import * as React from "react"
import { interpolate } from "d3-interpolate"
import { arc, pie, type PieArcDatum } from "d3-shape"

import { cn } from "@/lib/utils"

import type { BaseChartProps, ChartConfig } from "../chart-config"
import { ChartContainer } from "../chart-container"

export interface DonutChartDataPoint {
  label: string
  value: number
  color?: string
  [key: string]: unknown
}

export interface DonutChartProps extends BaseChartProps {
  data: DonutChartDataPoint[]
  /** Inner radius as ratio (0-1) of outer radius. 0.6 = 60% hollow */
  innerRadius?: number
  /** Padding angle between segments in radians */
  padAngle?: number
  /** Corner radius for rounded segments */
  cornerRadius?: number
  /** Starting angle in radians (0 = top) */
  startAngle?: number
  /** Ending angle in radians */
  endAngle?: number
  /** Sort segments by value */
  sortValues?: boolean
  /** Show percentage labels on segments */
  showLabels?: boolean
  /** Show label lines for small segments */
  showLabelLines?: boolean
  /** Minimum angle (radians) to show inline label */
  minLabelAngle?: number
  /** Center text (top line) */
  centerLabel?: React.ReactNode
  /** Center value (large text) */
  centerValue?: React.ReactNode
  /** Animate on mount */
  animate?: boolean
  /** Animation duration in ms */
  animationDuration?: number
  /** Active/selected segment index */
  activeIndex?: number
  /** Callback when segment is clicked */
  onSegmentClick?: (data: DonutChartDataPoint, index: number) => void
  /** Value formatter for tooltip and labels */
  valueFormatter?: (value: number, total: number) => string
  /** Show total in center when nothing hovered */
  showTotal?: boolean
  /** Variant style */
  variant?: "default" | "gradient" | "separated"
}

// Default colors
const DEFAULT_COLORS = [
  "hsl(var(--chart-1))",
  "hsl(var(--chart-2))",
  "hsl(var(--chart-3))",
  "hsl(var(--chart-4))",
  "hsl(var(--chart-5))",
]

export function DonutChart({
  data,
  config,
  className,
  width = 400,
  height = 400,
  margin = { top: 40, right: 40, bottom: 40, left: 40 },
  showTooltip = true,
  showLegend = true,
  innerRadius: innerRadiusRatio = 0.6,
  padAngle = 0.02,
  cornerRadius = 4,
  startAngle = -Math.PI / 2,
  endAngle = Math.PI * 1.5,
  sortValues = false,
  showLabels = false,
  showLabelLines = true,
  minLabelAngle = 0.4,
  centerLabel,
  centerValue,
  animate = true,
  animationDuration = 750,
  activeIndex: controlledActiveIndex,
  onSegmentClick,
  valueFormatter = (value, total) => `${((value / total) * 100).toFixed(1)}%`,
  showTotal = true,
  variant = "default",
}: DonutChartProps) {
  const [hoveredIndex, setHoveredIndex] = React.useState<number | null>(null)
  const [animationProgress, setAnimationProgress] = React.useState(
    animate ? 0 : 1
  )
  const [tooltipData, setTooltipData] = React.useState<{
    x: number
    y: number
    data: DonutChartDataPoint
    index: number
  } | null>(null)

  const containerRef = React.useRef<HTMLDivElement>(null)
  const gradientId = React.useId().replace(/:/g, "")

  // Animation
  React.useEffect(() => {
    if (!animate) return

    const startTime = Date.now()
    const animateFrame = () => {
      const elapsed = Date.now() - startTime
      const progress = Math.min(elapsed / animationDuration, 1)
      // Ease out cubic
      const eased = 1 - Math.pow(1 - progress, 3)
      setAnimationProgress(eased)

      if (progress < 1) {
        requestAnimationFrame(animateFrame)
      }
    }
    requestAnimationFrame(animateFrame)
  }, [animate, animationDuration])

  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom
  const outerRadius = Math.min(innerWidth, innerHeight) / 2
  const innerRadius = outerRadius * Math.max(0, Math.min(1, innerRadiusRatio))

  // Calculate total
  const total = data.reduce((sum, d) => sum + d.value, 0)

  // Active index (controlled or hovered)
  const activeIndex = controlledActiveIndex ?? hoveredIndex

  // Create pie generator
  const pieGenerator = React.useMemo(() => {
    const gen = pie<DonutChartDataPoint>()
      .value((d) => d.value)
      .padAngle(variant === "separated" ? 0.06 : padAngle)
      .startAngle(startAngle)
      .endAngle(interpolate(startAngle, endAngle)(animationProgress))

    if (sortValues) {
      return gen.sort((a, b) => b.value - a.value)
    }
    return gen.sort(null)
  }, [variant, padAngle, startAngle, endAngle, animationProgress, sortValues])

  // Arc datum type
  type ArcDatum = PieArcDatum<DonutChartDataPoint>

  // Create arc generators
  const arcGenerator = arc<ArcDatum>()
    .innerRadius(innerRadius)
    .outerRadius(outerRadius)
    .cornerRadius(cornerRadius)

  // Hover arc (slightly larger)
  const hoverArcGenerator = arc<ArcDatum>()
    .innerRadius(innerRadius - 4)
    .outerRadius(outerRadius + 8)
    .cornerRadius(cornerRadius)

  // Label arc (for positioning)
  const labelArcGenerator = arc<ArcDatum>()
    .innerRadius(outerRadius + 15)
    .outerRadius(outerRadius + 15)

  const arcs = pieGenerator(data)

  // Get color for segment
  const getColor = (d: DonutChartDataPoint, index: number): string => {
    if (d.color) return d.color
    const configColor = config?.[d.label]?.color
    if (configColor) return configColor
    return DEFAULT_COLORS[index % DEFAULT_COLORS.length]
  }

  // Handle mouse events
  const handleMouseMove = (
    e: React.MouseEvent,
    data: DonutChartDataPoint,
    index: number
  ) => {
    if (!showTooltip) return
    const rect = containerRef.current?.getBoundingClientRect()
    if (rect) {
      setTooltipData({
        x: e.clientX - rect.left,
        y: e.clientY - rect.top,
        data,
        index,
      })
    }
  }

  // Determine if label should be outside
  const shouldShowOutsideLabel = (
    arcData: ReturnType<typeof pieGenerator>[number]
  ) => {
    const angle = arcData.endAngle - arcData.startAngle
    return showLabels && showLabelLines && angle < minLabelAngle && angle > 0.1
  }

  // Center content
  const displayedCenterValue =
    activeIndex !== null
      ? valueFormatter(data[activeIndex].value, total)
      : (centerValue ?? (showTotal ? total.toLocaleString() : null))

  const displayedCenterLabel =
    activeIndex !== null
      ? data[activeIndex].label
      : (centerLabel ?? (showTotal ? "Total" : null))

  return (
    <ChartContainer
      config={config}
      className={cn("relative !aspect-auto flex-col", className)}
    >
      <div
        ref={containerRef}
        className="relative mx-auto aspect-square w-full max-w-[280px]"
      >
        <svg
          viewBox={`0 0 ${width} ${height}`}
          className="h-full w-full overflow-visible"
        >
          {/* Gradient definitions */}
          {variant === "gradient" && (
            <defs>
              {data.map((d, i) => {
                const color = getColor(d, i)
                return (
                  <linearGradient
                    key={i}
                    id={`gradient-${gradientId}-${i}`}
                    x1="0%"
                    y1="0%"
                    x2="100%"
                    y2="100%"
                  >
                    <stop offset="0%" stopColor={color} stopOpacity={1} />
                    <stop offset="100%" stopColor={color} stopOpacity={0.6} />
                  </linearGradient>
                )
              })}
            </defs>
          )}

          <g
            transform={`translate(${margin.left + innerWidth / 2}, ${margin.top + innerHeight / 2})`}
          >
            {/* Background ring */}
            <circle
              r={(outerRadius + innerRadius) / 2}
              fill="none"
              stroke="hsl(var(--muted))"
              strokeWidth={outerRadius - innerRadius}
              strokeOpacity={0.15}
            />

            {/* Donut segments */}
            {arcs.map((arcData, index) => {
              const isActive = activeIndex === index
              const d = data[index]
              const color = getColor(d, index)
              const fill =
                variant === "gradient"
                  ? `url(#gradient-${gradientId}-${index})`
                  : color

              return (
                <g key={index}>
                  {/* Shadow for active segment */}
                  {isActive && (
                    <path
                      d={hoverArcGenerator(arcData) ?? ""}
                      fill="black"
                      fillOpacity={0.1}
                      filter="blur(8px)"
                      className="pointer-events-none"
                    />
                  )}

                  {/* Main segment */}
                  <path
                    d={
                      (isActive ? hoverArcGenerator : arcGenerator)(arcData) ??
                      ""
                    }
                    fill={fill}
                    stroke={
                      variant === "separated"
                        ? "hsl(var(--background))"
                        : "none"
                    }
                    strokeWidth={variant === "separated" ? 3 : 0}
                    className={cn(
                      "cursor-pointer transition-all duration-200",
                      activeIndex !== null && !isActive && "opacity-50"
                    )}
                    style={{
                      filter: isActive ? "brightness(1.1)" : undefined,
                    }}
                    onMouseEnter={() => setHoveredIndex(index)}
                    onMouseMove={(e) => handleMouseMove(e, d, index)}
                    onMouseLeave={() => {
                      setHoveredIndex(null)
                      setTooltipData(null)
                    }}
                    onClick={() => onSegmentClick?.(d, index)}
                  />

                  {/* Inline labels for large segments */}
                  {showLabels &&
                    arcData.endAngle - arcData.startAngle >= minLabelAngle && (
                      <text
                        transform={`translate(${arcGenerator.centroid(arcData)})`}
                        textAnchor="middle"
                        dominantBaseline="middle"
                        className="pointer-events-none text-[11px] font-semibold"
                        fill="white"
                        style={{ textShadow: "0 1px 2px rgba(0,0,0,0.5)" }}
                      >
                        {valueFormatter(d.value, total)}
                      </text>
                    )}

                  {/* Outside labels with lines for small segments */}
                  {shouldShowOutsideLabel(arcData) && (
                    <g className="pointer-events-none">
                      <polyline
                        points={(() => {
                          const posA = arcGenerator.centroid(arcData)
                          const posB = labelArcGenerator.centroid(arcData)
                          const midAngle =
                            (arcData.startAngle + arcData.endAngle) / 2
                          const posC = [
                            posB[0] + (midAngle < Math.PI ? 10 : -10),
                            posB[1],
                          ]
                          return `${posA[0]},${posA[1]} ${posB[0]},${posB[1]} ${posC[0]},${posC[1]}`
                        })()}
                        fill="none"
                        stroke="hsl(var(--muted-foreground))"
                        strokeWidth={1}
                        strokeOpacity={0.5}
                      />
                      <text
                        transform={`translate(${labelArcGenerator.centroid(arcData)})`}
                        textAnchor={
                          (arcData.startAngle + arcData.endAngle) / 2 < Math.PI
                            ? "start"
                            : "end"
                        }
                        dx={
                          (arcData.startAngle + arcData.endAngle) / 2 < Math.PI
                            ? 15
                            : -15
                        }
                        dominantBaseline="middle"
                        className="fill-muted-foreground text-[10px]"
                      >
                        {d.label}
                      </text>
                    </g>
                  )}
                </g>
              )
            })}

            {/* Center content */}
            <g className="pointer-events-none">
              {displayedCenterValue && (
                <text
                  textAnchor="middle"
                  dominantBaseline="middle"
                  y={displayedCenterLabel ? -6 : 0}
                  className="fill-foreground text-2xl font-bold"
                  style={{ fontSize: innerRadius * 0.35 }}
                >
                  {displayedCenterValue}
                </text>
              )}
              {displayedCenterLabel && (
                <text
                  textAnchor="middle"
                  dominantBaseline="middle"
                  y={displayedCenterValue ? innerRadius * 0.2 : 0}
                  className="fill-muted-foreground text-sm"
                  style={{ fontSize: innerRadius * 0.15 }}
                >
                  {displayedCenterLabel}
                </text>
              )}
            </g>
          </g>
        </svg>

        {/* Tooltip */}
        {showTooltip && tooltipData && (
          <div
            className="pointer-events-none absolute z-50 -translate-x-1/2 -translate-y-full"
            style={{
              left: tooltipData.x,
              top: tooltipData.y - 10,
            }}
          >
            <div className="bg-popover text-popover-foreground rounded-lg border px-3 py-2 shadow-lg">
              <div className="flex items-center gap-2">
                <div
                  className="h-3 w-3 rounded-full"
                  style={{
                    backgroundColor: getColor(
                      tooltipData.data,
                      tooltipData.index
                    ),
                  }}
                />
                <span className="font-medium">{tooltipData.data.label}</span>
              </div>
              <div className="mt-1 text-sm">
                <span className="text-muted-foreground">Value: </span>
                <span className="font-semibold">
                  {tooltipData.data.value.toLocaleString()}
                </span>
                <span className="text-muted-foreground ml-2">
                  ({valueFormatter(tooltipData.data.value, total)})
                </span>
              </div>
            </div>
          </div>
        )}

        {/* Legend */}
        {showLegend && (
          <div className="mt-4 flex flex-wrap justify-center gap-4">
            {data.map((d, i) => (
              <button
                key={i}
                className={cn(
                  "flex items-center gap-2 rounded-md px-2 py-1 text-sm transition-all",
                  "hover:bg-muted/50",
                  activeIndex === i && "bg-muted"
                )}
                onMouseEnter={() => setHoveredIndex(i)}
                onMouseLeave={() => setHoveredIndex(null)}
                onClick={() => onSegmentClick?.(d, i)}
              >
                <div
                  className="h-3 w-3 rounded-full"
                  style={{ backgroundColor: getColor(d, i) }}
                />
                <span className="text-muted-foreground">{d.label}</span>
                <span className="font-medium">
                  {valueFormatter(d.value, total)}
                </span>
              </button>
            ))}
          </div>
        )}
      </div>
    </ChartContainer>
  )
}

"use client"

import * as React from "react"
import { bin } from "d3-array"
import { scaleLinear } from "d3-scale"

import { cn } from "@/lib/utils"

import { ChartAxis } from "../chart-axis"
import type { BaseChartProps } from "../chart-config"
import { ChartContainer } from "../chart-container"
import { ChartHorizontalGrid } from "../chart-grid"

// ============================================================================
// Types & Interfaces
// ============================================================================

export interface HistogramDataset {
  data: number[]
  label?: string
  color?: string
}

export interface HistogramChartProps extends BaseChartProps {
  /** Single dataset or multiple datasets for overlay */
  data: number[] | HistogramDataset[]
  /** Number of bins */
  bins?: number
  /** X-axis label */
  xAxisLabel?: string
  /** Y-axis label */
  yAxisLabel?: string
  /** Bar color (for single dataset) */
  color?: string
  /** Bar padding between bins */
  barPadding?: number
  /** Show density instead of count */
  showDensity?: boolean
  /** Normalize to percentages */
  normalized?: boolean
  /** Variant style */
  variant?: "default" | "overlay" | "gradient" | "stepped"
  /** Show bar border/stroke */
  showBorder?: boolean
  /** Border color */
  borderColor?: string
  /** Bar corner radius */
  cornerRadius?: number
  /** Opacity for overlay/stepped variants */
  fillOpacity?: number
  /** Color scale for gradient variant */
  colorScale?: "viridis" | "plasma" | "warm" | "cool" | "rainbow"
  /** Show legend for multiple datasets */
  showLegend?: boolean
}

// ============================================================================
// Color Scales
// ============================================================================

const COLOR_SCALES = {
  // Blue-purple gradient (default) - professional blue tones
  viridis: (t: number) => {
    const colors = [
      "#1e3a5f",
      "#2563eb",
      "#3b82f6",
      "#60a5fa",
      "#93c5fd",
      "#bfdbfe",
    ]
    const idx = Math.min(Math.floor(t * (colors.length - 1)), colors.length - 2)
    const localT = t * (colors.length - 1) - idx
    return interpolateColor(colors[idx], colors[idx + 1], localT)
  },
  // Plasma: deep purple -> magenta -> orange
  plasma: (t: number) => {
    const colors = [
      "#0d0887",
      "#6a00a8",
      "#b12a90",
      "#e16462",
      "#fca636",
      "#f0f921",
    ]
    const idx = Math.min(Math.floor(t * (colors.length - 1)), colors.length - 2)
    const localT = t * (colors.length - 1) - idx
    return interpolateColor(colors[idx], colors[idx + 1], localT)
  },
  // Warm: purple -> pink -> orange -> gold
  warm: (t: number) => {
    const colors = ["#6e40aa", "#be3caf", "#fe4b83", "#ff7847", "#e2b72f"]
    const idx = Math.min(Math.floor(t * (colors.length - 1)), colors.length - 2)
    const localT = t * (colors.length - 1) - idx
    return interpolateColor(colors[idx], colors[idx + 1], localT)
  },
  // Cool: indigo -> blue -> cyan
  cool: (t: number) => {
    const colors = [
      "#312e81",
      "#4338ca",
      "#6366f1",
      "#818cf8",
      "#a5b4fc",
      "#c7d2fe",
    ]
    const idx = Math.min(Math.floor(t * (colors.length - 1)), colors.length - 2)
    const localT = t * (colors.length - 1) - idx
    return interpolateColor(colors[idx], colors[idx + 1], localT)
  },
  // Rainbow with blue emphasis
  rainbow: (t: number) => {
    const h = 220 + t * 140 // Start from blue, cycle through purple to cyan
    return `hsl(${h % 360}, 70%, 55%)`
  },
}

function interpolateColor(c1: string, c2: string, t: number): string {
  const hex2rgb = (hex: string) => {
    const h = hex.replace("#", "")
    return [
      parseInt(h.substring(0, 2), 16),
      parseInt(h.substring(2, 4), 16),
      parseInt(h.substring(4, 6), 16),
    ]
  }
  const rgb2hex = (r: number, g: number, b: number) =>
    "#" +
    [r, g, b].map((x) => Math.round(x).toString(16).padStart(2, "0")).join("")

  const [r1, g1, b1] = hex2rgb(c1)
  const [r2, g2, b2] = hex2rgb(c2)
  return rgb2hex(r1 + (r2 - r1) * t, g1 + (g2 - g1) * t, b1 + (b2 - b1) * t)
}

// Default colors for multiple datasets (overlay variant)
const DEFAULT_COLORS = [
  "#3b82f6", // blue
  "#8b5cf6", // violet
  "#06b6d4", // cyan
  "#f59e0b", // amber
  "#ec4899", // pink
  "#10b981", // emerald
]

