// Component
// ============================================================================

export function HistogramChart({
  data,
  config,
  className,
  width = 600,
  height = 400,
  margin = { top: 20, right: 20, bottom: 40, left: 50 },
  showGrid = true,
  showTooltip = true,
  bins = 30,
  xAxisLabel,
  yAxisLabel,
  color,
  barPadding = 1,
  showDensity = false,
  normalized = false,
  variant = "default",
  showBorder = true,
  borderColor,
  cornerRadius = 0,
  fillOpacity,
  colorScale = "viridis",
  showLegend = true,
}: HistogramChartProps) {
  const [hoveredBin, setHoveredBin] = React.useState<{
    datasetIdx: number
    binIdx: number
  } | null>(null)

  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom

  // Normalize data to array of datasets
  const datasets: HistogramDataset[] = React.useMemo(() => {
    if (Array.isArray(data) && data.length > 0) {
      if (typeof data[0] === "number") {
        return [
          {
            data: data as number[],
            label: "Data",
            color: color || DEFAULT_COLORS[0],
          },
        ]
      }
      return (data as HistogramDataset[]).map((d, i) => ({
        ...d,
        color: d.color || DEFAULT_COLORS[i % DEFAULT_COLORS.length],
      }))
    }
    return []
  }, [data, color])

  // Calculate global domain
  const globalDomain = React.useMemo(() => {
    const allData = datasets.flatMap((d) => d.data)
    if (allData.length === 0) return [0, 1]
    return [Math.min(...allData), Math.max(...allData)]
  }, [datasets])

  // Create histogram bins for each dataset
  const histograms = React.useMemo(() => {
    const binGenerator = bin()
      .domain(globalDomain as [number, number])
      .thresholds(bins)

    return datasets.map((dataset) => {
      const hist = binGenerator(dataset.data)
      const total = dataset.data.length
      return hist.map((b) => ({
        x0: b.x0!,
        x1: b.x1!,
        count: b.length,
        density: b.length / total / (b.x1! - b.x0!),
        percent: (b.length / total) * 100,
      }))
    })
  }, [datasets, globalDomain, bins])

  // Scales
  const xScale = React.useMemo(() => {
    return scaleLinear().domain(globalDomain).range([0, innerWidth])
  }, [globalDomain, innerWidth])

  const yScale = React.useMemo(() => {
    let maxY = 0
    histograms.forEach((binData) => {
      binData.forEach((b) => {
        const val = showDensity ? b.density : normalized ? b.percent : b.count
        if (val > maxY) maxY = val
      })
    })
    return scaleLinear()
      .domain([0, maxY * 1.1])
      .range([innerHeight, 0])
      .nice()
  }, [histograms, innerHeight, showDensity, normalized])

  // Get color function for gradient variant
  const getGradientColor = React.useCallback(
    (binIdx: number, totalBins: number) => {
      const t = binIdx / (totalBins - 1)
      return COLOR_SCALES[colorScale](t)
    },
    [colorScale]
  )

  // Determine fill opacity based on variant
  const getFillOpacity = () => {
    if (fillOpacity !== undefined) return fillOpacity
    switch (variant) {
      case "overlay":
        return 0.6
      case "stepped":
        return 0.4
      default:
        return 1
    }
  }

  // Generate stepped path for a dataset
  const generateSteppedPath = (binData: (typeof histograms)[0]) => {
    if (binData.length === 0) return ""

    const points: string[] = []
    points.push(`M ${xScale(binData[0].x0)} ${innerHeight}`)

    binData.forEach((b) => {
      const yValue = showDensity ? b.density : normalized ? b.percent : b.count
      const y = yScale(yValue)
      points.push(`L ${xScale(b.x0)} ${y}`)
      points.push(`L ${xScale(b.x1)} ${y}`)
    })

    points.push(`L ${xScale(binData[binData.length - 1].x1)} ${innerHeight}`)
    points.push("Z")

    return points.join(" ")
  }

  // Render bars for a single dataset
  const renderBars = (
    binData: (typeof histograms)[0],
    datasetIdx: number,
    datasetColor: string
  ) => {
    return binData.map((b, binIdx) => {
      const barX = xScale(b.x0)
      const barWidth = Math.max(0, xScale(b.x1) - xScale(b.x0) - barPadding)
      const yValue = showDensity ? b.density : normalized ? b.percent : b.count
      const barY = yScale(yValue)
      const barHeight = Math.max(0, innerHeight - barY)

      let fillColor = datasetColor
      if (variant === "gradient") {
        fillColor = getGradientColor(binIdx, binData.length)
      }

      const isHovered =
        hoveredBin?.datasetIdx === datasetIdx && hoveredBin?.binIdx === binIdx

      return (
        <rect
          key={`${datasetIdx}-${binIdx}`}
          x={barX}
          y={barY}
          width={barWidth}
          height={barHeight}
          fill={fillColor}
          fillOpacity={getFillOpacity()}
          stroke={showBorder ? borderColor || fillColor : "none"}
          strokeWidth={showBorder ? 1 : 0}
          rx={cornerRadius}
          ry={cornerRadius}
          className={cn(
            "cursor-pointer transition-opacity duration-150",
            hoveredBin !== null && !isHovered && "opacity-60"
          )}
          onMouseEnter={() => setHoveredBin({ datasetIdx, binIdx })}
          onMouseLeave={() => setHoveredBin(null)}
        />
      )
    })
  }

  // Render stepped/area histogram
  const renderStepped = (
    binData: (typeof histograms)[0],
    datasetIdx: number,
    datasetColor: string
  ) => {
    const path = generateSteppedPath(binData)
    return (
      <g key={datasetIdx}>
        {/* The filled area path */}
        <path
          d={path}
          fill={datasetColor}
          fillOpacity={getFillOpacity()}
          stroke={datasetColor}
          strokeWidth={1.5}
          className={cn(
            "transition-opacity duration-150",
            hoveredBin !== null &&
              hoveredBin.datasetIdx !== datasetIdx &&
              "opacity-50"
          )}
        />
        {/* Invisible hit areas for each bin segment */}
        {binData.map((b, binIdx) => {
          const barX = xScale(b.x0)
          const barWidth = Math.max(0, xScale(b.x1) - xScale(b.x0))
          const yValue = showDensity
            ? b.density
            : normalized
              ? b.percent
              : b.count
          const barY = yScale(yValue)
          const barHeight = Math.max(0, innerHeight - barY)

          const isHovered =
            hoveredBin?.datasetIdx === datasetIdx &&
            hoveredBin?.binIdx === binIdx

          return (
            <rect
              key={`hit-${datasetIdx}-${binIdx}`}
              x={barX}
              y={barY}
              width={barWidth}
              height={barHeight}
              fill="transparent"
              className={cn("cursor-pointer", isHovered && "fill-foreground/5")}
              onMouseEnter={() => setHoveredBin({ datasetIdx, binIdx })}
              onMouseLeave={() => setHoveredBin(null)}
            />
          )
        })}
      </g>
    )
  }

  return (
    <ChartContainer config={config} className={cn("relative", className)}>
      <svg viewBox={`0 0 ${width} ${height}`} className="h-full w-full">
        <g transform={`translate(${margin.left}, ${margin.top})`}>
          {/* Grid */}
          {showGrid && (
            <ChartHorizontalGrid scale={yScale} width={innerWidth} />
          )}

          {/* Render based on variant */}
          {variant === "stepped"
            ? datasets.map((dataset, idx) =>
                renderStepped(histograms[idx], idx, dataset.color!)
              )
            : datasets.map((dataset, idx) =>
                renderBars(histograms[idx], idx, dataset.color!)
              )}

          {/* X Axis */}
          <ChartAxis
            scale={xScale}
            orientation="bottom"
            transform={`translate(0, ${innerHeight})`}
            label={xAxisLabel}
          />

          {/* Y Axis */}
          <ChartAxis
            scale={yScale}
            orientation="left"
            label={
              yAxisLabel ??
              (showDensity ? "Density" : normalized ? "Percentage" : "Count")
            }
          />
        </g>

        {/* Legend for multiple datasets */}
        {showLegend && datasets.length > 1 && (
          <g
            transform={`translate(${width - margin.right - 100}, ${margin.top})`}
          >
            <rect
              x={-10}
              y={-10}
              width={110}
              height={datasets.length * 22 + 10}
              fill="var(--background)"
              stroke="var(--border)"
              strokeWidth={1}
              rx={4}
            />
            {datasets.map((dataset, idx) => (
              <g key={idx} transform={`translate(0, ${idx * 22})`}>
                <rect
                  x={0}
                  y={0}
                  width={16}
                  height={14}
                  fill={dataset.color}
                  fillOpacity={getFillOpacity()}
                  stroke={dataset.color}
                  strokeWidth={1}
                  rx={2}
                />
                <text x={22} y={11} className="fill-foreground text-[11px]">
                  {dataset.label || `Dataset ${idx + 1}`}
                </text>
              </g>
            ))}
          </g>
        )}
      </svg>

      {/* Tooltip */}
      {showTooltip && hoveredBin !== null && (
        <div
          className="pointer-events-none absolute z-50"
          style={{
            left:
              margin.left +
              xScale(
                (histograms[hoveredBin.datasetIdx][hoveredBin.binIdx].x0 +
                  histograms[hoveredBin.datasetIdx][hoveredBin.binIdx].x1) /
                  2
              ),
            top:
              margin.top +
              yScale(
                showDensity
                  ? histograms[hoveredBin.datasetIdx][hoveredBin.binIdx].density
                  : normalized
                    ? histograms[hoveredBin.datasetIdx][hoveredBin.binIdx]
                        .percent
                    : histograms[hoveredBin.datasetIdx][hoveredBin.binIdx].count
              ) -
              10,
            transform: "translateX(-50%)",
          }}
        >
          <div className="border-border/50 bg-background rounded-lg border px-2.5 py-1.5 text-xs shadow-xl">
            {datasets.length > 1 && (
              <div
                className="mb-1 font-medium"
                style={{ color: datasets[hoveredBin.datasetIdx].color }}
              >
                {datasets[hoveredBin.datasetIdx].label ||
                  `Dataset ${hoveredBin.datasetIdx + 1}`}
              </div>
            )}
            <div className="font-medium">
              {histograms[hoveredBin.datasetIdx][hoveredBin.binIdx].x0.toFixed(
                1
              )}{" "}
              -{" "}
              {histograms[hoveredBin.datasetIdx][hoveredBin.binIdx].x1.toFixed(
                1
              )}
            </div>
            <div className="text-muted-foreground">
              Count:{" "}
              {histograms[hoveredBin.datasetIdx][hoveredBin.binIdx].count}
            </div>
            <div className="text-muted-foreground">
              {histograms[hoveredBin.datasetIdx][
                hoveredBin.binIdx
              ].percent.toFixed(1)}
              %
            </div>
          </div>
        </div>
      )}
    </ChartContainer>
  )
}

"use client"

import * as React from "react"
import { max, median, min, quantile } from "d3-array"
import { scaleBand, scaleLinear } from "d3-scale"

import { cn } from "@/lib/utils"

export interface BoxPlotDataPoint {
  label: string
  values: number[]
  color?: string
}

export interface BoxPlotStats {
  label: string
  min: number
  q1: number
  median: number
  q3: number
  max: number
  outliers: number[]
  color?: string
}

export interface BoxPlotChartProps {
  data: BoxPlotDataPoint[] | BoxPlotStats[]
  className?: string
  color?: string
  showGrid?: boolean
  showTooltip?: boolean
  orientation?: "vertical" | "horizontal"
  boxWidth?: number
  showOutliers?: boolean
  whiskerType?: "minmax" | "iqr"
  aspectRatio?: number
  valueFormatter?: (value: number) => string
}

function isStats(
  data: BoxPlotDataPoint[] | BoxPlotStats[]
): data is BoxPlotStats[] {
  return data.length > 0 && "median" in data[0]
}

function calculateStats(
  values: number[],
  whiskerType: "minmax" | "iqr"
): Omit<BoxPlotStats, "label" | "color"> {
  const sorted = [...values].sort((a, b) => a - b)
  const q1 = quantile(sorted, 0.25) ?? 0
  const med = median(sorted) ?? 0
  const q3 = quantile(sorted, 0.75) ?? 0
  const iqr = q3 - q1

  let minVal: number, maxVal: number
  let outliers: number[] = []

  if (whiskerType === "iqr") {
    const lowerFence = q1 - 1.5 * iqr
    const upperFence = q3 + 1.5 * iqr
    minVal = min(sorted.filter((v) => v >= lowerFence)) ?? sorted[0]
    maxVal =
      max(sorted.filter((v) => v <= upperFence)) ?? sorted[sorted.length - 1]
    outliers = sorted.filter((v) => v < lowerFence || v > upperFence)
  } else {
    minVal = min(sorted) ?? 0
    maxVal = max(sorted) ?? 0
  }

  return { min: minVal, q1, median: med, q3, max: maxVal, outliers }
}

export function BoxPlotChart({
  data,
  className,
  color = "#2563eb",
  showGrid = true,
  showTooltip = true,
  orientation = "vertical",
  boxWidth = 0.6,
  showOutliers = true,
  whiskerType = "iqr",
  aspectRatio = 2,
  valueFormatter = (value) => value.toFixed(0),
}: BoxPlotChartProps) {
  const containerRef = React.useRef<HTMLDivElement>(null)
  const [dimensions, setDimensions] = React.useState({ width: 0, height: 0 })
  const [hoveredIndex, setHoveredIndex] = React.useState<number | null>(null)
  const [tooltipPos, setTooltipPos] = React.useState({ x: 0, y: 0 })

  // Responsive sizing
  React.useEffect(() => {
    const updateDimensions = () => {
      if (containerRef.current) {
        const width = containerRef.current.offsetWidth
        setDimensions({ width, height: width / aspectRatio })
      }
    }
    updateDimensions()
    window.addEventListener("resize", updateDimensions)
    return () => window.removeEventListener("resize", updateDimensions)
  }, [aspectRatio])

  const { width, height } = dimensions
  const margin = { top: 20, right: 20, bottom: 40, left: 50 }
  const innerWidth = Math.max(0, width - margin.left - margin.right)
  const innerHeight = Math.max(0, height - margin.top - margin.bottom)
  const isVertical = orientation === "vertical"

  // Calculate stats if raw values provided
  const statsData: BoxPlotStats[] = React.useMemo(() => {
    if (isStats(data)) return data
    return data.map((d) => ({
      label: d.label,
      color: d.color,
      ...calculateStats(d.values, whiskerType),
    }))
  }, [data, whiskerType])

  // Category scale
  const categoryScale = React.useMemo(() => {
    return scaleBand()
      .domain(statsData.map((d) => d.label))
      .range(isVertical ? [0, innerWidth] : [0, innerHeight])
      .padding(0.3)
  }, [statsData, innerWidth, innerHeight, isVertical])

  // Value scale
  const valueScale = React.useMemo(() => {
    const allValues = statsData.flatMap((d) => [d.min, d.max, ...d.outliers])
    const minV = Math.min(...allValues)
    const maxV = Math.max(...allValues)
    const padding = (maxV - minV) * 0.1
    return scaleLinear()
      .domain([Math.floor(minV - padding), Math.ceil(maxV + padding)])
      .range(isVertical ? [innerHeight, 0] : [0, innerWidth])
      .nice()
  }, [statsData, innerWidth, innerHeight, isVertical])

  const actualBoxWidth = categoryScale.bandwidth() * boxWidth
  const ticks = valueScale.ticks(5)

  if (width === 0) {
    return <div ref={containerRef} className={cn("w-full", className)} />
  }

  return (
    <div ref={containerRef} className={cn("relative w-full", className)}>
      <svg
        width={width}
        height={height}
        viewBox={`0 0 ${width} ${height}`}
        className="overflow-visible"
      >
        <g transform={`translate(${margin.left}, ${margin.top})`}>
          {/* Grid */}
          {showGrid && (
            <>
              {/* Horizontal grid lines */}
              {ticks.map((tick) => (
                <line
                  key={`h-${tick}`}
                  x1={0}
                  x2={innerWidth}
                  y1={isVertical ? valueScale(tick) : 0}
                  y2={isVertical ? valueScale(tick) : innerHeight}
                  stroke="hsl(var(--border))"
                  strokeOpacity={0.5}
                  strokeDasharray="3 3"
                />
              ))}
              {/* Vertical grid lines */}
              {statsData.map((d) => {
                const x =
                  (categoryScale(d.label) ?? 0) + categoryScale.bandwidth() / 2
                return (
                  <line
                    key={`v-${d.label}`}
                    x1={x}
                    x2={x}
                    y1={0}
                    y2={innerHeight}
                    stroke="hsl(var(--border))"
                    strokeOpacity={0.5}
                    strokeDasharray="3 3"
                  />
                )
              })}
            </>
          )}

          {/* Box plots */}
          {statsData.map((d, index) => {
            const boxColor = d.color ?? color
            const center =
              (categoryScale(d.label) ?? 0) + categoryScale.bandwidth() / 2
            const boxOffset = actualBoxWidth / 2
            const isHovered = hoveredIndex === index

            if (isVertical) {
              return (
                <g
                  key={d.label}
                  className={cn(
                    "cursor-pointer transition-opacity duration-200",
                    hoveredIndex !== null && !isHovered && "opacity-40"
                  )}
                  onMouseEnter={(e) => {
                    setHoveredIndex(index)
                    const rect = containerRef.current?.getBoundingClientRect()
                    if (rect) {
                      setTooltipPos({
                        x: e.clientX - rect.left,
                        y: e.clientY - rect.top,
                      })
                    }
                  }}
                  onMouseMove={(e) => {
                    const rect = containerRef.current?.getBoundingClientRect()
                    if (rect) {
                      setTooltipPos({
                        x: e.clientX - rect.left,
                        y: e.clientY - rect.top,
                      })
                    }
                  }}
                  onMouseLeave={() => setHoveredIndex(null)}
                >
                  {/* Whisker line */}
                  <line
                    x1={center}
                    x2={center}
                    y1={valueScale(d.min)}
                    y2={valueScale(d.max)}
                    stroke={boxColor}
                    strokeWidth={1.5}
                  />

                  {/* Min whisker */}
                  <line
                    x1={center - boxOffset * 0.5}
                    x2={center + boxOffset * 0.5}
                    y1={valueScale(d.min)}
                    y2={valueScale(d.min)}
                    stroke={boxColor}
                    strokeWidth={2}
                  />

                  {/* Max whisker */}
                  <line
                    x1={center - boxOffset * 0.5}
                    x2={center + boxOffset * 0.5}
                    y1={valueScale(d.max)}
                    y2={valueScale(d.max)}
                    stroke={boxColor}
                    strokeWidth={2}
                  />

                  {/* Box */}
                  <rect
                    x={center - boxOffset}
                    y={valueScale(d.q3)}
                    width={actualBoxWidth}
                    height={Math.max(0, valueScale(d.q1) - valueScale(d.q3))}
                    fill={boxColor}
                    fillOpacity={0.2}
                    stroke={boxColor}
                    strokeWidth={2}
                    rx={4}
                  />

                  {/* Median line */}
                  <line
                    x1={center - boxOffset}
                    x2={center + boxOffset}
                    y1={valueScale(d.median)}
                    y2={valueScale(d.median)}
                    stroke={boxColor}
                    strokeWidth={3}
                  />

                  {/* Outliers */}
                  {showOutliers &&
                    d.outliers.map((outlier, i) => (
                      <circle
                        key={i}
                        cx={center}
                        cy={valueScale(outlier)}
                        r={4}
                        fill={boxColor}
                        fillOpacity={0.5}
                        stroke={boxColor}
                        strokeWidth={1.5}
                      />
                    ))}
                </g>
              )
            } else {
              // Horizontal orientation
              return (
                <g
                  key={d.label}
                  className={cn(
                    "cursor-pointer transition-opacity duration-200",
                    hoveredIndex !== null && !isHovered && "opacity-40"
                  )}
                  onMouseEnter={(e) => {
                    setHoveredIndex(index)
                    const rect = containerRef.current?.getBoundingClientRect()
                    if (rect) {
                      setTooltipPos({
                        x: e.clientX - rect.left,
                        y: e.clientY - rect.top,
                      })
                    }
                  }}
                  onMouseMove={(e) => {
                    const rect = containerRef.current?.getBoundingClientRect()
                    if (rect) {
                      setTooltipPos({
                        x: e.clientX - rect.left,
                        y: e.clientY - rect.top,
                      })
                    }
                  }}
                  onMouseLeave={() => setHoveredIndex(null)}
                >
                  {/* Whisker line */}
                  <line
                    y1={center}
                    y2={center}
                    x1={valueScale(d.min)}
                    x2={valueScale(d.max)}
                    stroke={boxColor}
                    strokeWidth={1.5}
                  />

                  {/* Min whisker */}
                  <line
                    y1={center - boxOffset * 0.5}
                    y2={center + boxOffset * 0.5}
                    x1={valueScale(d.min)}
                    x2={valueScale(d.min)}
                    stroke={boxColor}
                    strokeWidth={2}
                  />

                  {/* Max whisker */}
                  <line
                    y1={center - boxOffset * 0.5}
                    y2={center + boxOffset * 0.5}
                    x1={valueScale(d.max)}
                    x2={valueScale(d.max)}
                    stroke={boxColor}
                    strokeWidth={2}
                  />

                  {/* Box */}
                  <rect
                    y={center - boxOffset}
                    x={valueScale(d.q1)}
                    height={actualBoxWidth}
                    width={Math.max(0, valueScale(d.q3) - valueScale(d.q1))}
                    fill={boxColor}
                    fillOpacity={0.2}
                    stroke={boxColor}
                    strokeWidth={2}
                    rx={4}
                  />

                  {/* Median line */}
                  <line
                    y1={center - boxOffset}
                    y2={center + boxOffset}
                    x1={valueScale(d.median)}
                    x2={valueScale(d.median)}
                    stroke={boxColor}
                    strokeWidth={3}
                  />

                  {/* Outliers */}
                  {showOutliers &&
                    d.outliers.map((outlier, i) => (
                      <circle
                        key={i}
                        cy={center}
                        cx={valueScale(outlier)}
                        r={4}
                        fill={boxColor}
                        fillOpacity={0.5}
                        stroke={boxColor}
                        strokeWidth={1.5}
                      />
                    ))}
                </g>
              )
            }
          })}

          {/* X Axis */}
          <g transform={`translate(0, ${innerHeight})`}>
            {statsData.map((d) => {
              const x =
                (categoryScale(d.label) ?? 0) + categoryScale.bandwidth() / 2
              return (
                <text
                  key={d.label}
                  x={x}
                  y={24}
                  textAnchor="middle"
                  className="fill-muted-foreground text-xs"
                >
                  {d.label}
                </text>
              )
            })}
          </g>

          {/* Y Axis */}
          <g>
            {ticks.map((tick) => (
              <text
                key={tick}
                x={-12}
                y={valueScale(tick)}
                dy="0.32em"
                textAnchor="end"
                className="fill-muted-foreground text-xs"
              >
                {valueFormatter(tick)}
              </text>
            ))}
          </g>
        </g>
      </svg>

      {/* Tooltip */}
      {showTooltip && hoveredIndex !== null && (
        <div
          className="pointer-events-none absolute z-50"
          style={{
            left: tooltipPos.x + 10,
            top: tooltipPos.y - 10,
            transform: "translateY(-100%)",
          }}
        >
          <div className="bg-background rounded-lg border px-3 py-2 shadow-lg">
            <p className="text-foreground mb-1 text-sm font-medium">
              {statsData[hoveredIndex].label}
            </p>
            <div className="space-y-0.5 text-sm">
              <div className="flex items-center justify-between gap-4">
                <span className="text-muted-foreground">Max</span>
                <span style={{ color: statsData[hoveredIndex].color ?? color }}>
                  {valueFormatter(statsData[hoveredIndex].max)}
                </span>
              </div>
              <div className="flex items-center justify-between gap-4">
                <span className="text-muted-foreground">Q3</span>
                <span style={{ color: statsData[hoveredIndex].color ?? color }}>
                  {valueFormatter(statsData[hoveredIndex].q3)}
                </span>
              </div>
              <div className="flex items-center justify-between gap-4">
                <span className="text-muted-foreground">Median</span>
                <span style={{ color: statsData[hoveredIndex].color ?? color }}>
                  {valueFormatter(statsData[hoveredIndex].median)}
                </span>
              </div>
              <div className="flex items-center justify-between gap-4">
                <span className="text-muted-foreground">Q1</span>
                <span style={{ color: statsData[hoveredIndex].color ?? color }}>
                  {valueFormatter(statsData[hoveredIndex].q1)}
                </span>
              </div>
              <div className="flex items-center justify-between gap-4">
                <span className="text-muted-foreground">Min</span>
                <span style={{ color: statsData[hoveredIndex].color ?? color }}>
                  {valueFormatter(statsData[hoveredIndex].min)}
                </span>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

"use client"

import * as React from "react"
import { bin, max, median, quantile } from "d3-array"
import { scaleBand, scaleLinear } from "d3-scale"
import { area, curveCardinal } from "d3-shape"

import { cn } from "@/lib/utils"

import { ChartAxis } from "../chart-axis"
import type { BaseChartProps, ChartConfig } from "../chart-config"
import { ChartContainer } from "../chart-container"
import { ChartHorizontalGrid } from "../chart-grid"

export interface ViolinChartData {
  label: string
  values: number[]
  color?: string
}

export interface ViolinChartProps extends BaseChartProps {
  data: ViolinChartData[]
  orientation?: "vertical" | "horizontal"
  bandwidth?: number
  showBoxPlot?: boolean
  showMedian?: boolean
  resolution?: number
  xAxisLabel?: string
  yAxisLabel?: string
}

// Kernel density estimation
function kde(
  values: number[],
  domain: [number, number],
  bandwidth: number,
  resolution: number
): Array<{ x: number; y: number }> {
  const [minVal, maxVal] = domain
  const step = (maxVal - minVal) / resolution
  const points: Array<{ x: number; y: number }> = []

  for (let x = minVal; x <= maxVal; x += step) {
    let density = 0
    for (const v of values) {
      const u = (x - v) / bandwidth
      // Gaussian kernel
      density += Math.exp(-0.5 * u * u) / Math.sqrt(2 * Math.PI)
    }
    density /= values.length * bandwidth
    points.push({ x, y: density })
  }

  return points
}

export function ViolinChart({
  data,
  config = {},
  className,
  width = 600,
  height = 400,
  margin = { top: 20, right: 20, bottom: 40, left: 50 },
  showGrid = true,
  showTooltip = true,
  orientation = "vertical",
  bandwidth: bandwidthProp,
  showBoxPlot = true,
  showMedian = true,
  resolution = 50,
  xAxisLabel,
  yAxisLabel,
}: ViolinChartProps) {
  const [hoveredIndex, setHoveredIndex] = React.useState<number | null>(null)

  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom
  const isVertical = orientation === "vertical"

  // Calculate all stats and KDE
  const processedData = React.useMemo(() => {
    const allValues = data.flatMap((d) => d.values)
    const globalMin = Math.min(...allValues)
    const globalMax = Math.max(...allValues)
    const domain: [number, number] = [globalMin, globalMax]

    return data.map((d) => {
      const sorted = [...d.values].sort((a, b) => a - b)
      const q1 = quantile(sorted, 0.25) ?? 0
      const med = median(sorted) ?? 0
      const q3 = quantile(sorted, 0.75) ?? 0
      const iqr = q3 - q1

      // Silverman's rule of thumb for bandwidth
      const std = Math.sqrt(
        d.values.reduce((acc, v) => acc + Math.pow(v - med, 2), 0) /
          d.values.length
      )
      const bw =
        bandwidthProp ??
        0.9 * Math.min(std, iqr / 1.34) * Math.pow(d.values.length, -0.2)

      const density = kde(d.values, domain, bw, resolution)
      const maxDensity = max(density, (p) => p.y) ?? 1

      return {
        label: d.label,
        color: d.color,
        values: d.values,
        density,
        maxDensity,
        q1,
        median: med,
        q3,
        min: Math.min(...sorted),
        max: Math.max(...sorted),
      }
    })
  }, [data, bandwidthProp, resolution])

  // Category scale
  const categoryScale = React.useMemo(() => {
    return scaleBand()
      .domain(data.map((d) => d.label))
      .range(isVertical ? [0, innerWidth] : [0, innerHeight])
      .padding(0.2)
  }, [data, innerWidth, innerHeight, isVertical])

  // Value scale
  const valueScale = React.useMemo(() => {
    const allValues = data.flatMap((d) => d.values)
    const minV = Math.min(...allValues)
    const maxV = Math.max(...allValues)
    const padding = (maxV - minV) * 0.1
    return scaleLinear()
      .domain([minV - padding, maxV + padding])
      .range(isVertical ? [innerHeight, 0] : [0, innerWidth])
      .nice()
  }, [data, innerWidth, innerHeight, isVertical])

  // Density scale (for violin width)
  const maxMaxDensity = Math.max(...processedData.map((d) => d.maxDensity))
  const densityScale = scaleLinear()
    .domain([0, maxMaxDensity])
    .range([0, categoryScale.bandwidth() / 2])

  return (
    <ChartContainer config={config} className={cn("relative", className)}>
      <svg viewBox={`0 0 ${width} ${height}`} className="h-full w-full">
        <g transform={`translate(${margin.left}, ${margin.top})`}>
          {/* Grid */}
          {showGrid && (
            <ChartHorizontalGrid
              scale={
                isVertical
                  ? valueScale
                  : scaleLinear()
                      .domain(valueScale.domain())
                      .range([innerHeight, 0])
              }
              width={innerWidth}
            />
          )}

          {/* Violins */}
          {processedData.map((d, index) => {
            const color =
              d.color ??
              config[d.label]?.color ??
              `hsl(var(--chart-${(index % 5) + 1}))`
            const center =
              (categoryScale(d.label) ?? 0) + categoryScale.bandwidth() / 2
            const isHovered = hoveredIndex === index

            // Create violin path
            const violinArea = area<{ x: number; y: number }>().curve(
              curveCardinal
            )

            if (isVertical) {
              violinArea
                .x0((p) => center - densityScale(p.y))
                .x1((p) => center + densityScale(p.y))
                .y((p) => valueScale(p.x))
            } else {
              violinArea
                .y0((p) => center - densityScale(p.y))
                .y1((p) => center + densityScale(p.y))
                .x((p) => valueScale(p.x))
            }

            return (
              <g
                key={d.label}
                className={cn(
                  "cursor-pointer transition-opacity duration-200",
                  hoveredIndex !== null && !isHovered && "opacity-50"
                )}
                onMouseEnter={() => setHoveredIndex(index)}
                onMouseLeave={() => setHoveredIndex(null)}
              >
                {/* Violin shape */}
                <path
                  d={violinArea(d.density) ?? ""}
                  fill={color}
                  fillOpacity={0.3}
                  stroke={color}
                  strokeWidth={1.5}
                />

                {/* Box plot overlay */}
                {showBoxPlot && (
                  <>
                    {isVertical ? (
                      <>
                        {/* Box */}
                        <rect
                          x={center - 4}
                          y={valueScale(d.q3)}
                          width={8}
                          height={valueScale(d.q1) - valueScale(d.q3)}
                          fill={color}
                          fillOpacity={0.6}
                          rx={1}
                        />
                        {/* Whiskers */}
                        <line
                          x1={center}
                          x2={center}
                          y1={valueScale(d.min)}
                          y2={valueScale(d.q1)}
                          stroke={color}
                          strokeWidth={1}
                        />
                        <line
                          x1={center}
                          x2={center}
                          y1={valueScale(d.q3)}
                          y2={valueScale(d.max)}
                          stroke={color}
                          strokeWidth={1}
                        />
                      </>
                    ) : (
                      <>
                        {/* Box */}
                        <rect
                          y={center - 4}
                          x={valueScale(d.q1)}
                          height={8}
                          width={valueScale(d.q3) - valueScale(d.q1)}
                          fill={color}
                          fillOpacity={0.6}
                          rx={1}
                        />
                        {/* Whiskers */}
                        <line
                          y1={center}
                          y2={center}
                          x1={valueScale(d.min)}
                          x2={valueScale(d.q1)}
                          stroke={color}
                          strokeWidth={1}
                        />
                        <line
                          y1={center}
                          y2={center}
                          x1={valueScale(d.q3)}
                          x2={valueScale(d.max)}
                          stroke={color}
                          strokeWidth={1}
                        />
                      </>
                    )}
                  </>
                )}

                {/* Median point */}
                {showMedian && (
                  <circle
                    cx={isVertical ? center : valueScale(d.median)}
                    cy={isVertical ? valueScale(d.median) : center}
                    r={4}
                    fill="white"
                    stroke={color}
                    strokeWidth={2}
                  />
                )}
              </g>
            )
          })}

          {/* Axes */}
          <ChartAxis
            scale={isVertical ? categoryScale : valueScale}
            orientation="bottom"
            transform={`translate(0, ${innerHeight})`}
            label={xAxisLabel}
          />
          <ChartAxis
            scale={isVertical ? valueScale : categoryScale}
            orientation="left"
            label={yAxisLabel}
          />
        </g>
      </svg>

      {/* Tooltip */}
      {showTooltip && hoveredIndex !== null && (
        <div
          className="pointer-events-none absolute z-50"
          style={{
            left:
              margin.left +
              (isVertical
                ? (categoryScale(processedData[hoveredIndex].label) ?? 0) +
                  categoryScale.bandwidth() / 2
                : valueScale(processedData[hoveredIndex].median)),
            top: margin.top + 10,
          }}
        >
          <div className="border-border/50 bg-background rounded-lg border px-2.5 py-1.5 text-xs shadow-xl">
            <div className="font-medium">
              {processedData[hoveredIndex].label}
            </div>
            <div className="text-muted-foreground">
              n: {processedData[hoveredIndex].values.length}
            </div>
            <div className="text-muted-foreground">
              Median: {processedData[hoveredIndex].median.toFixed(2)}
            </div>
            <div className="text-muted-foreground">
              Q1-Q3: {processedData[hoveredIndex].q1.toFixed(2)} -{" "}
              {processedData[hoveredIndex].q3.toFixed(2)}
            </div>
          </div>
        </div>
      )}
    </ChartContainer>
  )
}

"use client"

import * as React from "react"
import { scaleBand, scaleLinear } from "d3-scale"

import { cn } from "@/lib/utils"

export interface CandlestickDataPoint {
  date: string | Date
  open: number
  high: number
  low: number
  close: number
}

export interface CandlestickChartProps {
  data: CandlestickDataPoint[]
  className?: string
  upColor?: string
  downColor?: string
  showGrid?: boolean
  showTooltip?: boolean
  hollowCandles?: boolean
  aspectRatio?: number
  valueFormatter?: (value: number) => string
  dateFormatter?: (date: Date) => string
}

export function CandlestickChart({
  data,
  className,
  upColor = "#22c55e",
  downColor = "#ef4444",
  showGrid = true,
  showTooltip = true,
  hollowCandles = false,
  aspectRatio = 2.5,
  valueFormatter = (value) => `$${value.toFixed(0)}`,
  dateFormatter = (date) =>
    date.toLocaleDateString("en-US", { month: "short" }),
}: CandlestickChartProps) {
  const containerRef = React.useRef<HTMLDivElement>(null)
  const [dimensions, setDimensions] = React.useState({ width: 0, height: 0 })
  const [hoveredIndex, setHoveredIndex] = React.useState<number | null>(null)
  const [tooltipPos, setTooltipPos] = React.useState({ x: 0, y: 0 })

  // Responsive sizing
  React.useEffect(() => {
    const updateDimensions = () => {
      if (containerRef.current) {
        const width = containerRef.current.offsetWidth
        setDimensions({ width, height: width / aspectRatio })
      }
    }
    updateDimensions()
    window.addEventListener("resize", updateDimensions)
    return () => window.removeEventListener("resize", updateDimensions)
  }, [aspectRatio])

  const { width, height } = dimensions
  const margin = { top: 20, right: 20, bottom: 40, left: 50 }
  const innerWidth = Math.max(0, width - margin.left - margin.right)
  const innerHeight = Math.max(0, height - margin.top - margin.bottom)

  // X Scale
  const xScale = React.useMemo(() => {
    return scaleBand()
      .domain(data.map((d) => String(d.date)))
      .range([0, innerWidth])
      .padding(0.2)
  }, [data, innerWidth])

  // Y Scale (price)
  const yScale = React.useMemo(() => {
    const allPrices = data.flatMap((d) => [d.high, d.low])
    const minPrice = Math.min(...allPrices)
    const maxPrice = Math.max(...allPrices)
    const padding = (maxPrice - minPrice) * 0.1
    return scaleLinear()
      .domain([Math.max(0, minPrice - padding), maxPrice + padding])
      .range([innerHeight, 0])
      .nice()
  }, [data, innerHeight])

  const candleWidth = xScale.bandwidth() * 0.8
  const ticks = yScale.ticks(5)

  // Get unique months for x-axis labels
  const monthLabels = React.useMemo(() => {
    const labels: { date: string; x: number }[] = []
    let lastMonth = -1
    data.forEach((d) => {
      const date = new Date(d.date)
      const month = date.getMonth()
      if (month !== lastMonth) {
        labels.push({
          date: String(d.date),
          x: (xScale(String(d.date)) ?? 0) + xScale.bandwidth() / 2,
        })
        lastMonth = month
      }
    })
    return labels
  }, [data, xScale])

  if (width === 0) {
    return <div ref={containerRef} className={cn("w-full", className)} />
  }

  return (
    <div ref={containerRef} className={cn("relative w-full", className)}>
      <svg
        width={width}
        height={height}
        viewBox={`0 0 ${width} ${height}`}
        className="overflow-visible"
      >
        <g transform={`translate(${margin.left}, ${margin.top})`}>
          {/* Grid - dashed lines like area chart */}
          {showGrid && (
            <>
              {/* Horizontal grid lines */}
              {ticks.map((tick) => (
                <line
                  key={`h-${tick}`}
                  x1={0}
                  x2={innerWidth}
                  y1={yScale(tick)}
                  y2={yScale(tick)}
                  stroke="hsl(var(--border))"
                  strokeDasharray="3 3"
                  strokeOpacity={0.5}
                />
              ))}
              {/* Vertical grid lines at month boundaries */}
              {monthLabels.map((label, i) => (
                <line
                  key={`v-${i}`}
                  x1={label.x}
                  x2={label.x}
                  y1={0}
                  y2={innerHeight}
                  stroke="hsl(var(--border))"
                  strokeDasharray="3 3"
                  strokeOpacity={0.5}
                />
              ))}
            </>
          )}

          {/* Candlesticks */}
          {data.map((d, index) => {
            const isUp = d.close >= d.open
            const color = isUp ? upColor : downColor
            const bodyTop = isUp ? d.close : d.open
            const bodyBottom = isUp ? d.open : d.close
            const x = (xScale(String(d.date)) ?? 0) + xScale.bandwidth() / 2
            const isHovered = hoveredIndex === index

            // For hollow candles: up candles are hollow, down are filled
            const fill = hollowCandles ? (isUp ? "transparent" : color) : color

            return (
              <g
                key={index}
                className={cn(
                  "cursor-pointer transition-opacity duration-200",
                  hoveredIndex !== null && !isHovered && "opacity-40"
                )}
                onMouseEnter={(e) => {
                  setHoveredIndex(index)
                  const rect = containerRef.current?.getBoundingClientRect()
                  if (rect) {
                    setTooltipPos({
                      x: e.clientX - rect.left,
                      y: e.clientY - rect.top,
                    })
                  }
                }}
                onMouseMove={(e) => {
                  const rect = containerRef.current?.getBoundingClientRect()
                  if (rect) {
                    setTooltipPos({
                      x: e.clientX - rect.left,
                      y: e.clientY - rect.top,
                    })
                  }
                }}
                onMouseLeave={() => setHoveredIndex(null)}
              >
                {/* Wick (high to low) */}
                <line
                  x1={x}
                  x2={x}
                  y1={yScale(d.high)}
                  y2={yScale(d.low)}
                  stroke={color}
                  strokeWidth={1}
                />

                {/* Body */}
                <rect
                  x={x - candleWidth / 2}
                  y={yScale(bodyTop)}
                  width={candleWidth}
                  height={Math.max(1, yScale(bodyBottom) - yScale(bodyTop))}
                  fill={fill}
                  stroke={color}
                  strokeWidth={1}
                  rx={1}
                />
              </g>
            )
          })}

          {/* X Axis - Month labels */}
          <g transform={`translate(0, ${innerHeight})`}>
            {monthLabels.map((label, i) => {
              const date = new Date(label.date)
              return (
                <text
                  key={i}
                  x={label.x}
                  y={24}
                  textAnchor="middle"
                  className="fill-muted-foreground text-xs"
                >
                  {dateFormatter(date)}
                </text>
              )
            })}
          </g>

          {/* Y Axis */}
          <g>
            {ticks.map((tick) => (
              <text
                key={tick}
                x={-12}
                y={yScale(tick)}
                dy="0.32em"
                textAnchor="end"
                className="fill-muted-foreground text-xs"
              >
                {valueFormatter(tick)}
              </text>
            ))}
          </g>
        </g>
      </svg>

      {/* Tooltip - auto-adjusts position based on available space */}
      {showTooltip &&
        hoveredIndex !== null &&
        (() => {
          const tooltipWidth = 140
          const tooltipHeight = 120
          const padding = 10

          // Determine horizontal position
          const spaceOnRight = width - tooltipPos.x
          const showOnLeft = spaceOnRight < tooltipWidth + padding * 2

          // Determine vertical position
          const spaceOnTop = tooltipPos.y
          const showBelow = spaceOnTop < tooltipHeight + padding

          return (
            <div
              className="pointer-events-none absolute z-50"
              style={{
                left: showOnLeft
                  ? tooltipPos.x - padding
                  : tooltipPos.x + padding,
                top: showBelow
                  ? tooltipPos.y + padding
                  : tooltipPos.y - padding,
                transform: `translate(${showOnLeft ? "-100%" : "0"}, ${showBelow ? "0" : "-100%"})`,
              }}
            >
              <div className="bg-background rounded-lg border px-3 py-2 shadow-lg">
                <p className="text-foreground mb-1 text-sm font-medium">
                  {new Date(data[hoveredIndex].date).toLocaleDateString(
                    "en-US",
                    {
                      month: "short",
                      day: "numeric",
                      year: "numeric",
                    }
                  )}
                </p>
                <div className="grid grid-cols-2 gap-x-4 gap-y-0.5 text-sm">
                  <span className="text-muted-foreground">Open</span>
                  <span
                    className="font-mono"
                    style={{
                      color:
                        data[hoveredIndex].close >= data[hoveredIndex].open
                          ? upColor
                          : downColor,
                    }}
                  >
                    {valueFormatter(data[hoveredIndex].open)}
                  </span>
                  <span className="text-muted-foreground">High</span>
                  <span
                    className="font-mono"
                    style={{
                      color:
                        data[hoveredIndex].close >= data[hoveredIndex].open
                          ? upColor
                          : downColor,
                    }}
                  >
                    {valueFormatter(data[hoveredIndex].high)}
                  </span>
                  <span className="text-muted-foreground">Low</span>
                  <span
                    className="font-mono"
                    style={{
                      color:
                        data[hoveredIndex].close >= data[hoveredIndex].open
                          ? upColor
                          : downColor,
                    }}
                  >
                    {valueFormatter(data[hoveredIndex].low)}
                  </span>
                  <span className="text-muted-foreground">Close</span>
                  <span
                    className="font-mono"
                    style={{
                      color:
                        data[hoveredIndex].close >= data[hoveredIndex].open
                          ? upColor
                          : downColor,
                    }}
                  >
                    {valueFormatter(data[hoveredIndex].close)}
                  </span>
                </div>
              </div>
            </div>
          )
        })()}
    </div>
  )
}

"use client"

import * as React from "react"
import { scaleBand, scaleLinear } from "d3-scale"

import { cn } from "@/lib/utils"

import { ChartAxis } from "../chart-axis"
import type { BaseChartProps, ChartConfig } from "../chart-config"
import { ChartContainer } from "../chart-container"
import { ChartHorizontalGrid } from "../chart-grid"
import { ChartTooltipContent } from "../chart-tooltip"

export interface WaterfallDataPoint {
  label: string
  value: number
  isTotal?: boolean
  isSubtotal?: boolean
}

export interface WaterfallChartProps extends BaseChartProps {
  data: WaterfallDataPoint[]
  positiveColor?: string
  negativeColor?: string
  totalColor?: string
  connectorColor?: string
  showConnector?: boolean
  barRadius?: number
  xAxisLabel?: string
  yAxisLabel?: string
}

export function WaterfallChart({
  data,
  config,
  className,
  width = 700,
  height = 400,
  margin = { top: 20, right: 20, bottom: 60, left: 60 },
  showGrid = true,
  showTooltip = true,
  positiveColor = "#3b82f6",
  negativeColor = "#93c5fd",
  totalColor = "#1e40af",
  connectorColor = "currentColor",
  showConnector = true,
  barRadius = 2,
  xAxisLabel,
  yAxisLabel,
}: WaterfallChartProps) {
  const [hoveredIndex, setHoveredIndex] = React.useState<number | null>(null)

  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom

  // Calculate cumulative values
  const processedData = React.useMemo(() => {
    let runningTotal = 0
    return data.map((d, i) => {
      const start = d.isTotal || d.isSubtotal ? 0 : runningTotal
      const end = d.isTotal || d.isSubtotal ? d.value : runningTotal + d.value
      runningTotal = end
      return {
        ...d,
        start,
        end,
        isPositive: d.value >= 0,
      }
    })
  }, [data])

  // Scales
  const xScale = React.useMemo(() => {
    return scaleBand()
      .domain(data.map((d) => d.label))
      .range([0, innerWidth])
      .padding(0.3)
  }, [data, innerWidth])

  const yScale = React.useMemo(() => {
    const allValues = processedData.flatMap((d) => [d.start, d.end])
    const minVal = Math.min(0, ...allValues)
    const maxVal = Math.max(0, ...allValues)
    const padding = (maxVal - minVal) * 0.1
    return scaleLinear()
      .domain([minVal - padding, maxVal + padding])
      .range([innerHeight, 0])
      .nice()
  }, [processedData, innerHeight])

  return (
    <ChartContainer config={config} className={cn("!aspect-auto", className)}>
      <svg viewBox={`0 0 ${width} ${height}`} className="h-full w-full">
        <g transform={`translate(${margin.left}, ${margin.top})`}>
          {/* Grid */}
          {showGrid && (
            <ChartHorizontalGrid scale={yScale} width={innerWidth} />
          )}

          {/* Zero line */}
          <line
            x1={0}
            x2={innerWidth}
            y1={yScale(0)}
            y2={yScale(0)}
            stroke="currentColor"
            strokeWidth={1}
            className="text-border"
          />

          {/* Bars and connectors */}
          {processedData.map((d, index) => {
            const x = xScale(d.label) ?? 0
            const barWidth = xScale.bandwidth()
            const y1 = yScale(Math.max(d.start, d.end))
            const y2 = yScale(Math.min(d.start, d.end))
            const barHeight = Math.abs(y2 - y1)

            const color =
              d.isTotal || d.isSubtotal
                ? totalColor
                : d.isPositive
                  ? positiveColor
                  : negativeColor

            const isHovered = hoveredIndex === index

            return (
              <g key={index}>
                {/* Connector line */}
                {showConnector && index > 0 && !d.isTotal && (
                  <line
                    x1={xScale(processedData[index - 1].label)! + barWidth}
                    x2={x}
                    y1={yScale(processedData[index - 1].end)}
                    y2={yScale(processedData[index - 1].end)}
                    stroke={connectorColor}
                    strokeWidth={1}
                    strokeDasharray="3,3"
                    className="text-muted-foreground/50"
                  />
                )}

                {/* Bar */}
                <rect
                  x={x}
                  y={y1}
                  width={barWidth}
                  height={Math.max(1, barHeight)}
                  fill={color}
                  rx={barRadius}
                  ry={barRadius}
                  className={cn(
                    "cursor-pointer transition-opacity duration-200",
                    hoveredIndex !== null && !isHovered && "opacity-50"
                  )}
                  onMouseEnter={() => setHoveredIndex(index)}
                  onMouseLeave={() => setHoveredIndex(null)}
                />

                {/* Value label */}
                <text
                  x={x + barWidth / 2}
                  y={d.value >= 0 ? y1 - 5 : y2 + 14}
                  textAnchor="middle"
                  className="fill-foreground pointer-events-none text-[10px] font-medium"
                >
                  {d.value >= 0 ? "+" : ""}
                  {d.value.toLocaleString()}
                </text>
              </g>
            )
          })}

          {/* X Axis */}
          <ChartAxis
            scale={xScale}
            orientation="bottom"
            transform={`translate(0, ${innerHeight})`}
            label={xAxisLabel}
          />

          {/* Y Axis */}
          <ChartAxis scale={yScale} orientation="left" label={yAxisLabel} />
        </g>
      </svg>

      {/* Tooltip */}
      {showTooltip && hoveredIndex !== null && (
        <div
          className="pointer-events-none absolute z-50"
          style={{
            left:
              margin.left +
              (xScale(processedData[hoveredIndex].label) ?? 0) +
              xScale.bandwidth() / 2,
            top:
              margin.top +
              yScale(
                Math.max(
                  processedData[hoveredIndex].start,
                  processedData[hoveredIndex].end
                )
              ) -
              50,
          }}
        >
          <div className="border-border/50 bg-background -translate-x-1/2 rounded-lg border px-2.5 py-1.5 text-xs shadow-xl">
            <div className="font-medium">
              {processedData[hoveredIndex].label}
            </div>
            <div className="text-muted-foreground">
              Change: {processedData[hoveredIndex].value >= 0 ? "+" : ""}
              {processedData[hoveredIndex].value.toLocaleString()}
            </div>
            <div className="text-muted-foreground">
              Running Total: {processedData[hoveredIndex].end.toLocaleString()}
            </div>
          </div>
        </div>
      )}
    </ChartContainer>
  )
}

"use client"

import * as React from "react"
import { scaleLinear } from "d3-scale"
import { area, curveBasis } from "d3-shape"

import { cn } from "@/lib/utils"

import type { BaseChartProps, ChartConfig } from "../chart-config"
import { ChartContainer } from "../chart-container"

export interface FunnelSeries {
  name: string
  values: number[] // Value at each stage
  color?: string
}

export interface FunnelChartProps extends BaseChartProps {
  /** Stage labels */
  stages: string[]
  /** Data series - each series flows through all stages */
  series: FunnelSeries[]
  /** Color scheme */
  colorScheme?: "orange" | "blue" | "purple" | "green" | "pink" | "custom"
  /** Show stage markers (vertical lines) */
  showStageMarkers?: boolean
  /** Show value pills at each stage */
  showValuePills?: boolean
  /** Position of value pills */
  pillPosition?: "top" | "bottom" | "both" | "center"
  /** Animate on mount */
  animate?: boolean
  /** Animation duration */
  animationDuration?: number
  /** Value formatter */
  valueFormatter?: (value: number) => string
  /** Minimum height for the flow (prevents collapse to zero) */
  minFlowHeight?: number
  /** How much of vertical space to use (0-1, default 0.85) */
  flowExpansion?: number
  /** Click handler */
  onSeriesClick?: (series: FunnelSeries, stageIndex: number) => void
}

// Legacy interface for backwards compatibility
export interface FunnelDataPoint {
  label: string
  value: number
  color?: string
}

// Color schemes matching the images - gradient from light to dark
const COLOR_SCHEMES = {
  orange: [
    "#FEF3C7", // lightest
    "#FDE68A",
    "#FCD34D",
    "#FBBF24",
    "#F59E0B",
    "#D97706",
    "#B45309",
    "#92400E", // darkest
  ],
  blue: [
    "#DBEAFE",
    "#BFDBFE",
    "#93C5FD",
    "#60A5FA",
    "#3B82F6",
    "#2563EB",
    "#1D4ED8",
    "#1E40AF",
  ],
  purple: [
    "#EDE9FE",
    "#DDD6FE",
    "#C4B5FD",
    "#A78BFA",
    "#8B5CF6",
    "#7C3AED",
    "#6D28D9",
    "#5B21B6",
  ],
  green: [
    "#D1FAE5",
    "#A7F3D0",
    "#6EE7B7",
    "#34D399",
    "#10B981",
    "#059669",
    "#047857",
    "#065F46",
  ],
  pink: [
    "#FCE7F3",
    "#FBCFE8",
    "#F9A8D4",
    "#F472B6",
    "#EC4899",
    "#DB2777",
    "#BE185D",
    "#9D174D",
  ],
  custom: [],
}

export function FunnelChart({
  stages,
  series,
  config,
  className,
  width = 900,
  height = 320,
  margin = { top: 45, right: 40, bottom: 45, left: 40 },
  showTooltip = true,
  colorScheme = "orange",
  showStageMarkers = true,
  showValuePills = true,
  pillPosition = "both",
  animate = true,
  animationDuration = 1000,
  valueFormatter = (v) => v.toLocaleString(),
  minFlowHeight = 12,
  flowExpansion = 0.98,
  onSeriesClick,
}: FunnelChartProps) {
  const [animationProgress, setAnimationProgress] = React.useState(
    animate ? 0 : 1
  )
  const [hoveredSeries, setHoveredSeries] = React.useState<number | null>(null)
  const [tooltipData, setTooltipData] = React.useState<{
    x: number
    y: number
    seriesIndex: number
    stageIndex: number
  } | null>(null)
  const containerRef = React.useRef<HTMLDivElement>(null)
  const gradientId = React.useId().replace(/:/g, "")

  // Animation
  React.useEffect(() => {
    if (!animate) return
    const startTime = Date.now()
    const animateFrame = () => {
      const elapsed = Date.now() - startTime
      const progress = Math.min(elapsed / animationDuration, 1)
      // Ease out cubic
      const eased = 1 - Math.pow(1 - progress, 3)
      setAnimationProgress(eased)
      if (progress < 1) requestAnimationFrame(animateFrame)
    }
    requestAnimationFrame(animateFrame)
  }, [animate, animationDuration])

  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom
  const centerY = innerHeight / 2

  const stageCount = stages.length
  const seriesCount = series.length

  // Get color for series - innermost is lightest, outermost is darkest
  const getColor = (index: number): string => {
    if (colorScheme === "custom" && series[index]?.color) {
      return series[index].color!
    }
    const scheme = COLOR_SCHEMES[colorScheme] || COLOR_SCHEMES.orange
    // Map series index to color - distribute evenly across scheme
    const colorIndex = Math.floor(
      (index / Math.max(seriesCount - 1, 1)) * (scheme.length - 1)
    )
    return scheme[Math.min(colorIndex, scheme.length - 1)]
  }

  // Calculate max total at any stage for scaling
  const maxStageTotal = React.useMemo(() => {
    let max = 0
    for (let stageIndex = 0; stageIndex < stageCount; stageIndex++) {
      let total = 0
      for (const s of series) {
        total += s.values[stageIndex] || 0
      }
      max = Math.max(max, total)
    }
    return max || 1
  }, [series, stageCount])

  // Y scale - maps values to heights (half the inner height for symmetric expansion)
  // flowExpansion controls how much of the available vertical space is used
  const yScale = scaleLinear()
    .domain([0, maxStageTotal])
    .range([0, (innerHeight / 2) * flowExpansion])

  // Generate intermediate points for smoother curves
  const generateIntermediatePoints = (
    x1: number,
    y1: number,
    x2: number,
    y2: number,
    segments: number = 3
  ): [number, number][] => {
    const points: [number, number][] = []
    for (let i = 0; i <= segments; i++) {
      const t = i / segments
      // Use ease-in-out for natural flow
      const easeT = t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2
      points.push([x1 + (x2 - x1) * t, y1 + (y2 - y1) * easeT])
    }
    return points
  }

  // Generate flowing area paths for each series
  const areaPaths = React.useMemo(() => {
    const paths: {
      topPath: string
      bottomPath: string
      color: string
      seriesIndex: number
    }[] = []

    // Calculate heights at each stage for each series
    const seriesHeights: number[][] = []
    for (let stageIndex = 0; stageIndex < stageCount; stageIndex++) {
      const heights: number[] = []
      for (let seriesIndex = 0; seriesIndex < seriesCount; seriesIndex++) {
        const value = series[seriesIndex].values[stageIndex] || 0
        const height = Math.max(
          yScale(value) * animationProgress,
          minFlowHeight * animationProgress
        )
        heights.push(height)
      }
      seriesHeights.push(heights)
    }

    // Calculate cumulative offsets at each stage
    const cumulativeOffsets: number[][] = []
    for (let stageIndex = 0; stageIndex < stageCount; stageIndex++) {
      const offsets: number[] = [0]
      let cumulative = 0
      for (let seriesIndex = 0; seriesIndex < seriesCount; seriesIndex++) {
        cumulative += seriesHeights[stageIndex][seriesIndex]
        offsets.push(cumulative)
      }
      cumulativeOffsets.push(offsets)
    }

    // Create area path for each series (from innermost to outermost)
    for (let seriesIndex = 0; seriesIndex < seriesCount; seriesIndex++) {
      // Build points with intermediate values for smooth curves
      const topPoints: [number, number][] = []
      const bottomPoints: [number, number][] = []

      for (let stageIndex = 0; stageIndex < stageCount; stageIndex++) {
        const stageX = (stageIndex / (stageCount - 1)) * innerWidth
        const offset = cumulativeOffsets[stageIndex][seriesIndex]
        const height = seriesHeights[stageIndex][seriesIndex]

        // Top edge (above center line)
        const topY = centerY - offset - height
        // Bottom edge (below center line)
        const bottomY = centerY + offset + height

        if (stageIndex > 0) {
          // Add intermediate points for smooth transitions
          const prevStageX = ((stageIndex - 1) / (stageCount - 1)) * innerWidth
          const prevOffset = cumulativeOffsets[stageIndex - 1][seriesIndex]
          const prevHeight = seriesHeights[stageIndex - 1][seriesIndex]
          const prevTopY = centerY - prevOffset - prevHeight
          const prevBottomY = centerY + prevOffset + prevHeight

          const intermediateTop = generateIntermediatePoints(
            prevStageX,
            prevTopY,
            stageX,
            topY,
            4
          )
          const intermediateBottom = generateIntermediatePoints(
            prevStageX,
            prevBottomY,
            stageX,
            bottomY,
            4
          )

          // Skip first point to avoid duplication
          topPoints.push(...intermediateTop.slice(1))
          bottomPoints.push(...intermediateBottom.slice(1))
        } else {
          topPoints.push([stageX, topY])
          bottomPoints.push([stageX, bottomY])
        }
      }

      // Create SVG path using D3 area
      const areaGenerator = area<[number, number]>()
        .x((d) => d[0])
        .y0((_, i) => bottomPoints[i]?.[1] ?? centerY)
        .y1((d) => d[1])
        .curve(curveBasis)

      const pathData = areaGenerator(topPoints)

      if (pathData) {
        paths.push({
          topPath: pathData,
          bottomPath: pathData, // Same path works due to y0/y1
          color: getColor(seriesIndex),
          seriesIndex,
        })
      }
    }

    // Reverse so innermost (first series) is rendered last (on top visually matches images)
    return paths.reverse()
  }, [
    series,
    seriesCount,
    stageCount,
    innerWidth,
    centerY,
    yScale,
    animationProgress,
    minFlowHeight,
    flowExpansion,
    colorScheme,
  ])

  // Calculate stage X positions
  const stagePositions = React.useMemo(() => {
    return stages.map((_, i) => (i / (stageCount - 1)) * innerWidth)
  }, [stages, stageCount, innerWidth])

  // Calculate values to display in pills (top and bottom at each stage)
  const pillData = React.useMemo(() => {
    return stages.map((_, stageIndex) => {
      // Get values sorted by their position (outer to inner for display)
      const stageValues = series.map((s, i) => ({
        value: s.values[stageIndex] || 0,
        seriesIndex: i,
      }))

      // Top half shows first half of series, bottom shows second half
      const midPoint = Math.ceil(seriesCount / 2)
      const topSeries = stageValues.slice(0, midPoint)
      const bottomSeries = stageValues.slice(midPoint)

      return {
        x: stagePositions[stageIndex],
        topValue: topSeries.reduce((sum, s) => sum + s.value, 0),
        bottomValue: bottomSeries.reduce((sum, s) => sum + s.value, 0),
        totalValue: stageValues.reduce((sum, s) => sum + s.value, 0),
      }
    })
  }, [series, seriesCount, stages, stagePositions])

  // Handle mouse move for tooltip
  const handleMouseMove = (e: React.MouseEvent, seriesIndex: number) => {
    if (!showTooltip) return
    const rect = containerRef.current?.getBoundingClientRect()
    if (rect) {
      // Determine which stage we're over
      const relativeX = e.clientX - rect.left - margin.left
      const stageIndex = Math.round((relativeX / innerWidth) * (stageCount - 1))
      setTooltipData({
        x: e.clientX - rect.left,
        y: e.clientY - rect.top,
        seriesIndex,
        stageIndex: Math.max(0, Math.min(stageCount - 1, stageIndex)),
      })
    }
  }

  return (
    <ChartContainer
      config={config}
      className={cn("!aspect-auto flex-col", className)}
    >
      <div className="relative mx-auto w-full max-w-[400px]">
        <div
          ref={containerRef}
          className="relative w-full"
          style={{ aspectRatio: `${width}/${height}` }}
        >
          <svg
            viewBox={`0 0 ${width} ${height}`}
            className="h-full w-full overflow-visible"
          >
            {/* Gradient definitions for each series */}
            <defs>
              {series.map((_, i) => {
                const color = getColor(i)
                return (
                  <linearGradient
                    key={i}
                    id={`flow-gradient-${gradientId}-${i}`}
                    x1="0%"
                    y1="0%"
                    x2="100%"
                    y2="0%"
                  >
                    <stop offset="0%" stopColor={color} stopOpacity={1} />
                    <stop offset="50%" stopColor={color} stopOpacity={1} />
                    <stop offset="100%" stopColor={color} stopOpacity={1} />
                  </linearGradient>
                )
              })}
              {/* Drop shadow filter */}
              <filter
                id={`pill-shadow-${gradientId}`}
                x="-20%"
                y="-20%"
                width="140%"
                height="140%"
              >
                <feDropShadow
                  dx="0"
                  dy="1"
                  stdDeviation="2"
                  floodOpacity="0.15"
                />
              </filter>
            </defs>

            <g transform={`translate(${margin.left}, ${margin.top})`}>
              {/* Background fade for depth effect */}
              <rect
                x={0}
                y={0}
                width={innerWidth}
                height={innerHeight}
                fill="transparent"
              />

              {/* Flowing area paths - rendered from outermost to innermost */}
              {areaPaths.map(({ topPath, color, seriesIndex }, i) => (
                <path
                  key={i}
                  d={topPath}
                  fill={`url(#flow-gradient-${gradientId}-${seriesIndex})`}
                  className={cn(
                    "cursor-pointer transition-opacity duration-200",
                    hoveredSeries !== null &&
                      hoveredSeries !== seriesIndex &&
                      "opacity-30"
                  )}
                  onMouseEnter={() => setHoveredSeries(seriesIndex)}
                  onMouseMove={(e) => handleMouseMove(e, seriesIndex)}
                  onMouseLeave={() => {
                    setHoveredSeries(null)
                    setTooltipData(null)
                  }}
                  onClick={() => {
                    if (tooltipData) {
                      onSeriesClick?.(
                        series[seriesIndex],
                        tooltipData.stageIndex
                      )
                    }
                  }}
                />
              ))}

              {/* Stage markers (vertical lines) - only between stages, not at edges */}
              {showStageMarkers &&
                stagePositions
                  .slice(1, -1)
                  .map((x, i) => (
                    <line
                      key={i}
                      x1={x}
                      y1={0}
                      x2={x}
                      y2={innerHeight}
                      stroke="white"
                      strokeWidth={3}
                      strokeOpacity={0.9}
                      className="pointer-events-none"
                    />
                  ))}

              {/* Value pills */}
              {showValuePills &&
                animationProgress > 0.6 &&
                pillData.map(({ x, topValue, bottomValue, totalValue }, i) => (
                  <g
                    key={i}
                    style={{
                      opacity: Math.min(1, (animationProgress - 0.6) * 2.5),
                    }}
                  >
                    {/* Top pill */}
                    {(pillPosition === "top" || pillPosition === "both") &&
                      topValue > 0 && (
                        <g transform={`translate(${x}, -25)`}>
                          <rect
                            x={-40}
                            y={-14}
                            width={80}
                            height={28}
                            rx={14}
                            fill="white"
                            filter={`url(#pill-shadow-${gradientId})`}
                          />
                          <text
                            textAnchor="middle"
                            dominantBaseline="middle"
                            className="text-sm font-semibold"
                            fill="#374151"
                          >
                            {valueFormatter(topValue)}
                          </text>
                        </g>
                      )}

                    {/* Bottom pill */}
                    {(pillPosition === "bottom" || pillPosition === "both") &&
                      bottomValue > 0 && (
                        <g transform={`translate(${x}, ${innerHeight + 25})`}>
                          <rect
                            x={-40}
                            y={-14}
                            width={80}
                            height={28}
                            rx={14}
                            fill="white"
                            filter={`url(#pill-shadow-${gradientId})`}
                          />
                          <text
                            textAnchor="middle"
                            dominantBaseline="middle"
                            className="text-sm font-semibold"
                            fill="#374151"
                          >
                            {valueFormatter(bottomValue)}
                          </text>
                        </g>
                      )}

                    {/* Center pill - shows total */}
                    {pillPosition === "center" && (
                      <g transform={`translate(${x}, ${centerY})`}>
                        <rect
                          x={-40}
                          y={-14}
                          width={80}
                          height={28}
                          rx={14}
                          fill="white"
                          filter={`url(#pill-shadow-${gradientId})`}
                        />
                        <text
                          textAnchor="middle"
                          dominantBaseline="middle"
                          className="text-sm font-semibold"
                          fill="#374151"
                        >
                          {valueFormatter(totalValue)}
                        </text>
                      </g>
                    )}
                  </g>
                ))}
            </g>
          </svg>

          {/* Tooltip */}
          {showTooltip && tooltipData && (
            <div
              className="pointer-events-none absolute z-50 -translate-x-1/2 -translate-y-full"
              style={{
                left: tooltipData.x,
                top: tooltipData.y - 10,
              }}
            >
              <div className="bg-popover text-popover-foreground rounded-lg border px-3 py-2 shadow-lg">
                <div className="flex items-center gap-2">
                  <div
                    className="h-3 w-3 rounded-sm"
                    style={{
                      backgroundColor: getColor(tooltipData.seriesIndex),
                    }}
                  />
                  <span className="font-medium">
                    {series[tooltipData.seriesIndex]?.name}
                  </span>
                </div>
                <div className="mt-1 text-sm">
                  <span className="text-muted-foreground">Stage: </span>
                  <span className="font-medium">
                    {stages[tooltipData.stageIndex]}
                  </span>
                </div>
                <div className="text-sm">
                  <span className="text-muted-foreground">Value: </span>
                  <span className="font-semibold">
                    {valueFormatter(
                      series[tooltipData.seriesIndex]?.values[
                        tooltipData.stageIndex
                      ] || 0
                    )}
                  </span>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </ChartContainer>
  )
}

"use client"

import * as React from "react"
import { interpolateRgb } from "d3-interpolate"
import { scaleBand, scaleLinear } from "d3-scale"

import { cn } from "@/lib/utils"

import { ChartAxis } from "../chart-axis"
import type { BaseChartProps } from "../chart-config"
import { ChartContainer } from "../chart-container"

// ============================================================================
// Types & Interfaces
// ============================================================================

export interface HeatmapDataPoint {
  x: string | number
  y: string | number
  value: number
  date?: Date | string
  metadata?: Record<string, unknown>
}

export interface CalendarDataPoint {
  date: Date | string
  value: number
  metadata?: Record<string, unknown>
}

export interface HeatmapLegendConfig {
  show?: boolean
  position?: "top-right" | "bottom-right" | "bottom-left" | "top-left"
  showLabels?: boolean
  lessLabel?: string
  moreLabel?: string
}

export interface RadialHeatmapDataPoint {
  day: number | string // 0-6 (Sunday-Saturday) or day name
  hour: number | string // 0-23 or hour string like "12am"
  value: number
  metadata?: Record<string, unknown>
}

export interface HeatmapChartProps extends BaseChartProps {
  /** Data points for the heatmap */
  data: HeatmapDataPoint[] | CalendarDataPoint[] | RadialHeatmapDataPoint[]
  /** Variant style */
  variant?: "matrix" | "calendar" | "compact" | "radial"
  /** X-axis labels (for matrix variant) */
  xLabels?: string[]
  /** Y-axis labels (for matrix variant) */
  yLabels?: string[]
  /** Color scale - array of colors from low to high */
  colorScale?: string[]
  /** Color theme preset */
  colorTheme?:
    | "green"
    | "blue"
    | "purple"
    | "orange"
    | "red"
    | "gray"
    | "pink"
    | "heat"
    | "thermal"
  /** Show values in cells */
  showValues?: boolean
  /** Cell border radius */
  cellRadius?: number
  /** Cell padding/gap */
  cellGap?: number
  /** Cell size (for calendar variant) */
  cellSize?: number
  /** X-axis label */
  xAxisLabel?: string
  /** Y-axis label */
  yAxisLabel?: string
  /** Value formatter */
  valueFormat?: (value: number) => string
  /** Start of week (0 = Sunday, 1 = Monday) */
  weekStartsOn?: 0 | 1
  /** Show month labels (calendar variant) */
  showMonthLabels?: boolean
  /** Show weekday labels (calendar variant) */
  showWeekdayLabels?: boolean
  /** Legend configuration */
  legend?: HeatmapLegendConfig
  /** Number of color levels */
  levels?: number
  /** Custom level function */
  getLevelFromValue?: (value: number, max: number) => number
  /** On cell click handler */
  onCellClick?: (data: HeatmapDataPoint | CalendarDataPoint) => void
  /** Empty cell color */
  emptyColor?: string
}

// ============================================================================
// Color Themes
// ============================================================================

const COLOR_THEMES = {
  green: {
    light: ["#ebedf0", "#9be9a8", "#40c463", "#30a14e", "#216e39"],
    dark: ["#161b22", "#0e4429", "#006d32", "#26a641", "#39d353"],
  },
  blue: {
    light: ["#ebedf0", "#c6e6ff", "#79c0ff", "#388bfd", "#1f6feb"],
    dark: ["#161b22", "#0d419d", "#1158c7", "#388bfd", "#58a6ff"],
  },
  purple: {
    light: ["#ebedf0", "#d8b4fe", "#a855f7", "#9333ea", "#7e22ce"],
    dark: ["#161b22", "#3b0764", "#6b21a8", "#9333ea", "#a855f7"],
  },
