const WEEKDAYS_FULL = [
  "Sunday",
  "Monday",
  "Tuesday",
  "Wednesday",
  "Thursday",
  "Friday",
  "Saturday",
]

const HOURS_12 = [
  "12am",
  "1am",
  "2am",
  "3am",
  "4am",
  "5am",
  "6am",
  "7am",
  "8am",
  "9am",
  "10am",
  "11am",
  "12pm",
  "1pm",
  "2pm",
  "3pm",
  "4pm",
  "5pm",
  "6pm",
  "7pm",
  "8pm",
  "9pm",
  "10pm",
  "11pm",
]

interface RadialHeatmapProps {
  data: RadialHeatmapDataPoint[]
  config?: BaseChartProps["config"]
  className?: string
  width: number
  height: number
  margin: { top: number; right: number; bottom: number; left: number }
  showTooltip: boolean
  colors: readonly string[] | string[]
  cellGap: number
  valueFormat: (value: number) => string
  weekStartsOn: 0 | 1
  legend: HeatmapLegendConfig
  onCellClick?: (data: RadialHeatmapDataPoint) => void
  emptyColor: string
  hoveredCell: {
    x: number
    y: number
    data: HeatmapDataPoint | CalendarDataPoint | RadialHeatmapDataPoint
  } | null
  setHoveredCell: React.Dispatch<
    React.SetStateAction<{
      x: number
      y: number
      data: HeatmapDataPoint | CalendarDataPoint | RadialHeatmapDataPoint
    } | null>
  >
}

function RadialHeatmap({
  data,
  config,
  className,
  width,
  height,
  margin,
  showTooltip,
  colors,
  cellGap,
  valueFormat,
  weekStartsOn,
  legend,
  onCellClick,
  emptyColor,
  hoveredCell,
  setHoveredCell,
}: RadialHeatmapProps) {
  // Parse day to index (0-6)
  const parseDayIndex = (day: number | string): number => {
    if (typeof day === "number") return day
    const lower = day.toLowerCase()
    const index = WEEKDAYS_FULL.findIndex((d) =>
      d.toLowerCase().startsWith(lower)
    )
    return index >= 0 ? index : 0
  }

  // Parse hour to index (0-23)
  const parseHourIndex = (hour: number | string): number => {
    if (typeof hour === "number") return hour
    const lower = hour.toLowerCase().replace(/\s/g, "")
    const index = HOURS_12.findIndex((h) => h.toLowerCase() === lower)
    return index >= 0 ? index : 0
  }

  // Build data matrix [day][hour] = value
  const dataMatrix = React.useMemo(() => {
    const matrix: number[][] = Array.from({ length: 7 }, () =>
      Array(24).fill(0)
    )
    data.forEach((d) => {
      const dayIndex = parseDayIndex(d.day)
      const hourIndex = parseHourIndex(d.hour)
      matrix[dayIndex][hourIndex] = (matrix[dayIndex][hourIndex] || 0) + d.value
    })
    return matrix
  }, [data])

  // Get max value for color scaling
  const maxValue = React.useMemo(() => {
    return Math.max(...data.map((d) => d.value), 1)
  }, [data])

  // Calculate dimensions
  const size = Math.min(
    width - margin.left - margin.right,
    height - margin.top - margin.bottom
  )
  const centerX = size / 2
  const centerY = size / 2
  const outerRadius = size / 2 - 30 // Leave space for hour labels
  const innerRadius = outerRadius * 0.35 // Center hole for day labels
  const ringWidth = (outerRadius - innerRadius) / 7 - cellGap / 2

  // Color interpolator
  const getColor = React.useCallback(
    (value: number) => {
      if (value <= 0) return emptyColor
      const t = Math.min(value / maxValue, 1)
      if (colors.length === 2) {
        return interpolateRgb(colors[0], colors[1])(t)
      }
      const segmentSize = 1 / (colors.length - 1)
      const segmentIndex = Math.min(
        Math.floor(t / segmentSize),
        colors.length - 2
      )
      const segmentT = (t - segmentIndex * segmentSize) / segmentSize
      return interpolateRgb(
        colors[segmentIndex],
        colors[segmentIndex + 1]
      )(segmentT)
    },
    [colors, maxValue, emptyColor]
  )

  // Generate arc path
  const generateArc = (dayIndex: number, hourIndex: number): string => {
    // Day rings: Sunday (0) is innermost, Saturday (6) is outermost
    const dayRadius = innerRadius + dayIndex * (ringWidth + cellGap / 2)
    const nextDayRadius = dayRadius + ringWidth

    // Hour segments: 12am starts at bottom (270 degrees), going clockwise
    const hourAngle = 360 / 24
    const startAngle = (270 + hourIndex * hourAngle) % 360
    const endAngle = (startAngle + hourAngle - cellGap) % 360

    const startRad = (startAngle * Math.PI) / 180
    const endRad = (endAngle * Math.PI) / 180

    // Calculate points
    const innerStartX = centerX + dayRadius * Math.cos(startRad)
    const innerStartY = centerY + dayRadius * Math.sin(startRad)
    const innerEndX = centerX + dayRadius * Math.cos(endRad)
    const innerEndY = centerY + dayRadius * Math.sin(endRad)
    const outerStartX = centerX + nextDayRadius * Math.cos(startRad)
    const outerStartY = centerY + nextDayRadius * Math.sin(startRad)
    const outerEndX = centerX + nextDayRadius * Math.cos(endRad)
    const outerEndY = centerY + nextDayRadius * Math.sin(endRad)

    const largeArc = hourAngle - cellGap > 180 ? 1 : 0

    return `
      M ${innerStartX} ${innerStartY}
      A ${dayRadius} ${dayRadius} 0 ${largeArc} 1 ${innerEndX} ${innerEndY}
      L ${outerEndX} ${outerEndY}
      A ${nextDayRadius} ${nextDayRadius} 0 ${largeArc} 0 ${outerStartX} ${outerStartY}
      Z
    `
  }

  // Generate hour label positions
  const hourLabels = React.useMemo(() => {
    const labels: { hour: string; x: number; y: number; angle: number }[] = []
    const labelRadius = outerRadius + 18

    for (let i = 0; i < 24; i++) {
      const angle = (270 + i * 15 + 7.5) % 360 // Center of each hour segment
      const rad = (angle * Math.PI) / 180
      labels.push({
        hour: HOURS_12[i],
        x: centerX + labelRadius * Math.cos(rad),
        y: centerY + labelRadius * Math.sin(rad),
        angle: angle > 90 && angle < 270 ? angle + 180 : angle,
      })
    }
    return labels
  }, [centerX, centerY, outerRadius])

  // Order days based on weekStartsOn
  const orderedDays = React.useMemo(() => {
    const days = [...WEEKDAYS_FULL]
    if (weekStartsOn === 1) {
      // Monday first
      days.push(days.shift()!) // Move Sunday to end
    }
    return days
  }, [weekStartsOn])

  return (
    <ChartContainer config={config} className={cn("relative", className)}>
      <svg
        viewBox={`0 0 ${size + margin.left + margin.right} ${size + margin.top + margin.bottom + 60}`}
        className="h-full w-full"
      >
        <g transform={`translate(${margin.left}, ${margin.top})`}>
          {/* Hour labels around the outside */}
          {hourLabels.map((label, i) => (
            <text
              key={i}
              x={label.x}
              y={label.y}
              textAnchor="middle"
              dominantBaseline="middle"
              className="fill-muted-foreground text-[10px]"
              transform={`rotate(${label.angle - 90}, ${label.x}, ${label.y})`}
            >
              {label.hour}
            </text>
          ))}

          {/* Radial cells */}
          {Array.from({ length: 7 }).map((_, dayIdx) => {
            const actualDayIndex =
              weekStartsOn === 1 ? (dayIdx + 1) % 7 : dayIdx
            return Array.from({ length: 24 }).map((_, hourIdx) => {
              const value = dataMatrix[actualDayIndex][hourIdx]
              const color = getColor(value)
              const path = generateArc(dayIdx, hourIdx)

              const isHovered =
                hoveredCell?.data &&
                "day" in hoveredCell.data &&
                "hour" in hoveredCell.data &&
                parseDayIndex(hoveredCell.data.day) === actualDayIndex &&
                parseHourIndex(hoveredCell.data.hour) === hourIdx

              return (
                <path
                  key={`${dayIdx}-${hourIdx}`}
                  d={path}
                  fill={color}
                  stroke={isHovered ? "var(--foreground)" : "var(--background)"}
                  strokeWidth={isHovered ? 2 : 0.5}
                  className="cursor-pointer transition-all duration-150"
                  onMouseEnter={(e) =>
                    setHoveredCell({
                      x: e.clientX,
                      y: e.clientY,
                      data: {
                        day: actualDayIndex,
                        hour: hourIdx,
                        value,
                      },
                    })
                  }
                  onMouseLeave={() => setHoveredCell(null)}
                  onClick={() =>
                    onCellClick?.({
                      day: actualDayIndex,
                      hour: hourIdx,
                      value,
                    })
                  }
                />
              )
            })
          })}

          {/* Day labels in center */}
          {orderedDays.map((day, i) => (
            <text
              key={day}
              x={centerX}
              y={centerY - innerRadius + 20 + i * 14}
              textAnchor="middle"
              dominantBaseline="middle"
              className="fill-muted-foreground text-[11px] font-medium"
            >
              {day}
            </text>
          ))}
        </g>

        {/* Legend */}
        {legend.show && (
          <g transform={`translate(${margin.left}, ${size + margin.top + 20})`}>
            <defs>
              <linearGradient
                id="radial-heatmap-gradient"
                x1="0"
                y1="0"
                x2="1"
                y2="0"
              >
                {colors.map((color, i) => (
                  <stop
                    key={i}
                    offset={`${(i / (colors.length - 1)) * 100}%`}
                    stopColor={color}
                  />
                ))}
              </linearGradient>
            </defs>
            <text x={0} y={10} className="fill-muted-foreground text-[11px]">
              {legend.lessLabel || "Less"}
            </text>
            <rect
              x={35}
              y={0}
              width={size - 100}
              height={16}
              fill="url(#radial-heatmap-gradient)"
              rx={3}
            />
            <text
              x={size - 60}
              y={10}
              className="fill-muted-foreground text-[11px]"
            >
              {legend.moreLabel || "More"}
            </text>
          </g>
        )}
      </svg>

      {/* Tooltip */}
      {showTooltip &&
        hoveredCell &&
        hoveredCell.data &&
        "day" in hoveredCell.data &&
        "hour" in hoveredCell.data && (
          <div
            className="pointer-events-none fixed z-50"
            style={{
              left: hoveredCell.x + 10,
              top: hoveredCell.y - 10,
            }}
          >
            <div className="border-border/50 bg-background rounded-lg border px-2.5 py-1.5 text-xs shadow-xl">
              <div className="font-medium">
                {WEEKDAYS_FULL[parseDayIndex(hoveredCell.data.day)]},{" "}
                {HOURS_12[parseHourIndex(hoveredCell.data.hour)]}
              </div>
              <div className="text-muted-foreground">
                Value: {valueFormat(hoveredCell.data.value)}
              </div>
            </div>
          </div>
        )}
    </ChartContainer>
  )
}

"use client"

import * as React from "react"
import { contours } from "d3-contour"
import { geoPath } from "d3-geo"
import { interpolateRgb } from "d3-interpolate"
import { scaleLinear } from "d3-scale"

import { cn } from "@/lib/utils"

import { ChartAxis } from "../chart-axis"
import type { BaseChartProps } from "../chart-config"
import { ChartContainer } from "../chart-container"
import { ChartGrid } from "../chart-grid"

export interface ContourPoint {
  x: number
  y: number
  value?: number
}

export interface ContourChartProps extends BaseChartProps {
  /** 2D array of z values (grid data) */
  data: number[][]
  /** Optional scatter points to display on top */
  points?: ContourPoint[]
  xDomain?: [number, number]
  yDomain?: [number, number]
  /** Number of contour levels */
  levels?: number
  /** Color scale - supports 2-7 colors for gradient */
  colorScale?: string[]
  /** Show filled contour regions */
  showFill?: boolean
  /** Show contour lines */
  showLines?: boolean
  /** Contour line width */
  lineWidth?: number
  /** Line color (defaults to darker shade of fill) */
  lineColor?: string
  /** Show data point markers */
  showMarkers?: boolean
  /** Marker symbol: "x", "cross", "circle", "diamond" */
  markerSymbol?: "x" | "cross" | "circle" | "diamond"
  /** Marker size */
  markerSize?: number
  /** Marker color */
  markerColor?: string
  xAxisLabel?: string
  yAxisLabel?: string
  /** Smoothing factor for contours (higher = smoother) */
  bandwidth?: number
}

// Predefined color scales
export const CONTOUR_COLOR_SCALES = {
  // Rainbow (like the image)
  rainbow: ["#0000ff", "#00ffff", "#00ff00", "#ffff00", "#ff8000", "#ff0000"],
  // Viridis-like
  viridis: ["#440154", "#414487", "#2a788e", "#22a884", "#7ad151", "#fde725"],
  // Cool to warm
  coolwarm: [
    "#3b4cc0",
    "#7092c0",
    "#aac7fd",
    "#f7f7f7",
    "#f4a582",
    "#d6604d",
    "#b40426",
  ],
  // Ocean
  ocean: [
    "#023858",
    "#045a8d",
    "#0570b0",
    "#3690c0",
    "#74a9cf",
    "#a6bddb",
    "#d0d1e6",
  ],
  // Thermal
  thermal: ["#0d0887", "#6a00a8", "#b12a90", "#e16462", "#fca636", "#f0f921"],
  // Default blue
  blue: ["#eff6ff", "#3b82f6", "#1e3a8a"],
}

export function ContourChart({
  data,
  points,
  config,
  className,
  width = 600,
  height = 400,
  margin = { top: 20, right: 80, bottom: 50, left: 60 },
  showGrid = true,
  showTooltip = true,
  xDomain,
  yDomain,
  levels = 10,
  colorScale = CONTOUR_COLOR_SCALES.rainbow,
  showFill = true,
  showLines = true,
  lineWidth = 0.5,
  lineColor,
  showMarkers = true,
  markerSymbol = "x",
  markerSize = 8,
  markerColor = "#333333",
  xAxisLabel,
  yAxisLabel,
  bandwidth = 1,
}: ContourChartProps) {
  const [mousePos, setMousePos] = React.useState<{
    x: number
    y: number
    value: number
  } | null>(null)

  const gradientId = React.useId().replace(/:/g, "")
  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom

  const rows = data.length
  const cols = data[0]?.length ?? 0

  // Calculate value range
  const allValues = data.flat()
  const minValue = Math.min(...allValues)
  const maxValue = Math.max(...allValues)

  // Scales
  const actualXDomain = xDomain ?? [0, cols - 1]
  const actualYDomain = yDomain ?? [0, rows - 1]

  const xScale = scaleLinear().domain(actualXDomain).range([0, innerWidth])
  const yScale = scaleLinear().domain(actualYDomain).range([innerHeight, 0])
  const valueScale = scaleLinear().domain([minValue, maxValue]).range([0, 1])

  // Color interpolator for multiple colors
  const getColor = React.useCallback(
    (value: number) => {
      const t = valueScale(value)
      const n = colorScale.length - 1
      const segment = Math.min(Math.floor(t * n), n - 1)
      const localT = t * n - segment
      return interpolateRgb(
        colorScale[segment],
        colorScale[segment + 1]
      )(localT)
    },
    [colorScale, valueScale]
  )

  // Generate contours using d3-contour
  const contourGenerator = React.useMemo(() => {
    const thresholds = Array.from(
      { length: levels + 1 },
      (_, i) => minValue + ((maxValue - minValue) * i) / levels
    )
    return contours().size([cols, rows]).thresholds(thresholds)
  }, [cols, rows, levels, minValue, maxValue])

  // Flatten data for d3-contour (expects 1D array)
  const flatData = React.useMemo(() => {
    // d3-contour expects row-major order, bottom to top
    const result: number[] = []
    for (let j = rows - 1; j >= 0; j--) {
      for (let i = 0; i < cols; i++) {
        result.push(data[j][i])
      }
    }
    return result
  }, [data, rows, cols])

  // Generate contour paths
  const contourPaths = React.useMemo(() => {
    return contourGenerator(flatData)
  }, [contourGenerator, flatData])

  // Path generator that transforms from grid coords to screen coords
  const pathGenerator = React.useMemo(() => {
    return geoPath().projection({
      stream: (s) => ({
        point: (x: number, y: number) => {
          // Transform from grid coordinates to screen coordinates
          const screenX = (x / (cols - 1)) * innerWidth
          const screenY = innerHeight - (y / (rows - 1)) * innerHeight
          s.point(screenX, screenY)
        },
        lineStart: () => s.lineStart(),
        lineEnd: () => s.lineEnd(),
        polygonStart: () => s.polygonStart(),
        polygonEnd: () => s.polygonEnd(),
        sphere: () => {},
      }),
    })
  }, [cols, rows, innerWidth, innerHeight])

  // Generate marker path based on symbol
  const getMarkerPath = React.useCallback(
    (cx: number, cy: number) => {
      const s = markerSize / 2
      switch (markerSymbol) {
        case "x":
          return `M${cx - s},${cy - s}L${cx + s},${cy + s}M${cx + s},${cy - s}L${cx - s},${cy + s}`
        case "cross":
          return `M${cx},${cy - s}L${cx},${cy + s}M${cx - s},${cy}L${cx + s},${cy}`
        case "diamond":
          return `M${cx},${cy - s}L${cx + s},${cy}L${cx},${cy + s}L${cx - s},${cy}Z`
        case "circle":
        default:
          return ""
      }
    },
    [markerSize, markerSymbol]
  )

  // Handle mouse move
  const handleMouseMove = (e: React.MouseEvent<SVGSVGElement>) => {
    const rect = e.currentTarget.getBoundingClientRect()
    const x = e.clientX - rect.left - margin.left
    const y = e.clientY - rect.top - margin.top

    if (x < 0 || x > innerWidth || y < 0 || y > innerHeight) {
      setMousePos(null)
      return
    }

    const dataX = Math.round((x / innerWidth) * (cols - 1))
    const dataY = Math.round(((innerHeight - y) / innerHeight) * (rows - 1))

    if (dataX >= 0 && dataX < cols && dataY >= 0 && dataY < rows) {
      setMousePos({
        x: xScale.invert(x),
        y: yScale.invert(y),
        value: data[dataY]?.[dataX] ?? 0,
      })
    }
  }

  // Generate grid points for markers
  const gridPoints = React.useMemo(() => {
    if (!showMarkers && !points) return []

    if (points) {
      return points.map((p) => ({
        x: xScale(p.x),
        y: yScale(p.y),
        value: p.value,
      }))
    }

    // Generate markers at grid intersections
    const result: { x: number; y: number; value: number }[] = []
    for (let j = 0; j < rows; j++) {
      for (let i = 0; i < cols; i++) {
        const gridX =
          actualXDomain[0] +
          ((actualXDomain[1] - actualXDomain[0]) * i) / (cols - 1)
        const gridY =
          actualYDomain[0] +
          ((actualYDomain[1] - actualYDomain[0]) * j) / (rows - 1)
        result.push({
          x: xScale(gridX),
          y: yScale(gridY),
          value: data[j][i],
        })
      }
    }
    return result
  }, [
    showMarkers,
    points,
    data,
    rows,
    cols,
    xScale,
    yScale,
    actualXDomain,
    actualYDomain,
  ])

  return (
    <ChartContainer
      config={config}
      className={cn("!aspect-auto flex-col", className)}
    >
      <div className="w-full">
        <svg
          viewBox={`0 0 ${width} ${height}`}
          className="h-full w-full"
          onMouseMove={handleMouseMove}
          onMouseLeave={() => setMousePos(null)}
        >
          <g transform={`translate(${margin.left}, ${margin.top})`}>
            {/* Clip path for contours */}
            <defs>
              <clipPath id={`clip-${gradientId}`}>
                <rect width={innerWidth} height={innerHeight} />
              </clipPath>
            </defs>

            {/* Filled contours */}
            {showFill && (
              <g clipPath={`url(#clip-${gradientId})`}>
                {contourPaths.map((contour, i) => (
                  <path
                    key={`fill-${i}`}
                    d={pathGenerator(contour) || ""}
                    fill={getColor(contour.value)}
                    fillOpacity={0.9}
                    className="pointer-events-none"
                  />
                ))}
              </g>
            )}

            {/* Contour lines */}
            {showLines && (
              <g clipPath={`url(#clip-${gradientId})`}>
                {contourPaths.map((contour, i) => (
                  <path
                    key={`line-${i}`}
                    d={pathGenerator(contour) || ""}
                    fill="none"
                    stroke={lineColor || "rgba(0,0,0,0.3)"}
                    strokeWidth={lineWidth}
                    className="pointer-events-none"
                  />
                ))}
              </g>
            )}

            {/* Grid */}
            {showGrid && (
              <ChartGrid
                xScale={xScale}
                yScale={yScale}
                width={innerWidth}
                height={innerHeight}
              />
            )}

            {/* Data point markers */}
            {showMarkers &&
              gridPoints.map((point, i) =>
                markerSymbol === "circle" ? (
                  <circle
                    key={`marker-${i}`}
                    cx={point.x}
                    cy={point.y}
                    r={markerSize / 2}
                    fill="none"
                    stroke={markerColor}
                    strokeWidth={1.5}
                    className="pointer-events-none"
                  />
                ) : (
                  <path
                    key={`marker-${i}`}
                    d={getMarkerPath(point.x, point.y)}
                    fill="none"
                    stroke={markerColor}
                    strokeWidth={1.5}
                    className="pointer-events-none"
                  />
                )
              )}

            {/* X Axis */}
            <ChartAxis
              scale={xScale}
              orientation="bottom"
              transform={`translate(0, ${innerHeight})`}
              label={xAxisLabel}
            />

            {/* Y Axis */}
            <ChartAxis scale={yScale} orientation="left" label={yAxisLabel} />
          </g>

          {/* Color legend */}
          <g
            transform={`translate(${width - margin.right + 15}, ${margin.top})`}
          >
            <defs>
              <linearGradient
                id={`contour-gradient-${gradientId}`}
                x1="0"
                y1="1"
                x2="0"
                y2="0"
              >
                {colorScale.map((color, i) => (
                  <stop
                    key={i}
                    offset={`${(i / (colorScale.length - 1)) * 100}%`}
                    stopColor={color}
                  />
                ))}
              </linearGradient>
            </defs>
            <rect
              width={15}
              height={innerHeight}
              fill={`url(#contour-gradient-${gradientId})`}
              rx={2}
            />
            <text
              x={20}
              y={0}
              dominantBaseline="hanging"
              className="fill-muted-foreground text-[10px]"
            >
              {maxValue.toFixed(1)}
            </text>
            <text
              x={20}
              y={innerHeight}
              dominantBaseline="auto"
              className="fill-muted-foreground text-[10px]"
            >
              {minValue.toFixed(1)}
            </text>
          </g>
        </svg>
      </div>

      {/* Tooltip */}
      {showTooltip && mousePos && (
        <div
          className="pointer-events-none absolute z-50"
          style={{
            left: margin.left + xScale(mousePos.x),
            top: margin.top + yScale(mousePos.y),
          }}
        >
          <div className="border-border/50 bg-background -mt-2 -translate-x-1/2 -translate-y-full rounded-lg border px-2.5 py-1.5 text-xs shadow-xl">
            <div className="text-muted-foreground">
              x: {mousePos.x.toFixed(2)}, y: {mousePos.y.toFixed(2)}
            </div>
            <div className="font-medium">
              Value: {mousePos.value.toFixed(2)}
            </div>
          </div>
        </div>
      )}
    </ChartContainer>
  )
}

