  showGrid: boolean
}

function getVariantDefaults(variant: RadarChartVariant): VariantDefaults {
  switch (variant) {
    case "comparison":
      return {
        levels: 5,
        showDots: false,
        dotSize: 4,
        fillOpacity: 0.4,
        strokeWidth: 2.5,
        showLabels: true,
        labelOffset: 25,
        showLevelLabels: false,
        gridType: "polygon",
        showRadialLines: true,
        showLegend: false,
        showGrid: true,
      }
    case "legend":
      return {
        levels: 5,
        showDots: false,
        dotSize: 4,
        fillOpacity: 0.35,
        strokeWidth: 2,
        showLabels: true,
        labelOffset: 20,
        showLevelLabels: false,
        gridType: "polygon",
        showRadialLines: true,
        showLegend: true,
        showGrid: true,
      }
    case "filled":
      return {
        levels: 5,
        showDots: false,
        dotSize: 4,
        fillOpacity: 0.5,
        strokeWidth: 2,
        showLabels: true,
        labelOffset: 20,
        showLevelLabels: false,
        gridType: "polygon",
        showRadialLines: true,
        showLegend: false,
        showGrid: true,
      }
    case "circle":
      return {
        levels: 4,
        showDots: false,
        dotSize: 4,
        fillOpacity: 0.4,
        strokeWidth: 2,
        showLabels: true,
        labelOffset: 20,
        showLevelLabels: false,
        gridType: "circle",
        showRadialLines: false,
        showLegend: false,
        showGrid: true,
      }
    case "minimal":
      return {
        levels: 0,
        showDots: true,
        dotSize: 5,
        fillOpacity: 0.4,
        strokeWidth: 2,
        showLabels: true,
        labelOffset: 20,
        showLevelLabels: false,
        gridType: "polygon",
        showRadialLines: false,
        showLegend: false,
        showGrid: false,
      }
    case "labels":
      return {
        levels: 5,
        showDots: false,
        dotSize: 4,
        fillOpacity: 0.4,
        strokeWidth: 2,
        showLabels: true,
        labelOffset: 35,
        showLevelLabels: false,
        gridType: "polygon",
        showRadialLines: true,
        showLegend: false,
        showGrid: true,
      }
    default:
      return {
        levels: 5,
        showDots: true,
        dotSize: 4,
        fillOpacity: 0.25,
        strokeWidth: 2,
        showLabels: true,
        labelOffset: 20,
        showLevelLabels: true,
        gridType: "polygon",
        showRadialLines: true,
        showLegend: true,
        showGrid: true,
      }
  }
}

// ============================================================================
// Component
// ============================================================================

export function RadarChart({
  data,
  config,
  className,
  variant = "default",
  width = 500,
  height = 500,
  margin: marginProp,
  showTooltip = true,
  showLegend: showLegendProp,
  showGrid: showGridProp,
  maxValue: maxValueProp,
  levels: levelsProp,
  showDots: showDotsProp,
  dotSize: dotSizeProp,
  fillOpacity: fillOpacityProp,
  strokeWidth: strokeWidthProp,
  showLabels: showLabelsProp,
  labelOffset: labelOffsetProp,
  showLevelLabels: showLevelLabelsProp,
  gridType: gridTypeProp,
  showRadialLines: showRadialLinesProp,
}: RadarChartProps) {
  const defaults = getVariantDefaults(variant)

  // Apply variant defaults with prop overrides
  const levels = levelsProp ?? defaults.levels
  const showDots = showDotsProp ?? defaults.showDots
  const dotSize = dotSizeProp ?? defaults.dotSize
  const fillOpacity = fillOpacityProp ?? defaults.fillOpacity
  const strokeWidth = strokeWidthProp ?? defaults.strokeWidth
  const showLabels = showLabelsProp ?? defaults.showLabels
  const labelOffset = labelOffsetProp ?? defaults.labelOffset
  const showLevelLabels = showLevelLabelsProp ?? defaults.showLevelLabels
  const gridType = gridTypeProp ?? defaults.gridType
  const showRadialLines = showRadialLinesProp ?? defaults.showRadialLines
  const showLegend = showLegendProp ?? defaults.showLegend
  const showGrid = showGridProp ?? defaults.showGrid

  const margin = marginProp ?? { top: 50, right: 50, bottom: 50, left: 50 }

  const [hoveredSeries, setHoveredSeries] = React.useState<string | null>(null)
  const [hoveredPoint, setHoveredPoint] = React.useState<{
    series: string
    axis: string
    value: number
    x: number
    y: number
  } | null>(null)
  const [tooltipPosition, setTooltipPosition] = React.useState<{
    x: number
    y: number
  } | null>(null)

  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom
  const radius = Math.min(innerWidth, innerHeight) / 2
  const centerX = innerWidth / 2
  const centerY = innerHeight / 2

  // Get all axes from data
  const axes = React.useMemo(() => {
    const axisSet = new Set<string>()
    data.forEach((series) => {
      series.data.forEach((d) => axisSet.add(d.axis))
    })
    return Array.from(axisSet)
  }, [data])

  const angleSlice = (2 * Math.PI) / axes.length

  // Calculate max value
  const maxValue =
    maxValueProp ??
    Math.max(...data.flatMap((s) => s.data.map((d) => d.value))) * 1.1

  // Radial scale
  const rScale = scaleLinear().domain([0, maxValue]).range([0, radius])

  // Get coordinates for a data point
  const getPoint = (axis: string, value: number) => {
    const index = axes.indexOf(axis)
    const angle = angleSlice * index - Math.PI / 2
    const r = rScale(value)
    return {
      x: centerX + r * Math.cos(angle),
      y: centerY + r * Math.sin(angle),
    }
  }

  // Generate radar area path
  const radarLine = lineRadial<RadarChartDataPoint>()
    .angle((d) => axes.indexOf(d.axis) * angleSlice)
    .radius((d) => rScale(d.value))
    .curve(curveLinearClosed)

  // Generate polygon path for grid
  const generatePolygonPath = (levelRadius: number): string => {
    const points: string[] = []
    for (let i = 0; i < axes.length; i++) {
      const angle = angleSlice * i - Math.PI / 2
      const x = centerX + levelRadius * Math.cos(angle)
      const y = centerY + levelRadius * Math.sin(angle)
      points.push(`${x},${y}`)
    }
    return `M ${points.join(" L ")} Z`
  }

  // Get color for series
  const getSeriesColor = (series: RadarChartSeries, index: number): string => {
    return (
      series.color ??
      config?.[series.name]?.color ??
      `var(--chart-${(index % 5) + 1})`
    )
  }

  // Legend items
  const legendItems: LegendItem[] = data.map((series, i) => ({
    name: series.name,
    color: getSeriesColor(series, i),
  }))

  // Get sorted data for a series
  const getSortedData = (series: RadarChartSeries) => {
    return axes.map((axis) => {
      const point = series.data.find((d) => d.axis === axis)
      return { axis, value: point?.value ?? 0 }
    })
  }

  // Handle area hover
  const handleAreaEnter = (series: RadarChartSeries) => {
    setHoveredSeries(series.name)
  }

  const handleAreaLeave = () => {
    setHoveredSeries(null)
    setTooltipPosition(null)
  }

  // Handle area mouse move for tooltip positioning
  const handleAreaMove = (
    e: React.MouseEvent<SVGPathElement>,
    series: RadarChartSeries,
    seriesIndex: number
  ) => {
    const svgRect = e.currentTarget.ownerSVGElement?.getBoundingClientRect()
    if (svgRect) {
      const x = e.clientX - svgRect.left
      const y = e.clientY - svgRect.top
      setTooltipPosition({ x, y })
      setHoveredSeries(series.name)
    }
  }

  return (
    <ChartContainer
      config={config}
      className={cn("relative !aspect-auto flex-col", className)}
    >
      <div className="relative mx-auto aspect-square w-full max-w-[320px]">
        <svg
          viewBox={`0 0 ${width} ${height}`}
          className="h-full w-full overflow-visible"
        >
          <g transform={`translate(${margin.left}, ${margin.top})`}>
            {/* Filled grid background for 'filled' variant */}
            {variant === "filled" && showGrid && (
              <path
                d={generatePolygonPath(radius)}
                fill="currentColor"
                className="text-primary/10"
              />
            )}

            {/* Grid levels */}
            {showGrid &&
              levels > 0 &&
              Array.from({ length: levels }, (_, i) => {
                const levelRadius = (radius / levels) * (i + 1)

                if (gridType === "circle") {
                  return (
                    <circle
                      key={i}
                      cx={centerX}
                      cy={centerY}
                      r={levelRadius}
                      fill="none"
                      stroke="currentColor"
                      strokeWidth={i === levels - 1 ? 1 : 0.5}
                      strokeOpacity={i === levels - 1 ? 0.5 : 0.3}
                      className="text-border"
                    />
                  )
                }

                return (
                  <path
                    key={i}
                    d={generatePolygonPath(levelRadius)}
                    fill="none"
                    stroke="currentColor"
                    strokeWidth={0.5}
                    strokeOpacity={0.3}
                    className="text-border"
                  />
                )
              })}

            {/* Radial lines (axis lines from center) */}
            {showRadialLines &&
              axes.map((axis, i) => {
                const angle = angleSlice * i - Math.PI / 2
                const x2 = centerX + radius * Math.cos(angle)
                const y2 = centerY + radius * Math.sin(angle)
                return (
                  <line
                    key={axis}
                    x1={centerX}
                    y1={centerY}
                    x2={x2}
                    y2={y2}
                    stroke="currentColor"
                    strokeWidth={0.5}
                    strokeOpacity={0.3}
                    className="text-border"
                  />
                )
              })}

            {/* Axis labels */}
            {showLabels &&
              axes.map((axis, i) => {
                const angle = angleSlice * i - Math.PI / 2
                const x = centerX + (radius + labelOffset) * Math.cos(angle)
                const y = centerY + (radius + labelOffset) * Math.sin(angle)

                // For 'labels' variant, show values alongside axis names
                if (variant === "labels") {
                  const values = data.map((series) => {
                    const point = series.data.find((d) => d.axis === axis)
                    return point?.value ?? 0
                  })

                  return (
                    <g key={axis}>
                      <text
                        x={x}
                        y={y - (i === 0 ? 8 : 0)}
                        textAnchor="middle"
                        dominantBaseline="middle"
                        className="fill-foreground text-[13px] font-medium"
                      >
                        {values.length > 1 ? (
                          <>
                            <tspan>{values[0]}</tspan>
                            <tspan className="fill-muted-foreground">/</tspan>
                            <tspan>{values[1]}</tspan>
                          </>
                        ) : (
                          values[0]
                        )}
                      </text>
                      <text
                        x={x}
                        y={y + (i === 0 ? 8 : 14)}
                        textAnchor="middle"
                        dominantBaseline="middle"
                        className="fill-muted-foreground text-[11px]"
                      >
                        {axis}
                      </text>
                    </g>
                  )
                }

                return (
                  <text
                    key={axis}
                    x={x}
                    y={y}
                    textAnchor="middle"
                    dominantBaseline="middle"
                    className="fill-muted-foreground text-[11px]"
                  >
                    {axis}
                  </text>
                )
              })}

            {/* Level labels */}
            {showLevelLabels &&
              levels > 0 &&
              Array.from({ length: levels }, (_, i) => {
                const levelValue = (maxValue / levels) * (i + 1)
                const levelRadius = (radius / levels) * (i + 1)
                return (
                  <text
                    key={i}
                    x={centerX + 4}
                    y={centerY - levelRadius}
                    className="fill-muted-foreground text-[9px]"
                    dominantBaseline="middle"
                  >
                    {levelValue.toFixed(0)}
                  </text>
                )
              })}

            {/* Radar areas */}
            {data.map((series, seriesIndex) => {
              const color = getSeriesColor(series, seriesIndex)
              const isHovered =
                hoveredSeries === null || hoveredSeries === series.name
              const sortedData = getSortedData(series)
              const seriesFillOpacity = series.fillOpacity ?? fillOpacity

              return (
                <g key={series.name}>
                  {/* Invisible hit area for better mouse interaction */}
                  <path
                    d={radarLine(sortedData) ?? ""}
                    transform={`translate(${centerX}, ${centerY})`}
                    fill="transparent"
                    stroke="transparent"
                    strokeWidth={20}
                    className="cursor-pointer"
                    style={{ pointerEvents: "stroke" }}
                    onMouseEnter={() => handleAreaEnter(series)}
                    onMouseMove={(e) => handleAreaMove(e, series, seriesIndex)}
                    onMouseLeave={handleAreaLeave}
                  />

                  {/* Visible Area */}
                  <path
                    d={radarLine(sortedData) ?? ""}
                    transform={`translate(${centerX}, ${centerY})`}
                    fill={color}
                    fillOpacity={seriesFillOpacity}
                    stroke={color}
                    strokeWidth={strokeWidth}
                    className={cn(
                      "cursor-pointer transition-opacity duration-200",
                      !isHovered && "opacity-30"
                    )}
                    style={{ pointerEvents: "visiblePainted" }}
                    onMouseEnter={() => handleAreaEnter(series)}
                    onMouseMove={(e) => handleAreaMove(e, series, seriesIndex)}
                    onMouseLeave={handleAreaLeave}
                  />

                  {/* Dots */}
                  {showDots &&
                    sortedData.map((d) => {
                      const point = getPoint(d.axis, d.value)
                      const isPointHovered =
                        hoveredPoint?.series === series.name &&
                        hoveredPoint?.axis === d.axis

                      return (
                        <circle
                          key={d.axis}
                          cx={point.x}
                          cy={point.y}
                          r={isPointHovered ? dotSize * 1.5 : dotSize}
                          fill={color}
                          stroke="hsl(var(--background))"
                          strokeWidth={2}
                          className={cn(
                            "cursor-pointer transition-all duration-200",
                            !isHovered && "opacity-30"
                          )}
                          onMouseEnter={() =>
                            setHoveredPoint({
                              series: series.name,
                              axis: d.axis,
                              value: d.value,
                              x: point.x,
                              y: point.y,
                            })
                          }
                          onMouseLeave={() => setHoveredPoint(null)}
                        />
                      )
                    })}
                </g>
              )
            })}
          </g>
        </svg>

        {/* Tooltip for dot hover */}
        {showTooltip && hoveredPoint && (
          <div
            className="pointer-events-none absolute z-50"
            style={{
              left: margin.left + hoveredPoint.x,
              top: margin.top + hoveredPoint.y - 10,
            }}
          >
            <div className="border-border/50 bg-background -translate-x-1/2 -translate-y-full rounded-lg border px-3 py-2 text-xs shadow-xl">
              <div className="flex items-center gap-2">
                <div
                  className="h-2.5 w-2.5 rounded-full"
                  style={{
                    backgroundColor: getSeriesColor(
                      data.find((s) => s.name === hoveredPoint.series)!,
                      data.findIndex((s) => s.name === hoveredPoint.series)
                    ),
                  }}
                />
                <span className="font-medium">{hoveredPoint.series}</span>
              </div>
              <div className="text-muted-foreground mt-1">
                {hoveredPoint.axis}: {hoveredPoint.value.toLocaleString()}
              </div>
            </div>
          </div>
        )}

        {/* Tooltip for area hover (when no dot is hovered) */}
        {showTooltip &&
          !hoveredPoint &&
          hoveredSeries &&
          tooltipPosition &&
          data.length > 0 && (
            <div
              className="pointer-events-none absolute z-50"
              style={{
                left: tooltipPosition.x + 15,
                top: tooltipPosition.y - 10,
              }}
            >
              <div className="border-border/50 bg-background rounded-lg border px-3 py-2 text-xs shadow-xl">
                <div className="flex items-center gap-2 font-medium">
                  <div
                    className="h-2.5 w-2.5 rounded-full"
                    style={{
                      backgroundColor: getSeriesColor(
                        data.find((s) => s.name === hoveredSeries)!,
                        data.findIndex((s) => s.name === hoveredSeries)
                      ),
                    }}
                  />
                  {hoveredSeries}
                </div>
                <div className="text-muted-foreground mt-1.5 space-y-0.5">
                  {data
                    .find((s) => s.name === hoveredSeries)
                    ?.data.map((d) => (
                      <div key={d.axis} className="flex justify-between gap-3">
                        <span>{d.axis}:</span>
                        <span className="text-foreground font-medium">
                          {d.value.toLocaleString()}
                        </span>
                      </div>
                    ))}
                </div>
              </div>
            </div>
          )}
      </div>

      {/* Legend */}
      {showLegend && data.length > 1 && (
        <ChartLegend items={legendItems} onItemHover={setHoveredSeries} />
      )}
    </ChartContainer>
  )
}

"use client"

import * as React from "react"
import {
  hierarchy,
  treemap,
  treemapBinary,
  treemapDice,
  treemapSlice,
  treemapSquarify,
} from "d3-hierarchy"

import { cn } from "@/lib/utils"

import type { BaseChartProps, ChartConfig } from "../chart-config"
import { ChartContainer } from "../chart-container"

export interface TreemapNode {
  name: string
  value?: number
  children?: TreemapNode[]
  color?: string
}

export interface TreemapChartProps extends BaseChartProps {
  data: TreemapNode
  tile?: "squarify" | "binary" | "slice" | "dice"
  padding?: number
  paddingInner?: number
  paddingOuter?: number
  round?: boolean
  showLabels?: boolean
  labelMinSize?: number
}

const tileMap = {
  squarify: treemapSquarify,
  binary: treemapBinary,
  slice: treemapSlice,
  dice: treemapDice,
}

export function TreemapChart({
  data,
  config,
  className,
  width = 600,
  height = 400,
  margin = { top: 10, right: 10, bottom: 10, left: 10 },
  showTooltip = true,
  tile = "squarify",
  padding = 1,
  paddingInner = 2,
  paddingOuter = 2,
  round = true,
  showLabels = true,
  labelMinSize = 30,
}: TreemapChartProps) {
  const [hoveredNode, setHoveredNode] = React.useState<TreemapNode | null>(null)

  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom

  // Create hierarchy and compute treemap layout
  const root = React.useMemo(() => {
    const h = hierarchy(data)
      .sum((d) => d.value ?? 0)
      .sort((a, b) => (b.value ?? 0) - (a.value ?? 0))

    const treemapLayout = treemap<TreemapNode>()
      .size([innerWidth, innerHeight])
      .tile(tileMap[tile])
      .padding(padding)
      .paddingInner(paddingInner)
      .paddingOuter(paddingOuter)
      .round(round)

    return treemapLayout(h)
  }, [
    data,
    innerWidth,
    innerHeight,
    tile,
    padding,
    paddingInner,
    paddingOuter,
    round,
  ])

  // Get all leaves (nodes with values)
  const leaves = root.leaves()

  // Calculate total value for percentages
  const totalValue = root.value ?? 1

  // Generate colors based on depth and index
  const getColor = (node: (typeof leaves)[number], index: number): string => {
    const nodeData = node.data
    if (nodeData.color) return nodeData.color
    if (config?.[nodeData.name]?.color) return config[nodeData.name].color!

    // Use different shades based on parent
    const parentIndex = node.parent
      ? leaves.filter((l) => l.parent === node.parent).indexOf(node)
      : index
    return `var(--chart-${(parentIndex % 5) + 1})`
  }

  return (
    <ChartContainer
      config={config}
      className={cn("!aspect-auto flex-col", className)}
    >
      <div className="relative mx-auto w-full max-w-[500px]">
        <svg
          viewBox={`0 0 ${width} ${height}`}
          className="h-full w-full overflow-visible"
        >
          <g transform={`translate(${margin.left}, ${margin.top})`}>
            {leaves.map((node, index) => {
              const nodeData = node.data
              const x = node.x0
              const y = node.y0
              const w = node.x1 - node.x0
              const h = node.y1 - node.y0
              const color = getColor(node, index)
              const isHovered = hoveredNode === nodeData

              return (
                <g key={`${nodeData.name}-${index}`}>
                  <rect
                    x={x}
                    y={y}
                    width={w}
                    height={h}
                    fill={color}
                    rx={2}
                    ry={2}
                    className={cn(
                      "cursor-pointer transition-all duration-200",
                      hoveredNode !== null && !isHovered && "opacity-60",
                      isHovered && "brightness-110"
                    )}
                    onMouseEnter={() => setHoveredNode(nodeData)}
                    onMouseLeave={() => setHoveredNode(null)}
                  />

                  {/* Label */}
                  {showLabels && w >= labelMinSize && h >= labelMinSize && (
                    <text
                      x={x + w / 2}
                      y={y + h / 2}
                      textAnchor="middle"
                      dominantBaseline="middle"
                      className="pointer-events-none fill-white text-[11px] font-medium"
                      style={{ textShadow: "0 1px 2px rgba(0,0,0,0.3)" }}
                    >
                      {nodeData.name.length > w / 8
                        ? `${nodeData.name.slice(0, Math.floor(w / 8))}...`
                        : nodeData.name}
                    </text>
                  )}
                </g>
              )
            })}
          </g>
        </svg>

        {/* Tooltip */}
        {showTooltip && hoveredNode && (
          <div
            className="pointer-events-none fixed z-50"
            style={{
              left: "50%",
              top: "50%",
              transform: "translate(-50%, -50%)",
            }}
          >
            <div className="border-border/50 bg-background rounded-lg border px-3 py-2 text-sm shadow-xl">
              <div className="font-medium">{hoveredNode.name}</div>
              <div className="text-muted-foreground">
                Value: {(hoveredNode.value ?? 0).toLocaleString()}
              </div>
              <div className="text-muted-foreground">
                {(((hoveredNode.value ?? 0) / totalValue) * 100).toFixed(1)}% of
                total
              </div>
            </div>
          </div>
        )}
      </div>
    </ChartContainer>
  )
}

"use client"

import * as React from "react"
import { hierarchy, partition } from "d3-hierarchy"
import { scaleOrdinal } from "d3-scale"
import { arc } from "d3-shape"

import { cn } from "@/lib/utils"

import type { BaseChartProps, ChartConfig } from "../chart-config"
import { ChartContainer } from "../chart-container"

export interface SunburstNode {
  name: string
  value?: number
  children?: SunburstNode[]
  color?: string
}

export interface SunburstChartProps extends BaseChartProps {
  data: SunburstNode
  innerRadius?: number
  padAngle?: number
  cornerRadius?: number
  showLabels?: boolean
  labelMinAngle?: number
}

export function SunburstChart({
  data,
  config,
  className,
  width = 500,
  height = 500,
  margin = { top: 10, right: 10, bottom: 10, left: 10 },
  showTooltip = true,
  innerRadius = 50,
  padAngle = 0.01,
  cornerRadius = 3,
  showLabels = true,
  labelMinAngle = 0.1,
}: SunburstChartProps) {
  const [hoveredNode, setHoveredNode] = React.useState<SunburstNode | null>(
    null
  )
  const [breadcrumbs, setBreadcrumbs] = React.useState<SunburstNode[]>([])

  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom
  const radius = Math.min(innerWidth, innerHeight) / 2
  const centerX = innerWidth / 2
  const centerY = innerHeight / 2

  // Create hierarchy and partition layout
  const root = React.useMemo(() => {
    const h = hierarchy(data)
      .sum((d) => d.value ?? 0)
      .sort((a, b) => (b.value ?? 0) - (a.value ?? 0))

    const partitionLayout = partition<SunburstNode>().size([
      2 * Math.PI,
      radius,
    ])

    return partitionLayout(h)
  }, [data, radius])

  // Calculate depth for color scaling
  const maxDepth = root.height

  // Color scale based on depth
  const depthColors = [
    "var(--chart-1)",
    "var(--chart-2)",
    "var(--chart-3)",
    "var(--chart-4)",
    "var(--chart-5)",
  ]

  const getColor = (node: typeof root, index: number): string => {
    const nodeData = node.data
    if (nodeData.color) return nodeData.color
    if (config?.[nodeData.name]?.color) return config[nodeData.name].color!
    return depthColors[node.depth % depthColors.length]
  }

  // Arc generator
  const arcGenerator = arc<typeof root>()
    .startAngle((d) => d.x0)
    .endAngle((d) => d.x1)
    .padAngle(padAngle)
    .innerRadius((d) =>
      d.depth === 0 ? 0 : innerRadius + (d.y0 / radius) * (radius - innerRadius)
    )
    .outerRadius((d) =>
      d.depth === 0
        ? innerRadius
        : innerRadius + (d.y1 / radius) * (radius - innerRadius)
    )
    .cornerRadius(cornerRadius)

  // Label arc for positioning
  const labelArc = arc<typeof root>()
    .startAngle((d) => d.x0)
    .endAngle((d) => d.x1)
    .innerRadius(
      (d) => innerRadius + ((d.y0 + d.y1) / 2 / radius) * (radius - innerRadius)
    )
    .outerRadius(
      (d) => innerRadius + ((d.y0 + d.y1) / 2 / radius) * (radius - innerRadius)
    )

  // Get all descendants for rendering
  const descendants = root.descendants()

  // Handle hover
  const handleHover = (node: typeof root | null) => {
    if (!node) {
      setHoveredNode(null)
      setBreadcrumbs([])
      return
    }
    setHoveredNode(node.data)
    setBreadcrumbs(
      node
        .ancestors()
        .reverse()
        .map((n) => n.data)
    )
  }

  // Total value for percentage calculation
  const totalValue = root.value ?? 1

  return (
    <ChartContainer
      config={config}
      className={cn("!aspect-auto flex-col", className)}
    >
      <div className="relative mx-auto aspect-square w-full max-w-[320px]">
        <svg
          viewBox={`0 0 ${width} ${height}`}
          className="h-full w-full overflow-visible"
        >
          <g
            transform={`translate(${margin.left + centerX}, ${margin.top + centerY})`}
          >
            {descendants.map((node, index) => {
              const nodeData = node.data
              const color = getColor(node, index)
              const isHovered = hoveredNode === nodeData
              const isAncestor = breadcrumbs.includes(nodeData)
              const angle = node.x1 - node.x0

              return (
                <g key={`${nodeData.name}-${node.depth}-${index}`}>
                  <path
                    d={arcGenerator(node) ?? ""}
                    fill={color}
                    className={cn(
                      "cursor-pointer transition-all duration-200",
                      hoveredNode !== null &&
                        !isHovered &&
                        !isAncestor &&
                        "opacity-40",
                      isHovered && "brightness-110"
                    )}
                    onMouseEnter={() => handleHover(node)}
                    onMouseLeave={() => handleHover(null)}
                  />

                  {/* Label */}
                  {showLabels && angle >= labelMinAngle && node.depth > 0 && (
                    <text
                      transform={`translate(${labelArc.centroid(node)}) rotate(${
                        ((node.x0 + node.x1) / 2 - Math.PI / 2) *
                        (180 / Math.PI)
                      })`}
                      textAnchor="middle"
                      dominantBaseline="middle"
                      className="pointer-events-none fill-white text-[9px] font-medium"
                      style={{ textShadow: "0 1px 2px rgba(0,0,0,0.5)" }}
                    >
                      {nodeData.name.length > 10
                        ? `${nodeData.name.slice(0, 8)}...`
                        : nodeData.name}
                    </text>
                  )}
                </g>
              )
            })}

            {/* Center label */}
            <text
              textAnchor="middle"
              dominantBaseline="middle"
              className="fill-foreground text-sm font-medium"
            >
              {hoveredNode?.name ?? data.name}
            </text>
            {hoveredNode && (
              <text
                y={16}
                textAnchor="middle"
                dominantBaseline="middle"
                className="fill-muted-foreground text-xs"
              >
                {(hoveredNode.value ?? 0).toLocaleString()}
              </text>
            )}
          </g>
        </svg>

        {/* Breadcrumb trail */}
        {breadcrumbs.length > 1 && (
          <div className="absolute top-2 left-2 flex items-center gap-1 text-xs">
            {breadcrumbs.map((node, i) => (
              <React.Fragment key={i}>
                {i > 0 && <span className="text-muted-foreground">/</span>}
                <span
                  className={
                    i === breadcrumbs.length - 1
                      ? "font-medium"
                      : "text-muted-foreground"
                  }
                >
                  {node.name}
                </span>
              </React.Fragment>
            ))}
          </div>
        )}

        {/* Tooltip */}
        {showTooltip && hoveredNode && breadcrumbs.length > 1 && (
          <div className="border-border/50 bg-background absolute bottom-2 left-2 rounded-lg border px-2.5 py-1.5 text-xs shadow-xl">
            <div className="font-medium">{hoveredNode.name}</div>
            <div className="text-muted-foreground">
              Value: {(hoveredNode.value ?? 0).toLocaleString()}
            </div>
            <div className="text-muted-foreground">
              {(((hoveredNode.value ?? 0) / totalValue) * 100).toFixed(1)}% of
              total
            </div>
          </div>
        )}
      </div>
    </ChartContainer>
  )
}

"use client"

import * as React from "react"
import {
  sankey,
  sankeyCenter,
  sankeyJustify,
  sankeyLeft,
  sankeyLinkHorizontal,
  sankeyRight,
} from "d3-sankey"

import { cn } from "@/lib/utils"

import type { BaseChartProps, ChartConfig } from "../chart-config"
import { ChartContainer } from "../chart-container"

export interface SankeyNode {
  id: string
  name?: string
  color?: string
}

export interface SankeyLink {
  source: string
  target: string
  value: number
  color?: string
}

export interface SankeyChartProps extends BaseChartProps {
  nodes: SankeyNode[]
  links: SankeyLink[]
  nodeWidth?: number
  nodePadding?: number
  nodeAlign?: "left" | "right" | "center" | "justify"
  linkOpacity?: number
  showLabels?: boolean
  showValues?: boolean
}

const alignMap = {
  left: sankeyLeft,
  right: sankeyRight,
  center: sankeyCenter,
  justify: sankeyJustify,
}

interface SankeyComputedNode {
  id: string
  name?: string
  color?: string
  x0: number
  x1: number
  y0: number
  y1: number
  value: number
  sourceLinks: SankeyComputedLink[]
  targetLinks: SankeyComputedLink[]
}

interface SankeyComputedLink {
  source: SankeyComputedNode
  target: SankeyComputedNode
  value: number
  width: number
  y0: number
  y1: number
  color?: string
}

export function SankeyChart({
  nodes,
  links,
  config,
  className,
  width = 800,
  height = 500,
  margin = { top: 20, right: 150, bottom: 20, left: 150 },
  showTooltip = true,
  nodeWidth = 15,
  nodePadding = 20,
  nodeAlign = "justify",
  linkOpacity = 0.5,
  showLabels = true,
  showValues = true,
}: SankeyChartProps) {
  const [hoveredElement, setHoveredElement] = React.useState<{
    type: "node" | "link"
    data: SankeyComputedNode | SankeyComputedLink
  } | null>(null)
  const hoverTimeoutRef = React.useRef<NodeJS.Timeout | null>(null)

  // Clear hover with a small delay to prevent flickering
  const clearHover = React.useCallback(() => {
    if (hoverTimeoutRef.current) {
      clearTimeout(hoverTimeoutRef.current)
    }
    hoverTimeoutRef.current = setTimeout(() => {
      setHoveredElement(null)
    }, 50)
  }, [])

  const setHover = React.useCallback(
    (type: "node" | "link", data: SankeyComputedNode | SankeyComputedLink) => {
      if (hoverTimeoutRef.current) {
        clearTimeout(hoverTimeoutRef.current)
        hoverTimeoutRef.current = null
      }
      setHoveredElement({ type, data })
    },
    []
  )

  React.useEffect(() => {
    return () => {
      if (hoverTimeoutRef.current) {
        clearTimeout(hoverTimeoutRef.current)
      }
    }
  }, [])

  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom

  // Create sankey layout
  const { computedNodes, computedLinks } = React.useMemo(() => {
    // Validate inputs
    if (!nodes.length || !links.length) {
      return { computedNodes: [], computedLinks: [] }
    }

    // Create graph - use string IDs for links when using nodeId()
    const sankeyData = {
      nodes: nodes.map((n) => ({ ...n })),
      links: links.map((l) => ({
        source: l.source,
        target: l.target,
        value: l.value,
        color: l.color,
      })),
    }

    // Create sankey generator
    const sankeyGenerator = sankey<
      (typeof sankeyData.nodes)[0],
      (typeof sankeyData.links)[0]
    >()
      .nodeId((d) => d.id)
      .nodeWidth(nodeWidth)
      .nodePadding(nodePadding)
      .nodeAlign(alignMap[nodeAlign])
      .extent([
        [0, 0],
        [innerWidth, innerHeight],
      ])

    try {
      const result = sankeyGenerator(sankeyData as any)
      return {
        computedNodes: result.nodes as unknown as SankeyComputedNode[],
        computedLinks: result.links as unknown as SankeyComputedLink[],
      }
    } catch (error) {
      console.error("Sankey layout error:", error)
      return { computedNodes: [], computedLinks: [] }
    }
  }, [nodes, links, innerWidth, innerHeight, nodeWidth, nodePadding, nodeAlign])

  // Get color for node
  const getNodeColor = (node: SankeyComputedNode, index: number): string => {
    if (node.color) return node.color
    const configColor =
      config?.[node.id]?.color ?? config?.[node.name ?? ""]?.color
    if (configColor) return configColor
    return `var(--chart-${(index % 5) + 1})`
  }

  // Link path generator
  const linkPath = sankeyLinkHorizontal()

  // Check if node or its links are highlighted
  const isNodeHighlighted = (node: SankeyComputedNode): boolean => {
    if (!hoveredElement) return true
    if (hoveredElement.type === "node") {
      const hoveredNode = hoveredElement.data as SankeyComputedNode
      if (hoveredNode === node) return true
      return (
        hoveredNode.sourceLinks.some((l) => l.target === node) ||
        hoveredNode.targetLinks.some((l) => l.source === node)
      )
    }
    if (hoveredElement.type === "link") {
      const hoveredLink = hoveredElement.data as SankeyComputedLink
      return hoveredLink.source === node || hoveredLink.target === node
    }
    return false
  }

  const isLinkHighlighted = (link: SankeyComputedLink): boolean => {
    if (!hoveredElement) return true
    if (hoveredElement.type === "link") {
      return hoveredElement.data === link
    }
    if (hoveredElement.type === "node") {
      const hoveredNode = hoveredElement.data as SankeyComputedNode
      return link.source === hoveredNode || link.target === hoveredNode
    }
    return false
  }

  return (
    <ChartContainer
      config={config}
      className={cn("!aspect-auto flex-col", className)}
    >
      <div
        className="relative mx-auto w-full"
        style={{ aspectRatio: `${width} / ${height}` }}
      >
        <svg
          viewBox={`0 0 ${width} ${height}`}
          className="h-full w-full overflow-visible"
        >
          <g transform={`translate(${margin.left}, ${margin.top})`}>
            {/* Links */}
            {computedLinks.map((link, index) => {
              const color =
                link.color ??
                getNodeColor(link.source, computedNodes.indexOf(link.source))
              const highlighted = isLinkHighlighted(link)
              const isHovered =
                hoveredElement?.type === "link" && hoveredElement.data === link

              return (
                <path
                  key={index}
                  d={linkPath(link as any) ?? ""}
                  fill="none"
                  stroke={color}
                  strokeWidth={Math.max(1, link.width)}
                  opacity={highlighted ? 1 : 0.15}
                  strokeOpacity={isHovered ? linkOpacity + 0.2 : linkOpacity}
                  className="cursor-pointer"
                  style={{ transition: "opacity 150ms ease-out" }}
                  onMouseEnter={() => setHover("link", link)}
                  onMouseLeave={clearHover}
                />
              )
            })}

            {/* Nodes */}
            {computedNodes.map((node, index) => {
              const color = getNodeColor(node, index)
              const highlighted = isNodeHighlighted(node)

              // Determine node type and label position:
              // - Source nodes (no incoming): label on LEFT
              // - Sink nodes (no outgoing): label on RIGHT
              // - Middle nodes: label on LEFT (same as source to prevent horizontal overlap)
              const isSink = node.sourceLinks.length === 0

              // Calculate label position - all non-sink nodes get labels on LEFT
              let labelX: number
              let labelY: number
              let textAnchor: "start" | "middle" | "end"

              if (isSink) {
                // Right side label for sink nodes
                labelX = node.x1 + 8
                labelY = (node.y0 + node.y1) / 2
                textAnchor = "start"
              } else {
                // Left side label for source and middle nodes
                labelX = node.x0 - 8
                labelY = (node.y0 + node.y1) / 2
                textAnchor = "end"
              }

              const labelText = showValues
                ? `${node.name ?? node.id} (${node.value.toLocaleString()})`
                : (node.name ?? node.id)

              return (
                <g key={node.id}>
                  <rect
                    x={node.x0}
                    y={node.y0}
                    width={node.x1 - node.x0}
                    height={Math.max(1, node.y1 - node.y0)}
                    fill={color}
                    rx={2}
                    opacity={highlighted ? 1 : 0.3}
                    className="cursor-pointer"
                    style={{ transition: "opacity 150ms ease-out" }}
                    onMouseEnter={() => setHover("node", node)}
                    onMouseLeave={clearHover}
                  />

                  {/* Node label */}
                  {showLabels && (
                    <text
                      x={labelX}
                      y={labelY}
                      textAnchor={textAnchor}
                      dominantBaseline="middle"
                      opacity={highlighted ? 1 : 0.4}
                      className="fill-foreground pointer-events-none text-[10px] font-medium"
                      style={{ transition: "opacity 150ms ease-out" }}
                    >
                      {labelText}
                    </text>
                  )}
                </g>
              )
            })}
          </g>
        </svg>

        {/* Tooltip */}
        {showTooltip && hoveredElement && (
          <div className="border-border/50 bg-background absolute bottom-4 left-4 rounded-lg border px-3 py-2 text-sm shadow-xl">
            {hoveredElement.type === "node" && (
              <>
                <div className="font-medium">
                  {(hoveredElement.data as SankeyComputedNode).name ??
                    (hoveredElement.data as SankeyComputedNode).id}
                </div>
                <div className="text-muted-foreground">
                  Value:{" "}
                  {(
                    hoveredElement.data as SankeyComputedNode
                  ).value.toLocaleString()}
                </div>
                <div className="text-muted-foreground mt-1 text-xs">
                  Incoming:{" "}
                  {
                    (hoveredElement.data as SankeyComputedNode).targetLinks
                      .length
                  }{" "}
                  | Outgoing:{" "}
                  {
                    (hoveredElement.data as SankeyComputedNode).sourceLinks
                      .length
                  }
                </div>
              </>
            )}
            {hoveredElement.type === "link" && (
              <>
                <div className="font-medium">
                  {(hoveredElement.data as SankeyComputedLink).source.name ??
                    (hoveredElement.data as SankeyComputedLink).source.id}{" "}
                  →{" "}
                  {(hoveredElement.data as SankeyComputedLink).target.name ??
                    (hoveredElement.data as SankeyComputedLink).target.id}
                </div>
                <div className="text-muted-foreground">
                  Value:{" "}
                  {(
                    hoveredElement.data as SankeyComputedLink
                  ).value.toLocaleString()}
                </div>
              </>
            )}
          </div>
        )}
      </div>
    </ChartContainer>
  )
}

"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

import type { BaseChartProps } from "../chart-config"
import { ChartContainer } from "../chart-container"

export interface GaugeChartProps extends BaseChartProps {
  /** Current value to display */
  value: number
  /** Minimum value */
  min?: number
  /** Maximum value */
  max?: number
  /** Label text below value */
  label?: string
  /** Units to display after value */
  units?: string
  /** Show the numeric value */
  showValue?: boolean
  /** Gauge variant style */
  variant?:
    | "modern"
    | "speedometer"
    | "segmented"
    | "radial"
    | "minimal"
    | "gradient"
    | "meter"
    | "dashboard"
  /** Arc thickness (as percentage of radius, 0-1) */
  thickness?: number
  /** Primary color or color for filled arc */
  color?: string
  /** Secondary color for gradient */
  colorSecondary?: string
  /** Background arc color */
  bgColor?: string
  /** Segments for segmented variant */
  segments?: Array<{ value: number; color: string; label?: string }>
  /** Show tick marks */
  showTicks?: boolean
  /** Number of tick marks */
  tickCount?: number
  /** Animate on mount */
  animate?: boolean
  /** Animation duration in ms */
  animationDuration?: number
  /** Value formatter */
  valueFormatter?: (value: number) => string
  /** Show percentage instead of value */
  showPercentage?: boolean
}

// Default colors
const COLORS = {
  primary: "#3b82f6",
  success: "#22c55e",
  warning: "#f59e0b",
  danger: "#ef4444",
  muted: "#e5e7eb",
  purple: "#8b5cf6",
  pink: "#ec4899",
}

export function GaugeChart({
  value,
  config,
  className,
  width = 280,
  height = 200,
  margin = { top: 20, right: 20, bottom: 20, left: 20 },
  min = 0,
  max = 100,
  label,
  units,
  showValue = true,
  variant = "modern",
  thickness = 0.15,
  color = COLORS.primary,
  colorSecondary = COLORS.purple,
  bgColor = COLORS.muted,
  segments,
  showTicks = false,
  tickCount = 5,
  animate = true,
  animationDuration = 1000,
  valueFormatter,
  showPercentage = false,
}: GaugeChartProps) {
  const [animatedPercentage, setAnimatedPercentage] = React.useState(0)
  const gradientId = React.useId().replace(/:/g, "")

  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom

  // Calculate dimensions based on variant
  const isRadial = variant === "radial"
  const centerX = innerWidth / 2
  const centerY = isRadial ? innerHeight / 2 : innerHeight * 0.75
  const radius =
    Math.min(innerWidth / 2, isRadial ? innerHeight / 2 : innerHeight * 0.7) *
    0.85
  const strokeWidth = radius * thickness

  // Clamp value and calculate percentage
  const clampedValue = Math.max(min, Math.min(max, value))
  const targetPercentage = (clampedValue - min) / (max - min)

  // Animate percentage
  React.useEffect(() => {
    if (!animate) {
      setAnimatedPercentage(targetPercentage)
      return
    }

    const startTime = Date.now()
    const startPercentage = animatedPercentage

    const animateFrame = () => {
      const elapsed = Date.now() - startTime
      const progress = Math.min(elapsed / animationDuration, 1)
      // Ease out cubic
      const eased = 1 - Math.pow(1 - progress, 3)
      const newPercentage =
        startPercentage + (targetPercentage - startPercentage) * eased
      setAnimatedPercentage(newPercentage)
      if (progress < 1) requestAnimationFrame(animateFrame)
    }
    requestAnimationFrame(animateFrame)
  }, [targetPercentage, animate, animationDuration])

  // Arc calculations for semi-circle (270 degrees for gauge, 360 for radial)
  const arcAngle = isRadial ? 360 : 270
  const circumference = 2 * Math.PI * radius
  const arcLength = (arcAngle / 360) * circumference
  const dashOffset = arcLength * (1 - animatedPercentage)

  // Format value
  const formatValue = (v: number): string => {
    if (valueFormatter) return valueFormatter(v)
    if (showPercentage) return `${Math.round((v / max) * 100)}%`
    if (v >= 1000000) return `${(v / 1000000).toFixed(1)}M`
    if (v >= 1000) return `${(v / 1000).toFixed(1)}K`
    return Math.round(v).toString()
  }

  // Get segment color at current value
  const getSegmentColor = (): string => {
    if (!segments || segments.length === 0) return color
    const currentValue = min + (max - min) * animatedPercentage
    for (let i = segments.length - 1; i >= 0; i--) {
      if (currentValue >= segments[i].value) {
        return segments[i].color
      }
    }
    return segments[0]?.color || color
  }

  // Generate tick positions for semi-circle
  const generateTicks = () => {
    if (!showTicks) return []
    const ticks = []
    const startAngle = -225 // Start from bottom-left
    const totalAngle = 270 // Semi-circle arc

    for (let i = 0; i < tickCount; i++) {
      const angle = startAngle + (totalAngle / (tickCount - 1)) * i
      const rad = (angle * Math.PI) / 180
      const tickValue = min + ((max - min) / (tickCount - 1)) * i

      // Outer tick position
      const outerX = centerX + (radius + 10) * Math.cos(rad)
      const outerY = centerY + (radius + 10) * Math.sin(rad)

      // Inner tick position
      const innerX = centerX + (radius - strokeWidth / 2 - 5) * Math.cos(rad)
      const innerY = centerY + (radius - strokeWidth / 2 - 5) * Math.sin(rad)

      // Label position
      const labelX = centerX + (radius + 25) * Math.cos(rad)
      const labelY = centerY + (radius + 25) * Math.sin(rad)

      ticks.push({
        angle,
        innerX,
        innerY,
        outerX,
        outerY,
        labelX,
        labelY,
        value: tickValue,
      })
    }
    return ticks
  }

  const ticks = generateTicks()

  // Semi-circle arc path (for background)
  const semiCirclePath = `
    M ${centerX - radius} ${centerY}
    A ${radius} ${radius} 0 1 1 ${centerX + radius} ${centerY}
  `

  // Radial uses circle
  const renderRadial = () => (
    <>
      {/* Background circle */}
      <circle
        cx={centerX}
        cy={centerY}
        r={radius}
        fill="none"
        stroke={bgColor}
        strokeWidth={strokeWidth}
      />
      {/* Value arc */}
      <circle
        cx={centerX}
        cy={centerY}
        r={radius}
        fill="none"
        stroke={segments ? getSegmentColor() : color}
        strokeWidth={strokeWidth}
        strokeLinecap="round"
        strokeDasharray={circumference}
        strokeDashoffset={circumference * (1 - animatedPercentage)}
        transform={`rotate(-90 ${centerX} ${centerY})`}
        style={{ transition: animate ? "none" : "stroke-dashoffset 0.3s ease" }}
      />
      {/* Center content */}
      {showValue && (
        <g transform={`translate(${centerX}, ${centerY})`}>
          <text
            textAnchor="middle"
            dominantBaseline="middle"
            className="fill-foreground font-bold"
            style={{ fontSize: radius * 0.4 }}
          >
            {formatValue(min + (max - min) * animatedPercentage)}
          </text>
          {(units || label) && (
            <text
              y={radius * 0.3}
              textAnchor="middle"
              className="fill-muted-foreground"
              style={{ fontSize: radius * 0.14 }}
            >
              {units || label}
            </text>
          )}
        </g>
      )}
    </>
  )

  // Modern clean arc
  const renderModern = () => (
    <>
      {/* Background arc */}
      <path
        d={semiCirclePath}
        fill="none"
        stroke={bgColor}
        strokeWidth={strokeWidth}
        strokeLinecap="round"
      />
      {/* Value arc */}
      <path
        d={semiCirclePath}
        fill="none"
        stroke={segments ? getSegmentColor() : color}
        strokeWidth={strokeWidth}
        strokeLinecap="round"
        strokeDasharray={arcLength}
        strokeDashoffset={dashOffset}
        style={{ transition: animate ? "none" : "stroke-dashoffset 0.3s ease" }}
      />
      {/* Center value */}
      {showValue && (
        <g transform={`translate(${centerX}, ${centerY - radius * 0.15})`}>
          <text
            textAnchor="middle"
            dominantBaseline="middle"
            className="fill-foreground font-bold"
            style={{ fontSize: radius * 0.45 }}
          >
            {formatValue(min + (max - min) * animatedPercentage)}
          </text>
          {units && (
            <text
              y={radius * 0.25}
              textAnchor="middle"
              className="fill-muted-foreground"
              style={{ fontSize: radius * 0.14 }}
            >
              {units}
            </text>
          )}
          {label && (
            <text
              y={radius * 0.45}
              textAnchor="middle"
              className="fill-muted-foreground"
              style={{ fontSize: radius * 0.12 }}
            >
              {label}
            </text>
          )}
        </g>
      )}
    </>
  )

  // Gradient arc
  const renderGradient = () => (
    <>
      <defs>
        <linearGradient
          id={`gauge-gradient-${gradientId}`}
          x1="0%"
          y1="0%"
          x2="100%"
          y2="0%"
        >
          <stop offset="0%" stopColor={color} />
          <stop offset="100%" stopColor={colorSecondary} />
        </linearGradient>
      </defs>
      {/* Background arc */}
      <path
        d={semiCirclePath}
        fill="none"
        stroke={bgColor}
        strokeWidth={strokeWidth}
        strokeLinecap="round"
      />
      {/* Gradient value arc */}
      <path
        d={semiCirclePath}
        fill="none"
        stroke={`url(#gauge-gradient-${gradientId})`}
        strokeWidth={strokeWidth}
        strokeLinecap="round"
        strokeDasharray={arcLength}
        strokeDashoffset={dashOffset}
      />
      {/* Center value */}
      {showValue && (
        <g transform={`translate(${centerX}, ${centerY - radius * 0.15})`}>
          <text
            textAnchor="middle"
            dominantBaseline="middle"
            className="fill-foreground font-bold"
            style={{ fontSize: radius * 0.45 }}
          >
            {formatValue(min + (max - min) * animatedPercentage)}
          </text>
          {label && (
            <text
              y={radius * 0.35}
              textAnchor="middle"
              className="fill-muted-foreground"
              style={{ fontSize: radius * 0.12 }}
            >
              {label}
            </text>
          )}
        </g>
      )}
    </>
  )

  // Speedometer with needle
  const renderSpeedometer = () => {
    const needleAngle = -225 + 270 * animatedPercentage
    const needleRad = (needleAngle * Math.PI) / 180
    const needleLength = radius * 0.7
    const needleX = centerX + needleLength * Math.cos(needleRad)
    const needleY = centerY + needleLength * Math.sin(needleRad)

    return (
      <>
        {/* Background arc */}
        <path
          d={semiCirclePath}
          fill="none"
          stroke={bgColor}
          strokeWidth={strokeWidth}
          strokeLinecap="round"
        />
        {/* Value arc */}
        <path
          d={semiCirclePath}
          fill="none"
          stroke={segments ? getSegmentColor() : color}
          strokeWidth={strokeWidth}
          strokeLinecap="round"
          strokeDasharray={arcLength}
          strokeDashoffset={dashOffset}
        />
        {/* Tick marks */}
        {ticks.map((tick, i) => (
          <g key={i}>
            <line
              x1={tick.innerX}
              y1={tick.innerY}
              x2={tick.innerX + (tick.outerX - tick.innerX) * 0.5}
              y2={tick.innerY + (tick.outerY - tick.innerY) * 0.5}
              stroke="currentColor"
              strokeWidth={2}
              className="text-muted-foreground"
            />
            <text
              x={tick.labelX}
              y={tick.labelY}
              textAnchor="middle"
              dominantBaseline="middle"
              className="fill-muted-foreground"
              style={{ fontSize: 9 }}
            >
              {formatValue(tick.value)}
            </text>
          </g>
        ))}
        {/* Needle */}
        <line
          x1={centerX}
          y1={centerY}
          x2={needleX}
          y2={needleY}
          stroke={segments ? getSegmentColor() : color}
          strokeWidth={3}
          strokeLinecap="round"
        />
        {/* Needle center */}
        <circle
          cx={centerX}
          cy={centerY}
          r={12}
          fill={segments ? getSegmentColor() : color}
        />
        <circle cx={centerX} cy={centerY} r={6} fill="white" />
        {/* Value below */}
        {showValue && (
          <text
            x={centerX}
            y={centerY + radius * 0.35}
            textAnchor="middle"
            className="fill-foreground font-bold"
            style={{ fontSize: radius * 0.28 }}
          >
            {formatValue(min + (max - min) * animatedPercentage)}
            {units && (
              <tspan
                className="fill-muted-foreground font-normal"
                style={{ fontSize: radius * 0.12 }}
              >
                {" "}
                {units}
              </tspan>
            )}
          </text>
        )}
      </>
    )
  }

  // Segmented colored zones
  const renderSegmented = () => {
    const segs = segments || [
      { value: 0, color: COLORS.success },
      { value: 33, color: COLORS.warning },
      { value: 66, color: COLORS.danger },
    ]

    // Gap angle in degrees between segments
    const gapAngle = 3

    // Generate individual arc paths for each segment
    const generateSegmentArc = (startPercent: number, endPercent: number) => {
      const startAngle = -225 + 270 * startPercent
      const endAngle = -225 + 270 * endPercent
      const startRad = (startAngle * Math.PI) / 180
      const endRad = (endAngle * Math.PI) / 180

      const x1 = centerX + radius * Math.cos(startRad)
      const y1 = centerY + radius * Math.sin(startRad)
      const x2 = centerX + radius * Math.cos(endRad)
      const y2 = centerY + radius * Math.sin(endRad)

      const largeArcFlag = endAngle - startAngle > 180 ? 1 : 0

      return `M ${x1} ${y1} A ${radius} ${radius} 0 ${largeArcFlag} 1 ${x2} ${y2}`
    }

    return (
      <>
        {/* Segmented arcs - using individual arc paths for clean edges */}
        {segs.map((seg, i) => {
          const nextValue = segs[i + 1]?.value ?? max
          const segStart = (seg.value - min) / (max - min)
          const segEnd = (nextValue - min) / (max - min)

          // Add small gaps between segments
          const gapOffset = gapAngle / 270 // Convert gap angle to percentage
          const adjustedStart = i === 0 ? segStart : segStart + gapOffset / 2
          const adjustedEnd =
            i === segs.length - 1 ? segEnd : segEnd - gapOffset / 2

          const isActive = animatedPercentage >= segStart

          return (
            <path
              key={i}
              d={generateSegmentArc(adjustedStart, adjustedEnd)}
              fill="none"
              stroke={seg.color}
              strokeWidth={strokeWidth}
              strokeLinecap="round"
              opacity={isActive ? 1 : 0.25}
              style={{ transition: "opacity 0.3s ease" }}
            />
          )
        })}
        {/* Indicator needle */}
        {(() => {
          const needleAngle = -225 + 270 * animatedPercentage
          const needleRad = (needleAngle * Math.PI) / 180
          const needleOuterX =
            centerX + (radius + strokeWidth / 2 + 6) * Math.cos(needleRad)
          const needleOuterY =
            centerY + (radius + strokeWidth / 2 + 6) * Math.sin(needleRad)
          const needleInnerX =
            centerX + (radius - strokeWidth / 2 - 6) * Math.cos(needleRad)
          const needleInnerY =
            centerY + (radius - strokeWidth / 2 - 6) * Math.sin(needleRad)

          return (
            <g>
              {/* Needle line */}
              <line
                x1={needleInnerX}
                y1={needleInnerY}
                x2={needleOuterX}
                y2={needleOuterY}
                stroke={getSegmentColor()}
                strokeWidth={3}
                strokeLinecap="round"
              />
              {/* Needle dot on arc */}
              <circle
                cx={centerX + radius * Math.cos(needleRad)}
                cy={centerY + radius * Math.sin(needleRad)}
                r={strokeWidth / 2 + 2}
                fill={getSegmentColor()}
              />
            </g>
          )
        })()}
        {/* Center value */}
        {showValue && (
          <g transform={`translate(${centerX}, ${centerY - radius * 0.15})`}>
            <text
              textAnchor="middle"
              dominantBaseline="middle"
              className="font-bold"
              style={{ fontSize: radius * 0.4, fill: getSegmentColor() }}
            >
              {formatValue(min + (max - min) * animatedPercentage)}
            </text>
            {label && (
              <text
                y={radius * 0.3}
                textAnchor="middle"
                className="fill-muted-foreground"
                style={{ fontSize: radius * 0.12 }}
              >
                {label}
              </text>
            )}
          </g>
        )}
      </>
    )
  }

  // Minimal thin arc
  const renderMinimal = () => (
    <>
      {/* Background arc */}
      <path
        d={semiCirclePath}
        fill="none"
        stroke={bgColor}
        strokeWidth={strokeWidth * 0.5}
        strokeLinecap="round"
      />
      {/* Value arc */}
      <path
        d={semiCirclePath}
        fill="none"
        stroke={segments ? getSegmentColor() : color}
        strokeWidth={strokeWidth}
        strokeLinecap="round"
        strokeDasharray={arcLength}
        strokeDashoffset={dashOffset}
      />
      {/* Min label */}
      <text
        x={centerX - radius - 10}
        y={centerY + 15}
        textAnchor="middle"
        className="fill-muted-foreground"
        style={{ fontSize: 10 }}
      >
        {formatValue(min)}
      </text>
      {/* Max label */}
      <text
        x={centerX + radius + 10}
        y={centerY + 15}
        textAnchor="middle"
        className="fill-muted-foreground"
        style={{ fontSize: 10 }}
      >
        {formatValue(max)}
      </text>
      {/* Center value */}
      {showValue && (
        <g transform={`translate(${centerX}, ${centerY - radius * 0.2})`}>
          <text
            textAnchor="middle"
            dominantBaseline="middle"
            className="fill-foreground font-bold"
            style={{ fontSize: radius * 0.5 }}
          >
            {formatValue(min + (max - min) * animatedPercentage)}
          </text>
          {label && (
            <text
              y={radius * 0.3}
              textAnchor="middle"
              className="fill-muted-foreground"
              style={{ fontSize: radius * 0.12 }}
            >
              {label}
            </text>
          )}
        </g>
      )}
    </>
  )

  // Meter style with ticks outside
  const renderMeter = () => (
    <>
      {/* Outer tick marks */}
      {ticks.map((tick, i) => (
        <g key={i}>
          <line
            x1={tick.outerX}
            y1={tick.outerY}
            x2={tick.outerX + (tick.labelX - tick.outerX) * 0.4}
            y2={tick.outerY + (tick.labelY - tick.outerY) * 0.4}
            stroke="currentColor"
            strokeWidth={i === 0 || i === tickCount - 1 ? 2.5 : 1.5}
            className="text-muted-foreground"
          />
          <text
            x={tick.labelX}
            y={tick.labelY}
            textAnchor="middle"
            dominantBaseline="middle"
            className="fill-muted-foreground font-medium"
            style={{ fontSize: 10 }}
          >
            {formatValue(tick.value)}
          </text>
        </g>
      ))}
      {/* Background arc */}
      <path
        d={semiCirclePath}
        fill="none"
        stroke={bgColor}
        strokeWidth={strokeWidth}
        strokeLinecap="round"
      />
      {/* Value arc */}
      <path
        d={semiCirclePath}
        fill="none"
        stroke={segments ? getSegmentColor() : color}
        strokeWidth={strokeWidth}
        strokeLinecap="round"
        strokeDasharray={arcLength}
        strokeDashoffset={dashOffset}
      />
      {/* Center value */}
      {showValue && (
        <g transform={`translate(${centerX}, ${centerY - radius * 0.1})`}>
          <text
            textAnchor="middle"
            dominantBaseline="middle"
            className="fill-foreground font-bold"
            style={{ fontSize: radius * 0.35 }}
          >
            {formatValue(min + (max - min) * animatedPercentage)}
          </text>
          {label && (
            <text
              y={radius * 0.25}
              textAnchor="middle"
              className="fill-muted-foreground"
              style={{ fontSize: radius * 0.11 }}
            >
              {label}
            </text>
          )}
        </g>
      )}
    </>
  )

  // Dashboard card style
  const renderDashboard = () => {
    const percentage = Math.round(animatedPercentage * 100)
    return (
      <>
        {/* Background arc */}
        <path
          d={semiCirclePath}
          fill="none"
          stroke={bgColor}
          strokeWidth={strokeWidth * 1.5}
          strokeLinecap="round"
        />
        {/* Value arc with rounded gradient look */}
        <path
          d={semiCirclePath}
          fill="none"
          stroke={segments ? getSegmentColor() : color}
          strokeWidth={strokeWidth * 1.5}
          strokeLinecap="round"
          strokeDasharray={arcLength}
          strokeDashoffset={dashOffset}
        />
        {/* Large percentage in center */}
        {showValue && (
          <g transform={`translate(${centerX}, ${centerY - radius * 0.2})`}>
            <text
              textAnchor="middle"
              dominantBaseline="middle"
              className="fill-foreground font-bold"
              style={{ fontSize: radius * 0.6 }}
            >
              {percentage}
              <tspan style={{ fontSize: radius * 0.25 }}>%</tspan>
            </text>
            {label && (
              <text
                y={radius * 0.35}
                textAnchor="middle"
                className="fill-muted-foreground font-medium"
                style={{ fontSize: radius * 0.13 }}
              >
                {label}
              </text>
            )}
          </g>
        )}
      </>
    )
  }

  const renderContent = () => {
    switch (variant) {
      case "speedometer":
        return renderSpeedometer()
      case "segmented":
        return renderSegmented()
      case "radial":
        return renderRadial()
      case "minimal":
        return renderMinimal()
      case "gradient":
        return renderGradient()
      case "meter":
        return renderMeter()
      case "dashboard":
        return renderDashboard()
      default:
        return renderModern()
    }
  }

  return (
    <ChartContainer
      config={config}
      className={cn("!aspect-auto flex-col", className)}
    >
      <div className="relative mx-auto aspect-square w-full max-w-[280px]">
        <svg
          viewBox={`0 0 ${width} ${height}`}
          className="h-full w-full overflow-visible"
        >
          <g transform={`translate(${margin.left}, ${margin.top})`}>
            {renderContent()}
          </g>
        </svg>
      </div>
    </ChartContainer>
  )
}

"use client"

import * as React from "react"
import { scaleLinear } from "d3-scale"

import { cn } from "@/lib/utils"

export interface BulletChartData {
  label: string
  value: number
  target: number
  ranges: [number, number, number] // [poor, satisfactory, good]
  max?: number
}

export interface BulletChartProps {
  data: BulletChartData[]
  className?: string
  orientation?: "horizontal" | "vertical"
  showLabels?: boolean
  showValues?: boolean
  valueFormatter?: (value: number) => string
  barColor?: string
  targetColor?: string
  rangeColors?: [string, string, string]
}

export function BulletChart({
  data,
  className,
  orientation = "horizontal",
  showLabels = true,
  showValues = true,
  valueFormatter = (value) => value.toLocaleString(),
  barColor = "#1e40af",
  targetColor = "#1e293b",
  rangeColors = ["#dbeafe", "#93c5fd", "#3b82f6"],
}: BulletChartProps) {
  const containerRef = React.useRef<HTMLDivElement>(null)
  const [hoveredIndex, setHoveredIndex] = React.useState<number | null>(null)

  const isHorizontal = orientation === "horizontal"
  const barHeight = 24
  const barSpacing = 60
  const labelWidth = 100
  const valueWidth = 60

  const width = 500
  const height = isHorizontal ? data.length * barSpacing + 40 : 400

  const margin = isHorizontal
    ? { top: 20, right: valueWidth + 20, bottom: 20, left: labelWidth }
    : { top: 20, right: 20, bottom: 60, left: 40 }

  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom

  return (
    <div ref={containerRef} className={cn("w-full", className)}>
      <svg
        viewBox={`0 0 ${width} ${height}`}
        className="h-auto w-full overflow-visible"
      >
        <g transform={`translate(${margin.left}, ${margin.top})`}>
          {data.map((d, index) => {
            const max = d.max ?? Math.max(d.ranges[2], d.target, d.value) * 1.1
            const scale = scaleLinear().domain([0, max]).range([0, innerWidth])

            const y = index * barSpacing
            const isHovered = hoveredIndex === index

            return (
              <g
                key={d.label}
                transform={`translate(0, ${y})`}
                className={cn(
                  "cursor-pointer transition-opacity duration-200",
                  hoveredIndex !== null && !isHovered && "opacity-50"
                )}
                onMouseEnter={() => setHoveredIndex(index)}
                onMouseLeave={() => setHoveredIndex(null)}
              >
                {/* Range backgrounds */}
                <rect
                  x={0}
                  y={0}
                  width={scale(d.ranges[2])}
                  height={barHeight}
                  fill={rangeColors[0]}
                  rx={2}
                />
                <rect
                  x={0}
                  y={barHeight * 0.15}
                  width={scale(d.ranges[1])}
                  height={barHeight * 0.7}
                  fill={rangeColors[1]}
                  rx={2}
                />
                <rect
                  x={0}
                  y={barHeight * 0.3}
                  width={scale(d.ranges[0])}
                  height={barHeight * 0.4}
                  fill={rangeColors[2]}
                  rx={2}
                />

                {/* Value bar */}
                <rect
                  x={0}
                  y={barHeight * 0.35}
                  width={scale(d.value)}
                  height={barHeight * 0.3}
                  fill={barColor}
                  rx={2}
                />

                {/* Target marker */}
                <line
                  x1={scale(d.target)}
                  x2={scale(d.target)}
                  y1={barHeight * 0.1}
                  y2={barHeight * 0.9}
                  stroke={targetColor}
                  strokeWidth={3}
                />

                {/* Label */}
                {showLabels && (
                  <text
                    x={-10}
                    y={barHeight / 2}
                    textAnchor="end"
                    dominantBaseline="middle"
                    className="fill-foreground text-sm font-medium"
                  >
                    {d.label}
                  </text>
                )}

                {/* Value */}
                {showValues && (
                  <text
                    x={innerWidth + 10}
                    y={barHeight / 2}
                    textAnchor="start"
                    dominantBaseline="middle"
                    className="fill-muted-foreground text-sm"
                  >
                    {valueFormatter(d.value)}
                  </text>
                )}
              </g>
            )
          })}
        </g>
      </svg>

      {/* Tooltip */}
      {hoveredIndex !== null && (
        <div className="mt-2 text-center text-sm">
          <span className="text-muted-foreground">
            {data[hoveredIndex].label}:{" "}
            {valueFormatter(data[hoveredIndex].value)} / Target:{" "}
            {valueFormatter(data[hoveredIndex].target)}
          </span>
        </div>
      )}
    </div>
  )
}

"use client"

import * as React from "react"
import { hierarchy, partition } from "d3-hierarchy"

import { cn } from "@/lib/utils"

export interface IcicleNode {
  name: string
  value?: number
  children?: IcicleNode[]
  color?: string
}

export interface IcicleChartProps {
  data: IcicleNode
  className?: string
  orientation?: "horizontal" | "vertical"
  showLabels?: boolean
  labelMinSize?: number
  padding?: number
  colorScheme?: string[]
}

export function IcicleChart({
  data,
  className,
  orientation = "vertical",
  showLabels = true,
  labelMinSize = 40,
  padding = 1,
  colorScheme = [
    "#1e40af",
    "#2563eb",
    "#3b82f6",
    "#60a5fa",
    "#93c5fd",
    "#bfdbfe",
  ],
}: IcicleChartProps) {
  const [hoveredNode, setHoveredNode] = React.useState<IcicleNode | null>(null)

  const isVertical = orientation === "vertical"
  const width = 500
  const height = 400

  // Create hierarchy and partition layout
  const root = React.useMemo(() => {
    const h = hierarchy(data)
      .sum((d) => d.value ?? 0)
      .sort((a, b) => (b.value ?? 0) - (a.value ?? 0))

    const partitionLayout = partition<IcicleNode>()
      .size(isVertical ? [width, height] : [height, width])
      .padding(padding)

    return partitionLayout(h)
  }, [data, width, height, padding, isVertical])

  // Get all nodes except root
  const nodes = root.descendants().filter((d) => d.depth > 0)

  // Calculate total value for percentages
  const totalValue = root.value ?? 1

  // Get color based on depth and index
  const getColor = (node: (typeof nodes)[number]): string => {
    if (node.data.color) return node.data.color
    const depthIndex = node.depth - 1
    return colorScheme[depthIndex % colorScheme.length]
  }

  return (
    <div className={cn("w-full", className)}>
      <svg
        viewBox={`0 0 ${width} ${height}`}
        className="h-auto w-full overflow-visible"
      >
        {nodes.map((node, index) => {
          const isHovered = hoveredNode === node.data

          // For vertical: x0,x1 are horizontal, y0,y1 are depth
          // For horizontal: swap them
          const x = isVertical ? node.x0 : node.y0
          const y = isVertical ? node.y0 : node.x0
          const w = isVertical ? node.x1 - node.x0 : node.y1 - node.y0
          const h = isVertical ? node.y1 - node.y0 : node.x1 - node.x0

          const color = getColor(node)
          const showLabel = showLabels && w >= labelMinSize && h >= 20

          return (
            <g key={`${node.data.name}-${index}`}>
              <rect
                x={x}
                y={y}
                width={w}
                height={h}
                fill={color}
                stroke="#fff"
                strokeWidth={1}
                rx={2}
                className={cn(
                  "cursor-pointer transition-all duration-200",
                  hoveredNode !== null && !isHovered && "opacity-60",
                  isHovered && "brightness-110"
                )}
                onMouseEnter={() => setHoveredNode(node.data)}
                onMouseLeave={() => setHoveredNode(null)}
              />

              {showLabel && (
                <text
                  x={x + w / 2}
                  y={y + h / 2}
                  textAnchor="middle"
                  dominantBaseline="middle"
                  className="pointer-events-none fill-white text-[11px] font-medium"
                  style={{ textShadow: "0 1px 2px rgba(0,0,0,0.3)" }}
                >
                  {node.data.name.length > w / 8
                    ? `${node.data.name.slice(0, Math.floor(w / 8))}...`
                    : node.data.name}
                </text>
              )}
            </g>
          )
        })}
      </svg>

      {/* Tooltip */}
      {hoveredNode && (
        <div className="mt-3 text-center">
          <div className="border-border/50 bg-background mx-auto inline-block rounded-lg border px-3 py-2 text-sm shadow-lg">
            <div className="font-medium">{hoveredNode.name}</div>
            <div className="text-muted-foreground">
              Value: {(hoveredNode.value ?? 0).toLocaleString()}
            </div>
            <div className="text-muted-foreground">
              {(((hoveredNode.value ?? 0) / totalValue) * 100).toFixed(1)}% of
              total
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

"use client"

import * as React from "react"
import { bin, extent, max } from "d3-array"
import { scaleLinear } from "d3-scale"

import { cn } from "@/lib/utils"

export interface DotPlotDataPoint {
  value: number
  color?: string
}

export interface DotPlotChartProps {
  data: DotPlotDataPoint[] | number[]
  className?: string
  dotSize?: number
  dotSpacing?: number
  showGrid?: boolean
  showXAxis?: boolean
  xAxisLabel?: string
  binCount?: number
  color?: string
  valueFormatter?: (value: number) => string
}

export function DotPlotChart({
  data,
  className,
  dotSize = 8,
  dotSpacing = 2,
  showGrid = true,
  showXAxis = true,
  xAxisLabel,
  binCount = 20,
  color = "#2563eb",
  valueFormatter = (value) => value.toLocaleString(),
}: DotPlotChartProps) {
  const [hoveredBin, setHoveredBin] = React.useState<number | null>(null)

  // Normalize data to array of values
  const values = React.useMemo(() => {
    return data.map((d) => (typeof d === "number" ? d : d.value))
  }, [data])

  // Get colors if provided
  const colors = React.useMemo(() => {
    return data.map((d) => (typeof d === "number" ? color : (d.color ?? color)))
  }, [data, color])

  const width = 500
  const margin = { top: 20, right: 20, bottom: xAxisLabel ? 60 : 40, left: 20 }

  const innerWidth = width - margin.left - margin.right

  // Create bins
  const binnedData = React.useMemo(() => {
    const [minVal, maxVal] = extent(values) as [number, number]
    const binGenerator = bin().domain([minVal, maxVal]).thresholds(binCount)

    const bins = binGenerator(values)

    // For each bin, track individual dots with their colors
    return bins.map((b) => {
      const dots: { value: number; color: string }[] = []
      b.forEach((val) => {
        // Find the actual index considering duplicates
        let foundCount = 0
        for (let i = 0; i < values.length; i++) {
          if (values[i] === val) {
            if (foundCount === dots.filter((d) => d.value === val).length) {
              dots.push({ value: val, color: colors[i] })
              break
            }
            foundCount++
          }
        }
      })
      return {
        x0: b.x0 ?? minVal,
        x1: b.x1 ?? maxVal,
        count: b.length,
        dots,
      }
    })
  }, [values, colors, binCount])

  // Calculate max stack height
  const maxCount = max(binnedData, (d) => d.count) ?? 0

  // Dynamic height based on max stack
  const dotTotalSize = dotSize + dotSpacing
  const innerHeight = Math.max(maxCount * dotTotalSize + 20, 100)
  const height = innerHeight + margin.top + margin.bottom

  // Scales
  const xScale = React.useMemo(() => {
    const [minVal, maxVal] = extent(values) as [number, number]
    const padding = (maxVal - minVal) * 0.05
    return scaleLinear()
      .domain([minVal - padding, maxVal + padding])
      .range([0, innerWidth])
      .nice()
  }, [values, innerWidth])

  const xTicks = xScale.ticks(7)

  // Calculate tooltip position as percentage
  const getTooltipPosition = (binIndex: number) => {
    const bin = binnedData[binIndex]
    const binCenter = (bin.x0 + bin.x1) / 2
    const xPos = margin.left + xScale(binCenter)
    const yPos = margin.top + innerHeight - bin.count * dotTotalSize - 8
    return {
      left: `${(xPos / width) * 100}%`,
      top: `${(yPos / height) * 100}%`,
    }
  }

  return (
    <div className={cn("relative w-full", className)}>
      <svg
        viewBox={`0 0 ${width} ${height}`}
        className="h-auto w-full overflow-visible"
      >
        <g transform={`translate(${margin.left}, ${margin.top})`}>
          {/* Grid lines */}
          {showGrid &&
            xTicks.map((tick) => (
              <line
                key={tick}
                x1={xScale(tick)}
                x2={xScale(tick)}
                y1={0}
                y2={innerHeight}
                stroke="hsl(var(--border))"
                strokeDasharray="3 3"
                strokeOpacity={0.3}
              />
            ))}

          {/* Baseline */}
          <line
            x1={0}
            x2={innerWidth}
            y1={innerHeight}
            y2={innerHeight}
            stroke="hsl(var(--border))"
          />

          {/* Dots stacked from bottom */}
          {binnedData.map((binData, binIndex) => {
            const binCenter = (binData.x0 + binData.x1) / 2
            const cx = xScale(binCenter)
            const isHovered = hoveredBin === binIndex

            return (
              <g key={binIndex}>
                {binData.dots.map((dot, dotIndex) => {
                  const cy = innerHeight - (dotIndex + 0.5) * dotTotalSize

                  return (
                    <circle
                      key={dotIndex}
                      cx={cx}
                      cy={cy}
                      r={dotSize / 2}
                      fill={dot.color}
                      className={cn(
                        "cursor-pointer transition-opacity duration-200",
                        hoveredBin !== null && !isHovered && "opacity-40"
                      )}
                      onMouseEnter={() => setHoveredBin(binIndex)}
                      onMouseLeave={() => setHoveredBin(null)}
                    />
                  )
                })}
              </g>
            )
          })}

          {/* X-axis labels */}
          {showXAxis &&
            xTicks.map((tick) => (
              <text
                key={`tick-${tick}`}
                x={xScale(tick)}
                y={innerHeight + 20}
                textAnchor="middle"
                className="fill-muted-foreground text-xs"
              >
                {valueFormatter(tick)}
              </text>
            ))}

          {/* X-axis label */}
          {xAxisLabel && (
            <text
              x={innerWidth / 2}
              y={innerHeight + 45}
              textAnchor="middle"
              className="fill-foreground text-sm font-medium"
            >
              {xAxisLabel}
            </text>
          )}
        </g>
      </svg>

      {/* HTML Tooltip */}
      {hoveredBin !== null && binnedData[hoveredBin] && (
        <div
          className="pointer-events-none absolute z-50 -translate-x-1/2 -translate-y-full"
          style={getTooltipPosition(hoveredBin)}
        >
          <div className="bg-foreground text-background rounded-md px-2 py-1 text-xs font-medium shadow-lg">
            {Math.round(binnedData[hoveredBin].x0)}-
            {Math.round(binnedData[hoveredBin].x1)}:{" "}
            {binnedData[hoveredBin].count}
          </div>
        </div>
      )}
    </div>
  )
}

"use client"

import * as React from "react"
import { scaleBand, scaleLinear } from "d3-scale"

import { cn } from "@/lib/utils"

export interface LollipopDataPoint {
  category: string
  value: number
  color?: string
  group?: string
}

export interface LollipopChartProps {
  data: LollipopDataPoint[]
  className?: string
  orientation?: "horizontal" | "vertical"
  dotSize?: number
  showGrid?: boolean
  showLegend?: boolean
  valueFormatter?: (value: number) => string
  color?: string
  stemColor?: string
  yAxisLabel?: string
}

export function LollipopChart({
  data,
  className,
  orientation = "vertical",
  dotSize = 10,
  showGrid = true,
  showLegend = true,
  valueFormatter = (value) => value.toFixed(1),
  color = "#2563eb",
  stemColor = "#d1d5db",
  yAxisLabel,
}: LollipopChartProps) {
  const [hoveredIndex, setHoveredIndex] = React.useState<number | null>(null)

  const isHorizontal = orientation === "horizontal"

  // Calculate dimensions - ensure enough space for each item
  const minItemSpace = dotSize * 3 // Minimum space per item (3x dot diameter)
  const calculatedWidth = Math.max(600, data.length * minItemSpace + 100)

  const width = isHorizontal ? 500 : calculatedWidth
  const height = isHorizontal ? Math.max(400, data.length * 30) : 320

  const margin = isHorizontal
    ? { top: 20, right: 30, bottom: 30, left: 130 }
    : { top: 20, right: 30, bottom: 40, left: 45 }

  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom

  // Get unique groups for legend
  const groups = React.useMemo(() => {
    const groupMap = new Map<string, string>()
    data.forEach((d) => {
      if (d.group && d.color && !groupMap.has(d.group)) {
        groupMap.set(d.group, d.color)
      }
    })
    return Array.from(groupMap.entries())
  }, [data])

  const categoryScale = React.useMemo(() => {
    return scaleBand()
      .domain(data.map((d) => d.category))
      .range(isHorizontal ? [0, innerHeight] : [0, innerWidth])
      .padding(0.4)
  }, [data, innerWidth, innerHeight, isHorizontal])

  const valueScale = React.useMemo(() => {
    const values = data.map((d) => d.value)
    const minVal = Math.min(...values, 0)
    const maxVal = Math.max(...values, 0)
    const range = maxVal - minVal || 1
    const padding = range * 0.2

    return scaleLinear()
      .domain([minVal - padding, maxVal + padding])
      .range(isHorizontal ? [0, innerWidth] : [innerHeight, 0])
      .nice()
  }, [data, innerWidth, innerHeight, isHorizontal])

  const ticks = valueScale.ticks(5)
  const zeroPos = valueScale(0)

  return (
    <div className={cn("relative w-full", className)}>
      {/* Legend */}
      {showLegend && groups.length > 0 && (
        <div className="mb-4 flex items-center justify-center gap-6">
          <span className="text-muted-foreground text-sm">cyl</span>
          {groups.map(([group, groupColor]) => (
            <div key={group} className="flex items-center gap-2">
              <div
                className="h-3.5 w-3.5 rounded-full"
                style={{ backgroundColor: groupColor }}
              />
              <span className="text-foreground text-sm">
                {group.replace(" cyl", "")}
              </span>
            </div>
          ))}
        </div>
      )}

      <div className="overflow-x-auto">
        <svg width={width} height={height} className="overflow-visible">
          <g transform={`translate(${margin.left}, ${margin.top})`}>
            {/* Grid lines */}
            {showGrid &&
              ticks.map((tick) => (
                <line
                  key={tick}
                  x1={isHorizontal ? valueScale(tick) : 0}
                  x2={isHorizontal ? valueScale(tick) : innerWidth}
                  y1={isHorizontal ? 0 : valueScale(tick)}
                  y2={isHorizontal ? innerHeight : valueScale(tick)}
                  stroke="#e5e7eb"
                  strokeWidth={1}
                />
              ))}

            {/* Lollipops */}
            {data.map((d, index) => {
              const isHovered = hoveredIndex === index
              const dotColor = d.color ?? color
              const categoryPos =
                (categoryScale(d.category) ?? 0) + categoryScale.bandwidth() / 2

              const x1 = isHorizontal ? zeroPos : categoryPos
              const y1 = isHorizontal ? categoryPos : zeroPos
              const x2 = isHorizontal ? valueScale(d.value) : categoryPos
              const y2 = isHorizontal ? categoryPos : valueScale(d.value)

              return (
                <g
                  key={`${d.category}-${index}`}
                  className="cursor-pointer"
                  onMouseEnter={() => setHoveredIndex(index)}
                  onMouseLeave={() => setHoveredIndex(null)}
                  style={{
                    opacity: hoveredIndex !== null && !isHovered ? 0.5 : 1,
                    transition: "opacity 150ms",
                  }}
                >
                  {/* Stem */}
                  <line
                    x1={x1}
                    y1={y1}
                    x2={x2}
                    y2={y2}
                    stroke={stemColor}
                    strokeWidth={2}
                  />

                  {/* Dot */}
                  <circle
                    cx={x2}
                    cy={y2}
                    r={isHovered ? dotSize + 2 : dotSize}
                    fill={dotColor}
                    style={{ transition: "r 150ms" }}
                  />
                </g>
              )
            })}

            {/* Category labels */}
            {data.map((d, index) => {
              const pos =
                (categoryScale(d.category) ?? 0) + categoryScale.bandwidth() / 2

              if (isHorizontal) {
                return (
                  <text
                    key={`label-${index}`}
                    x={-10}
                    y={pos}
                    textAnchor="end"
                    dominantBaseline="middle"
                    fontSize={11}
                    className="fill-foreground"
                  >
                    {d.category}
                  </text>
                )
              }

              return (
                <text
                  key={`label-${index}`}
                  x={pos}
                  y={innerHeight + 18}
                  textAnchor="middle"
                  fontSize={10}
                  className="fill-foreground"
                >
                  {d.category}
                </text>
              )
            })}

            {/* Value axis labels */}
            {ticks.map((tick) => (
              <text
                key={`tick-${tick}`}
                x={isHorizontal ? valueScale(tick) : -10}
                y={isHorizontal ? innerHeight + 16 : valueScale(tick)}
                textAnchor={isHorizontal ? "middle" : "end"}
                dominantBaseline={isHorizontal ? "auto" : "middle"}
                fontSize={12}
                className="fill-muted-foreground"
              >
                {tick}
              </text>
            ))}

            {/* Y-axis label */}
            {yAxisLabel && !isHorizontal && (
              <text
                x={0}
                y={0}
                textAnchor="middle"
                fontSize={12}
                className="fill-muted-foreground"
                transform={`translate(${-margin.left + 14}, ${innerHeight / 2}) rotate(-90)`}
              >
                {yAxisLabel}
              </text>
            )}
          </g>
        </svg>
      </div>

      {/* Tooltip */}
      {hoveredIndex !== null && (
        <div
          className="bg-foreground text-background pointer-events-none fixed z-[100] rounded-md px-2.5 py-1.5 text-xs font-medium shadow-lg"
          style={{
            left: "50%",
            top: "50%",
            transform: "translate(-50%, -50%)",
          }}
        >
          <span className="font-semibold">{data[hoveredIndex].category}</span>
          <span className="ml-1.5">
            {valueFormatter(data[hoveredIndex].value)}
          </span>
        </div>
      )}
    </div>
  )
}

