import * as React from "react"
import { scaleBand, scaleLinear } from "d3-scale"

import { cn } from "@/lib/utils"

export interface DumbbellDataPoint {
  category: string
  start: number
  end: number
}

export interface DumbbellChartProps {
  data: DumbbellDataPoint[]
  className?: string
  dotSize?: number
  showGrid?: boolean
  valueFormatter?: (value: number) => string
  startColor?: string
  endColor?: string
  connectorColor?: string
  startLabel?: string
  endLabel?: string
}

export function DumbbellChart({
  data,
  className,
  dotSize = 8,
  showGrid = true,
  valueFormatter = (value) => value.toLocaleString(),
  startColor = "#94a3b8",
  endColor = "#3b82f6",
  connectorColor = "#cbd5e1",
  startLabel = "Start",
  endLabel = "End",
}: DumbbellChartProps) {
  const [hoveredIndex, setHoveredIndex] = React.useState<number | null>(null)

  const width = 500
  const height = data.length * 45 + 70
  const margin = { top: 40, right: 40, bottom: 35, left: 90 }

  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom

  const categoryScale = React.useMemo(() => {
    return scaleBand()
      .domain(data.map((d) => d.category))
      .range([0, innerHeight])
      .padding(0.4)
  }, [data, innerHeight])

  const valueScale = React.useMemo(() => {
    const allValues = data.flatMap((d) => [d.start, d.end])
    const minVal = Math.min(...allValues)
    const maxVal = Math.max(...allValues)
    const range = maxVal - minVal || 1
    const padding = range * 0.15
    return scaleLinear()
      .domain([Math.max(0, minVal - padding), maxVal + padding])
      .range([0, innerWidth])
      .nice()
  }, [data, innerWidth])

  const ticks = valueScale.ticks(5)

  return (
    <div className={cn("relative w-full", className)}>
      {/* Legend */}
      <div className="mb-3 flex items-center justify-center gap-6">
        <div className="flex items-center gap-2">
          <div
            className="h-3 w-3 rounded-full"
            style={{ backgroundColor: startColor }}
          />
          <span className="text-muted-foreground text-sm">{startLabel}</span>
        </div>
        <div className="flex items-center gap-2">
          <div
            className="h-3 w-3 rounded-full"
            style={{ backgroundColor: endColor }}
          />
          <span className="text-muted-foreground text-sm">{endLabel}</span>
        </div>
      </div>

      <svg
        viewBox={`0 0 ${width} ${height}`}
        className="h-auto w-full overflow-visible"
      >
        <g transform={`translate(${margin.left}, ${margin.top})`}>
          {/* Grid lines */}
          {showGrid &&
            ticks.map((tick) => (
              <line
                key={tick}
                x1={valueScale(tick)}
                x2={valueScale(tick)}
                y1={0}
                y2={innerHeight}
                stroke="#e5e7eb"
                strokeWidth={1}
              />
            ))}

          {/* Baseline */}
          <line
            x1={0}
            x2={innerWidth}
            y1={innerHeight}
            y2={innerHeight}
            stroke="#e5e7eb"
            strokeWidth={1}
          />

          {/* Dumbbells */}
          {data.map((d, index) => {
            const isHovered = hoveredIndex === index
            const categoryPos =
              (categoryScale(d.category) ?? 0) + categoryScale.bandwidth() / 2

            const x1 = valueScale(d.start)
            const x2 = valueScale(d.end)
            const y = categoryPos

            return (
              <g
                key={d.category}
                className="cursor-pointer"
                onMouseEnter={() => setHoveredIndex(index)}
                onMouseLeave={() => setHoveredIndex(null)}
                style={{
                  opacity: hoveredIndex !== null && !isHovered ? 0.4 : 1,
                  transition: "opacity 150ms",
                }}
              >
                {/* Connector line */}
                <line
                  x1={x1}
                  y1={y}
                  x2={x2}
                  y2={y}
                  stroke={connectorColor}
                  strokeWidth={3}
                  strokeLinecap="round"
                />

                {/* Start dot */}
                <circle
                  cx={x1}
                  cy={y}
                  r={isHovered ? dotSize + 2 : dotSize}
                  fill={startColor}
                  style={{ transition: "r 150ms" }}
                />

                {/* End dot */}
                <circle
                  cx={x2}
                  cy={y}
                  r={isHovered ? dotSize + 2 : dotSize}
                  fill={endColor}
                  style={{ transition: "r 150ms" }}
                />
              </g>
            )
          })}

          {/* Category labels */}
          {data.map((d) => {
            const pos =
              (categoryScale(d.category) ?? 0) + categoryScale.bandwidth() / 2
            return (
              <text
                key={`label-${d.category}`}
                x={-12}
                y={pos}
                textAnchor="end"
                dominantBaseline="middle"
                fontSize={12}
                className="fill-foreground"
              >
                {d.category}
              </text>
            )
          })}

          {/* Value axis labels */}
          {ticks.map((tick) => (
            <text
              key={`tick-${tick}`}
              x={valueScale(tick)}
              y={innerHeight + 20}
              textAnchor="middle"
              fontSize={11}
              className="fill-muted-foreground"
            >
              {valueFormatter(tick)}
            </text>
          ))}
        </g>
      </svg>

      {/* Tooltip */}
      {hoveredIndex !== null && (
        <div className="bg-foreground text-background pointer-events-none absolute top-12 left-1/2 z-50 -translate-x-1/2 rounded-md px-3 py-1.5 text-xs font-medium shadow-lg">
          <span className="font-semibold">{data[hoveredIndex].category}</span>
          <span className="mx-2">·</span>
          <span>
            {startLabel}: {valueFormatter(data[hoveredIndex].start)}
          </span>
          <span className="mx-1">→</span>
          <span>
            {endLabel}: {valueFormatter(data[hoveredIndex].end)}
          </span>
          <span className="ml-2 opacity-70">
            ({data[hoveredIndex].end >= data[hoveredIndex].start ? "+" : ""}
            {valueFormatter(data[hoveredIndex].end - data[hoveredIndex].start)})
          </span>
        </div>
      )}
    </div>
  )
}

"use client"

import * as React from "react"
import { scaleLinear, scalePoint } from "d3-scale"
import { curveLinear, curveMonotoneX, line } from "d3-shape"

import { cn } from "@/lib/utils"

export interface SlopeDataPoint {
  category: string
  start: number
  end: number
  color?: string
}

export interface MultiPeriodSlopeDataPoint {
  category: string
  values: number[]
  color?: string
}

export interface SlopeChartProps {
  data: SlopeDataPoint[] | MultiPeriodSlopeDataPoint[]
  className?: string
  variant?: "lines" | "bumps" | "parallel"
  labels?: string[]
  showGrid?: boolean
  showValues?: boolean
  showRankChange?: boolean
  increaseColor?: string
  decreaseColor?: string
  neutralColor?: string
  valueFormatter?: (value: number) => string
}

// Type guard for multi-period data
function isMultiPeriod(
  data: SlopeDataPoint[] | MultiPeriodSlopeDataPoint[]
): data is MultiPeriodSlopeDataPoint[] {
  return data.length > 0 && "values" in data[0]
}

// Convert simple data to multi-period format
function normalizeData(
  data: SlopeDataPoint[] | MultiPeriodSlopeDataPoint[]
): MultiPeriodSlopeDataPoint[] {
  if (isMultiPeriod(data)) {
    return data
  }
  return data.map((d) => ({
    category: d.category,
    values: [d.start, d.end],
    color: d.color,
  }))
}

export function SlopeChart({
  data,
  className,
  variant = "lines",
  labels,
  showGrid = true,
  showValues = true,
  showRankChange = false,
  increaseColor = "#22c55e",
  decreaseColor = "#ef4444",
  neutralColor = "#94a3b8",
  valueFormatter = (value) => value.toLocaleString(),
}: SlopeChartProps) {
  const [hoveredIndex, setHoveredIndex] = React.useState<number | null>(null)

  // Normalize data to multi-period format
  const normalizedData = React.useMemo(() => normalizeData(data), [data])
  const periodCount = normalizedData[0]?.values.length ?? 2

  // Default labels
  const periodLabels =
    labels ??
    (periodCount === 2
      ? ["Start", "End"]
      : Array.from({ length: periodCount }, (_, i) => `Period ${i + 1}`))

  const width = 500
  const height = Math.max(300, normalizedData.length * 40 + 80)
  const margin = { top: 50, right: 90, bottom: 30, left: 90 }
  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom

  // X scale for periods
  const xScale = React.useMemo(() => {
    return scalePoint<number>()
      .domain(Array.from({ length: periodCount }, (_, i) => i))
      .range([0, innerWidth])
  }, [periodCount, innerWidth])

  // Y scale based on all values
  const yScale = React.useMemo(() => {
    const allValues = normalizedData.flatMap((d) => d.values)
    const minVal = Math.min(...allValues)
    const maxVal = Math.max(...allValues)
    const padding = (maxVal - minVal) * 0.15 || 10
    return scaleLinear()
      .domain([Math.min(0, minVal - padding), maxVal + padding])
      .range([innerHeight, 0])
      .nice()
  }, [normalizedData, innerHeight])

  const yTicks = yScale.ticks(5)

  // Get line color based on direction
  const getLineColor = (d: MultiPeriodSlopeDataPoint) => {
    if (d.color) return d.color
    const first = d.values[0]
    const last = d.values[d.values.length - 1]
    if (last > first) return increaseColor
    if (last < first) return decreaseColor
    return neutralColor
  }

  // Calculate overall change
  const getChange = (d: MultiPeriodSlopeDataPoint) => {
    const first = d.values[0]
    const last = d.values[d.values.length - 1]
    if (first === 0) return last > 0 ? 100 : 0
    return ((last - first) / Math.abs(first)) * 100
  }

  // Get rank at each period (for bumps chart)
  const getRanks = React.useMemo(() => {
    if (variant !== "bumps") return null

    const ranks: Map<string, number[]> = new Map()

    for (let period = 0; period < periodCount; period++) {
      const sorted = [...normalizedData]
        .map((d, i) => ({
          index: i,
          category: d.category,
          value: d.values[period],
        }))
        .sort((a, b) => b.value - a.value)

      sorted.forEach((item, rank) => {
        if (!ranks.has(item.category)) {
          ranks.set(item.category, [])
        }
        ranks.get(item.category)![period] = rank
      })
    }

    return ranks
  }, [normalizedData, periodCount, variant])

  // Y scale for ranks (bumps chart)
  const rankYScale = React.useMemo(() => {
    if (variant !== "bumps") return null
    return scaleLinear()
      .domain([0, normalizedData.length - 1])
      .range([20, innerHeight - 20])
  }, [variant, normalizedData.length, innerHeight])

  // Line generator
  const lineGenerator = React.useMemo(() => {
    return line<{ x: number; y: number }>()
      .x((d) => d.x)
      .y((d) => d.y)
      .curve(variant === "parallel" ? curveLinear : curveMonotoneX)
  }, [variant])

  // Generate path for each data series
  const getPath = (d: MultiPeriodSlopeDataPoint, index: number) => {
    if (variant === "bumps" && getRanks && rankYScale) {
      const ranks = getRanks.get(d.category)
      if (!ranks) return ""
      const points = ranks.map((rank, period) => ({
        x: xScale(period) ?? 0,
        y: rankYScale(rank),
      }))
      return lineGenerator(points) ?? ""
    }

    const points = d.values.map((value, period) => ({
      x: xScale(period) ?? 0,
      y: yScale(value),
    }))
    return lineGenerator(points) ?? ""
  }

  // Get Y position for endpoint
  const getEndY = (
    d: MultiPeriodSlopeDataPoint,
    index: number,
    periodIndex: number
  ) => {
    if (variant === "bumps" && getRanks && rankYScale) {
      const ranks = getRanks.get(d.category)
      return ranks ? rankYScale(ranks[periodIndex]) : 0
    }
    return yScale(d.values[periodIndex])
  }

  // Get rank change display
  const getRankChangeDisplay = (d: MultiPeriodSlopeDataPoint) => {
    if (!getRanks) return null
    const ranks = getRanks.get(d.category)
    if (!ranks) return null
    const change = ranks[0] - ranks[ranks.length - 1]
    if (change > 0) return `+${change}`
    if (change < 0) return `${change}`
    return "="
  }

  return (
    <div className={cn("relative w-full", className)}>
      {/* Legend */}
      <div className="mb-3 flex items-center justify-center gap-6">
        <div className="flex items-center gap-2">
          <div
            className="h-0.5 w-5"
            style={{ backgroundColor: increaseColor }}
          />
          <span className="text-muted-foreground text-sm">Increase</span>
        </div>
        <div className="flex items-center gap-2">
          <div
            className="h-0.5 w-5"
            style={{ backgroundColor: decreaseColor }}
          />
          <span className="text-muted-foreground text-sm">Decrease</span>
        </div>
        {variant !== "bumps" && (
          <div className="flex items-center gap-2">
            <div
              className="h-0.5 w-5"
              style={{ backgroundColor: neutralColor }}
            />
            <span className="text-muted-foreground text-sm">No change</span>
          </div>
        )}
      </div>

      <svg
        viewBox={`0 0 ${width} ${height}`}
        className="h-auto w-full overflow-visible"
      >
        <g transform={`translate(${margin.left}, ${margin.top})`}>
          {/* Grid lines */}
          {showGrid &&
            variant !== "bumps" &&
            yTicks.map((tick) => (
              <line
                key={tick}
                x1={0}
                x2={innerWidth}
                y1={yScale(tick)}
                y2={yScale(tick)}
                stroke="#e5e7eb"
                strokeDasharray="3 3"
              />
            ))}

          {/* Period headers */}
          {periodLabels.map((label, i) => (
            <text
              key={`header-${i}`}
              x={xScale(i) ?? 0}
              y={-25}
              textAnchor="middle"
              fontSize={12}
              fontWeight={500}
              className="fill-foreground"
            >
              {label}
            </text>
          ))}

          {/* Vertical axis lines */}
          {Array.from({ length: periodCount }).map((_, i) => (
            <line
              key={`axis-${i}`}
              x1={xScale(i) ?? 0}
              x2={xScale(i) ?? 0}
              y1={-10}
              y2={innerHeight + 10}
              stroke="#e5e7eb"
              strokeWidth={1}
            />
          ))}

          {/* Slope lines */}
          {normalizedData.map((d, index) => {
            const isHovered = hoveredIndex === index
            const color = getLineColor(d)
            const path = getPath(d, index)

            return (
              <g
                key={d.category}
                className="cursor-pointer"
                onMouseEnter={() => setHoveredIndex(index)}
                onMouseLeave={() => setHoveredIndex(null)}
                style={{
                  opacity: hoveredIndex !== null && !isHovered ? 0.2 : 1,
                  transition: "opacity 150ms",
                }}
              >
                {/* Line path */}
                <path
                  d={path}
                  fill="none"
                  stroke={color}
                  strokeWidth={isHovered ? 3 : 2}
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  style={{ transition: "stroke-width 150ms" }}
                />

                {/* Dots at each period */}
                {d.values.map((_, periodIndex) => (
                  <circle
                    key={periodIndex}
                    cx={xScale(periodIndex) ?? 0}
                    cy={getEndY(d, index, periodIndex)}
                    r={isHovered ? 5 : 4}
                    fill={color}
                    stroke="white"
                    strokeWidth={2}
                    style={{ transition: "r 150ms" }}
                  />
                ))}

                {/* Start label - category name */}
                <text
                  x={-12}
                  y={getEndY(d, index, 0)}
                  textAnchor="end"
                  dominantBaseline="middle"
                  fontSize={11}
                  className="fill-foreground"
                  style={{ fontWeight: isHovered ? 600 : 400 }}
                >
                  {d.category}
                </text>

                {/* End value */}
                {showValues && (
                  <text
                    x={innerWidth + 12}
                    y={getEndY(d, index, periodCount - 1)}
                    textAnchor="start"
                    dominantBaseline="middle"
                    fontSize={11}
                    className="fill-foreground"
                  >
                    {variant === "bumps" && showRankChange ? (
                      <>{getRankChangeDisplay(d)}</>
                    ) : (
                      <>
                        {valueFormatter(d.values[d.values.length - 1])}
                        <tspan fill={color} fontSize={10} fontWeight={500}>
                          {" "}
                          {getChange(d) >= 0 ? "+" : ""}
                          {getChange(d).toFixed(0)}%
                        </tspan>
                      </>
                    )}
                  </text>
                )}
              </g>
            )
          })}
        </g>
      </svg>

      {/* Tooltip */}
      {hoveredIndex !== null && (
        <div className="bg-foreground text-background pointer-events-none absolute top-16 left-1/2 z-50 -translate-x-1/2 rounded-md px-3 py-2 text-xs font-medium shadow-lg">
          <div className="mb-1 font-semibold">
            {normalizedData[hoveredIndex].category}
          </div>
          <div className="flex flex-wrap items-center gap-2 opacity-90">
            {normalizedData[hoveredIndex].values.map((value, i) => (
              <React.Fragment key={i}>
                <span>
                  {periodLabels[i]}: {valueFormatter(value)}
                </span>
                {i < normalizedData[hoveredIndex].values.length - 1 && (
                  <span className="opacity-50">→</span>
                )}
              </React.Fragment>
            ))}
          </div>
          {variant !== "bumps" && (
            <div
              className="mt-1.5 text-center font-semibold"
              style={{ color: getLineColor(normalizedData[hoveredIndex]) }}
            >
              {getChange(normalizedData[hoveredIndex]) >= 0 ? "+" : ""}
              {valueFormatter(
                normalizedData[hoveredIndex].values[
                  normalizedData[hoveredIndex].values.length - 1
                ] - normalizedData[hoveredIndex].values[0]
              )}{" "}
              ({getChange(normalizedData[hoveredIndex]) >= 0 ? "+" : ""}
              {getChange(normalizedData[hoveredIndex]).toFixed(1)}%)
            </div>
          )}
          {variant === "bumps" && getRanks && (
            <div
              className="mt-1.5 text-center font-semibold"
              style={{ color: getLineColor(normalizedData[hoveredIndex]) }}
            >
              Rank change: {getRankChangeDisplay(normalizedData[hoveredIndex])}
            </div>
          )}
        </div>
      )}
    </div>
  )
}

"use client"

import * as React from "react"
import { scaleBand, scaleLinear } from "d3-scale"

import { cn } from "@/lib/utils"

export interface OHLCDataPoint {
  date: string | Date
  open: number
  high: number
  low: number
  close: number
}

export interface OHLCChartProps {
  data: OHLCDataPoint[]
  className?: string
  upColor?: string
  downColor?: string
  showGrid?: boolean
  showTooltip?: boolean
  aspectRatio?: number
  valueFormatter?: (value: number) => string
  dateFormatter?: (date: Date) => string
}

export function OHLCChart({
  data,
  className,
  upColor = "#22c55e",
  downColor = "#ef4444",
  showGrid = true,
  showTooltip = true,
  aspectRatio = 2.5,
  valueFormatter = (value) => `$${value.toFixed(0)}`,
  dateFormatter = (date) =>
    date.toLocaleDateString("en-US", { month: "short" }),
}: OHLCChartProps) {
  const containerRef = React.useRef<HTMLDivElement>(null)
  const [dimensions, setDimensions] = React.useState({ width: 0, height: 0 })
  const [hoveredIndex, setHoveredIndex] = React.useState<number | null>(null)
  const [tooltipPos, setTooltipPos] = React.useState({ x: 0, y: 0 })

  React.useEffect(() => {
    const updateDimensions = () => {
      if (containerRef.current) {
        const width = containerRef.current.offsetWidth
        setDimensions({ width, height: width / aspectRatio })
      }
    }
    updateDimensions()
    window.addEventListener("resize", updateDimensions)
    return () => window.removeEventListener("resize", updateDimensions)
  }, [aspectRatio])

  const { width, height } = dimensions
  const margin = { top: 20, right: 20, bottom: 40, left: 50 }
  const innerWidth = Math.max(0, width - margin.left - margin.right)
  const innerHeight = Math.max(0, height - margin.top - margin.bottom)

  const xScale = React.useMemo(() => {
    return scaleBand()
      .domain(data.map((d) => String(d.date)))
      .range([0, innerWidth])
      .padding(0.3)
  }, [data, innerWidth])

  const yScale = React.useMemo(() => {
    const allPrices = data.flatMap((d) => [d.high, d.low])
    const minPrice = Math.min(...allPrices)
    const maxPrice = Math.max(...allPrices)
    const padding = (maxPrice - minPrice) * 0.1
    return scaleLinear()
      .domain([Math.max(0, minPrice - padding), maxPrice + padding])
      .range([innerHeight, 0])
      .nice()
  }, [data, innerHeight])

  const tickWidth = xScale.bandwidth() * 0.4
  const ticks = yScale.ticks(5)

  const monthLabels = React.useMemo(() => {
    const labels: { date: string; x: number }[] = []
    let lastMonth = -1
    data.forEach((d) => {
      const date = new Date(d.date)
      const month = date.getMonth()
      if (month !== lastMonth) {
        labels.push({
          date: String(d.date),
          x: (xScale(String(d.date)) ?? 0) + xScale.bandwidth() / 2,
        })
        lastMonth = month
      }
    })
    return labels
  }, [data, xScale])

  if (width === 0) {
    return <div ref={containerRef} className={cn("w-full", className)} />
  }

  return (
    <div ref={containerRef} className={cn("relative w-full", className)}>
      <svg
        width={width}
        height={height}
        viewBox={`0 0 ${width} ${height}`}
        className="overflow-visible"
      >
        <g transform={`translate(${margin.left}, ${margin.top})`}>
          {showGrid && (
            <>
              {ticks.map((tick) => (
                <line
                  key={`h-${tick}`}
                  x1={0}
                  x2={innerWidth}
                  y1={yScale(tick)}
                  y2={yScale(tick)}
                  stroke="hsl(var(--border))"
                  strokeDasharray="3 3"
                  strokeOpacity={0.5}
                />
              ))}
              {monthLabels.map((label, i) => (
                <line
                  key={`v-${i}`}
                  x1={label.x}
                  x2={label.x}
                  y1={0}
                  y2={innerHeight}
                  stroke="hsl(var(--border))"
                  strokeDasharray="3 3"
                  strokeOpacity={0.5}
                />
              ))}
            </>
          )}

          {/* OHLC bars */}
          {data.map((d, index) => {
            const isUp = d.close >= d.open
            const color = isUp ? upColor : downColor
            const x = (xScale(String(d.date)) ?? 0) + xScale.bandwidth() / 2
            const isHovered = hoveredIndex === index

            return (
              <g
                key={index}
                className={cn(
                  "cursor-pointer transition-opacity duration-200",
                  hoveredIndex !== null && !isHovered && "opacity-40"
                )}
                onMouseEnter={(e) => {
                  setHoveredIndex(index)
                  const rect = containerRef.current?.getBoundingClientRect()
                  if (rect) {
                    setTooltipPos({
                      x: e.clientX - rect.left,
                      y: e.clientY - rect.top,
                    })
                  }
                }}
                onMouseMove={(e) => {
                  const rect = containerRef.current?.getBoundingClientRect()
                  if (rect) {
                    setTooltipPos({
                      x: e.clientX - rect.left,
                      y: e.clientY - rect.top,
                    })
                  }
                }}
                onMouseLeave={() => setHoveredIndex(null)}
              >
                {/* Vertical line (high to low) */}
                <line
                  x1={x}
                  x2={x}
                  y1={yScale(d.high)}
                  y2={yScale(d.low)}
                  stroke={color}
                  strokeWidth={2}
                />

                {/* Open tick (left) */}
                <line
                  x1={x - tickWidth}
                  x2={x}
                  y1={yScale(d.open)}
                  y2={yScale(d.open)}
                  stroke={color}
                  strokeWidth={2}
                />

                {/* Close tick (right) */}
                <line
                  x1={x}
                  x2={x + tickWidth}
                  y1={yScale(d.close)}
                  y2={yScale(d.close)}
                  stroke={color}
                  strokeWidth={2}
                />
              </g>
            )
          })}

          {/* X Axis */}
          <g transform={`translate(0, ${innerHeight})`}>
            {monthLabels.map((label, i) => {
              const date = new Date(label.date)
              return (
                <text
                  key={i}
                  x={label.x}
                  y={24}
                  textAnchor="middle"
                  className="fill-muted-foreground text-xs"
                >
                  {dateFormatter(date)}
                </text>
              )
            })}
          </g>

          {/* Y Axis */}
          <g>
            {ticks.map((tick) => (
              <text
                key={tick}
                x={-12}
                y={yScale(tick)}
                dy="0.32em"
                textAnchor="end"
                className="fill-muted-foreground text-xs"
              >
                {valueFormatter(tick)}
              </text>
            ))}
          </g>
        </g>
      </svg>

      {/* Tooltip */}
      {showTooltip && hoveredIndex !== null && (
        <div
          className="pointer-events-none absolute z-50"
          style={{
            left: tooltipPos.x + 10,
            top: tooltipPos.y - 10,
            transform: "translateY(-100%)",
          }}
        >
          <div className="bg-background rounded-lg border px-3 py-2 shadow-lg">
            <p className="text-foreground mb-1 text-sm font-medium">
              {new Date(data[hoveredIndex].date).toLocaleDateString("en-US", {
                month: "short",
                day: "numeric",
                year: "numeric",
              })}
            </p>
            <div className="grid grid-cols-2 gap-x-4 gap-y-0.5 text-sm">
              <span className="text-muted-foreground">Open</span>
              <span
                className="font-mono"
                style={{
                  color:
                    data[hoveredIndex].close >= data[hoveredIndex].open
                      ? upColor
                      : downColor,
                }}
              >
                {valueFormatter(data[hoveredIndex].open)}
              </span>
              <span className="text-muted-foreground">High</span>
              <span
                className="font-mono"
                style={{
                  color:
                    data[hoveredIndex].close >= data[hoveredIndex].open
                      ? upColor
                      : downColor,
                }}
              >
                {valueFormatter(data[hoveredIndex].high)}
              </span>
              <span className="text-muted-foreground">Low</span>
              <span
                className="font-mono"
                style={{
                  color:
                    data[hoveredIndex].close >= data[hoveredIndex].open
                      ? upColor
                      : downColor,
                }}
              >
                {valueFormatter(data[hoveredIndex].low)}
              </span>
              <span className="text-muted-foreground">Close</span>
              <span
                className="font-mono"
                style={{
                  color:
                    data[hoveredIndex].close >= data[hoveredIndex].open
                      ? upColor
                      : downColor,
                }}
              >
                {valueFormatter(data[hoveredIndex].close)}
              </span>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

"use client"

import * as React from "react"
import type { GeoPermissibleObjects } from "d3-geo"
import {
  geoAlbersUsa,
  geoEqualEarth,
  geoMercator,
  geoNaturalEarth1,
  geoPath,
} from "d3-geo"
import { interpolateRgb } from "d3-interpolate"
import { feature } from "topojson-client"
import type { GeometryCollection, Topology } from "topojson-specification"

import { cn } from "@/lib/utils"

export interface GeoFeature {
  type: "Feature"
  properties: {
    name?: string
    iso_a2?: string
    iso_a3?: string
    [key: string]: unknown
  }
  geometry: GeoPermissibleObjects
  id?: string | number
}

export interface GeoJSON {
  type: "FeatureCollection"
  features: GeoFeature[]
}

export interface ChoroplethDataPoint {
  id: string // ISO country code (2 or 3 letter)
  value: number
  label?: string
}

export interface ChoroplethChartProps {
  data: ChoroplethDataPoint[]
  className?: string
  colorScale?: string[]
  showTooltip?: boolean
  showLegend?: boolean
  projection?: "naturalEarth" | "mercator" | "equalEarth" | "albersUsa"
  aspectRatio?: number
  legendTitle?: string
  valueFormatter?: (value: number) => string
  noDataColor?: string
  /** Custom GeoJSON/TopoJSON URL. Defaults to world countries. */
  geoUrl?: string
  /** Object name in TopoJSON (e.g., "states", "countries"). Auto-detected if not provided. */
  topojsonObject?: string
  /** Property name to use as feature ID (e.g., "name", "postal", "iso_a2") */
  idProperty?: string
}

// Default world countries GeoJSON URL
const WORLD_GEOJSON_URL =
  "https://cdn.jsdelivr.net/npm/world-atlas@2/countries-110m.json"

// Country-specific GeoJSON/TopoJSON URLs (all CORS-enabled)
export const GEO_URLS = {
  world: "https://cdn.jsdelivr.net/npm/world-atlas@2/countries-110m.json",
  usa: "https://cdn.jsdelivr.net/npm/us-atlas@3/states-10m.json",
  india:
    "https://raw.githubusercontent.com/datta07/INDIAN-SHAPEFILES/master/INDIA/INDIA_STATES.geojson",
  china:
    "https://raw.githubusercontent.com/markmarkoh/datamaps/master/src/js/data/chn.topo.json",
  uk: "https://raw.githubusercontent.com/markmarkoh/datamaps/master/src/js/data/gbr.topo.json",
  russia:
    "https://raw.githubusercontent.com/markmarkoh/datamaps/master/src/js/data/rus.topo.json",
  germany:
    "https://raw.githubusercontent.com/isellsoap/deutschlandGeoJSON/master/2_bundeslaender/4_niedrig.geo.json",
  france:
    "https://raw.githubusercontent.com/gregoiredavid/france-geojson/master/regions-version-simplifiee.geojson",
  brazil:
    "https://raw.githubusercontent.com/codeforamerica/click_that_hood/master/public/data/brazil-states.geojson",
} as const

export function ChoroplethChart({
  data,
  className,
  colorScale = ["#bfdbfe", "#60a5fa", "#1e40af"],
  showTooltip = true,
  showLegend = true,
  projection = "naturalEarth",
  aspectRatio = 2,
  legendTitle = "Value",
  valueFormatter = (v) => v.toLocaleString(),
  noDataColor = "hsl(var(--muted))",
  geoUrl,
  topojsonObject,
  idProperty,
}: ChoroplethChartProps) {
  const containerRef = React.useRef<HTMLDivElement>(null)
  const [dimensions, setDimensions] = React.useState({ width: 0, height: 0 })
  const [geoData, setGeoData] = React.useState<GeoJSON | null>(null)
  const [loading, setLoading] = React.useState(true)
  const [error, setError] = React.useState<string | null>(null)
  const [hoveredFeature, setHoveredFeature] = React.useState<GeoFeature | null>(
    null
  )
  const [tooltipPos, setTooltipPos] = React.useState({ x: 0, y: 0 })
  const gradientId = React.useId().replace(/:/g, "")

  // Responsive sizing
  React.useEffect(() => {
    const updateDimensions = () => {
      if (containerRef.current) {
        const width = containerRef.current.offsetWidth
        setDimensions({ width, height: width / aspectRatio })
      }
    }
    updateDimensions()
    window.addEventListener("resize", updateDimensions)
    return () => window.removeEventListener("resize", updateDimensions)
  }, [aspectRatio])

  // Fetch GeoJSON/TopoJSON
  React.useEffect(() => {
    const fetchGeoData = async () => {
      try {
        setLoading(true)
        setError(null)
        const url = geoUrl || WORLD_GEOJSON_URL

        const response = await fetch(url)
        if (!response.ok) {
          throw new Error(`HTTP ${response.status}: ${response.statusText}`)
        }

        const jsonData = await response.json()

        // Check if it's TopoJSON (has "objects" property) or GeoJSON
        if (jsonData.type === "Topology" && jsonData.objects) {
          // Convert TopoJSON to GeoJSON
          const topoData = jsonData as Topology<{
            [key: string]: GeometryCollection
          }>

          // Use specified object or find first available (case-insensitive)
          const availableKeys = Object.keys(topoData.objects)
          let objectName = topojsonObject || availableKeys[0]

          // Try case-insensitive match if exact match fails
          if (!topoData.objects[objectName]) {
            const lowerName = objectName.toLowerCase()
            const match = availableKeys.find(
              (k) => k.toLowerCase() === lowerName
            )
            if (match) {
              objectName = match
            } else {
              throw new Error(
                `TopoJSON object "${objectName}" not found. Available: ${availableKeys.join(", ")}`
              )
            }
          }

          const geoJson = feature(
            topoData,
            topoData.objects[objectName]
          ) as unknown as GeoJSON

          setGeoData(geoJson)
        } else if (jsonData.type === "FeatureCollection") {
          // Already GeoJSON
          setGeoData(jsonData as GeoJSON)
        } else {
          throw new Error(
            `Invalid geo data format: ${jsonData.type || "unknown"}`
          )
        }
      } catch (err) {
        const message = err instanceof Error ? err.message : "Unknown error"
        setError(`Failed to load map: ${message}`)
        console.error("Failed to load GeoJSON:", err)
      } finally {
        setLoading(false)
      }
    }
    fetchGeoData()
  }, [geoUrl, topojsonObject])

  const { width, height } = dimensions
  const margin = { top: 10, right: showLegend ? 80 : 20, bottom: 10, left: 10 }
  const innerWidth = Math.max(0, width - margin.left - margin.right)
  const innerHeight = Math.max(0, height - margin.top - margin.bottom)

  // Create data map for quick lookup (support various ID formats)
  const dataMap = React.useMemo(() => {
    const map = new Map<string, ChoroplethDataPoint>()
    data.forEach((d) => {
      map.set(d.id, d) // exact match
      map.set(d.id.toUpperCase(), d)
      map.set(d.id.toLowerCase(), d)
    })
    return map
  }, [data])

  // Calculate value range
  const { minValue, maxValue } = React.useMemo(() => {
    if (data.length === 0) return { minValue: 0, maxValue: 100 }
    const values = data.map((d) => d.value)
    return {
      minValue: Math.min(...values),
      maxValue: Math.max(...values),
    }
  }, [data])

  // Color scale function
  const getColor = React.useCallback(
    (value: number | undefined) => {
      if (value === undefined) return noDataColor
      const range = maxValue - minValue || 1
      const t = (value - minValue) / range

      if (colorScale.length === 2) {
        return interpolateRgb(colorScale[0], colorScale[1])(t)
      }
      if (t < 0.5) {
        return interpolateRgb(colorScale[0], colorScale[1])(t * 2)
      }
      return interpolateRgb(colorScale[1], colorScale[2])((t - 0.5) * 2)
    },
    [colorScale, minValue, maxValue, noDataColor]
  )

  // Get feature value by matching ID
  const getFeatureValue = React.useCallback(
    (feature: GeoFeature) => {
      // If idProperty is specified, use it first
      if (idProperty && feature.properties[idProperty]) {
        const id = String(feature.properties[idProperty])
        const d =
          dataMap.get(id) ||
          dataMap.get(id.toUpperCase()) ||
          dataMap.get(id.toLowerCase())
        if (d) return d.value
      }

      // Try different ID formats (various GeoJSON schemas)
      const ids = [
        feature.id,
        feature.properties.name,
        feature.properties.NAME,
        feature.properties.nom, // French regions
        feature.properties.STNAME_SH, // India states (official)
        feature.properties.iso_a2,
        feature.properties.iso_a3,
        feature.properties.postal,
        feature.properties.code,
        feature.properties.st_nm, // India states (datamaps)
        feature.properties.sigla, // Brazil states
      ].filter(Boolean) as string[]

      for (const id of ids) {
        const d =
          dataMap.get(id) ||
          dataMap.get(id.toUpperCase()) ||
          dataMap.get(id.toLowerCase())
        if (d) return d.value
      }
      return undefined
    },
    [dataMap, idProperty]
  )

  // Create projection
  const projectionFn = React.useMemo(() => {
    if (innerWidth === 0 || innerHeight === 0 || !geoData) return null

    const projections = {
      naturalEarth: geoNaturalEarth1,
      mercator: geoMercator,
      equalEarth: geoEqualEarth,
      albersUsa: geoAlbersUsa,
    }

    const proj = projections[projection]()

    // AlbersUSA has its own built-in scale, others need fitSize
    if (projection === "albersUsa") {
      // Scale to fit container - AlbersUSA is designed for ~960x600
      const scale = Math.min(innerWidth / 960, innerHeight / 600) * 1100
      return proj.scale(scale).translate([innerWidth / 2, innerHeight / 2])
    }

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    return proj.fitSize([innerWidth, innerHeight], geoData as any)
  }, [projection, innerWidth, innerHeight, geoData])

  const pathGenerator = React.useMemo(() => {
    if (!projectionFn) return null
    return geoPath().projection(projectionFn)
  }, [projectionFn])

  // Show loading state (use min-height when width not yet measured)
  if (loading) {
    return (
      <div ref={containerRef} className={cn("w-full", className)}>
        <div
          className="bg-muted/20 flex animate-pulse items-center justify-center rounded-lg"
          style={{ height: width > 0 ? width / aspectRatio : 200 }}
        >
          <span className="text-muted-foreground text-sm">Loading map...</span>
        </div>
      </div>
    )
  }

  // Show error state
  if (error || !geoData) {
    return (
      <div ref={containerRef} className={cn("w-full", className)}>
        <div
          className="bg-muted/20 flex items-center justify-center rounded-lg"
          style={{ height: width > 0 ? width / aspectRatio : 200 }}
        >
          <span className="text-muted-foreground text-sm">
            {error || "Failed to load map"}
          </span>
        </div>
      </div>
    )
  }

  // Wait for dimensions to be measured
  if (width === 0 || !pathGenerator) {
    return (
      <div
        ref={containerRef}
        className={cn("min-h-[200px] w-full", className)}
      />
    )
  }

  return (
    <div ref={containerRef} className={cn("relative w-full", className)}>
      <div className="flex w-full items-center justify-center">
        <svg
          width={width}
          height={height}
          viewBox={`0 0 ${width} ${height}`}
          className="overflow-visible"
        >
          <g transform={`translate(${margin.left}, ${margin.top})`}>
            {/* Map features */}
            {geoData.features.map((feature, index) => {
              const value = getFeatureValue(feature)
              const color = getColor(value)
              const isHovered = hoveredFeature === feature
              const pathD = pathGenerator(feature as any)

              if (!pathD) return null

              return (
                <path
                  key={feature.id || index}
                  d={pathD}
                  fill={color}
                  stroke="hsl(var(--background))"
                  strokeWidth={isHovered ? 1.5 : 0.5}
                  className={cn(
                    "cursor-pointer transition-all duration-150",
                    hoveredFeature !== null && !isHovered && "opacity-70"
                  )}
                  onMouseEnter={(e) => {
                    setHoveredFeature(feature)
                    const rect = containerRef.current?.getBoundingClientRect()
                    if (rect) {
                      setTooltipPos({
                        x: e.clientX - rect.left,
                        y: e.clientY - rect.top,
                      })
                    }
                  }}
                  onMouseMove={(e) => {
                    const rect = containerRef.current?.getBoundingClientRect()
                    if (rect) {
                      setTooltipPos({
                        x: e.clientX - rect.left,
                        y: e.clientY - rect.top,
                      })
                    }
                  }}
                  onMouseLeave={() => setHoveredFeature(null)}
                />
              )
            })}
          </g>

          {/* Color legend */}
          {showLegend && (
            <g
              transform={`translate(${width - margin.right + 15}, ${margin.top + 20})`}
            >
              <text
                className="fill-muted-foreground text-[10px] font-medium"
                y={-8}
              >
                {legendTitle}
              </text>
              <defs>
                <linearGradient
                  id={`gradient-${gradientId}`}
                  x1="0"
                  y1="1"
                  x2="0"
                  y2="0"
                >
                  <stop offset="0%" stopColor={colorScale[0]} />
                  {colorScale.length === 3 && (
                    <stop offset="50%" stopColor={colorScale[1]} />
                  )}
                  <stop
                    offset="100%"
                    stopColor={colorScale[colorScale.length - 1]}
                  />
                </linearGradient>
              </defs>
              <rect
                width={15}
                height={Math.max(0, innerHeight - 40)}
                fill={`url(#gradient-${gradientId})`}
                rx={2}
              />
              <text
                x={20}
                y={0}
                dominantBaseline="hanging"
                className="fill-muted-foreground text-[10px]"
              >
                {valueFormatter(maxValue)}
              </text>
              <text
                x={20}
                y={Math.max(0, innerHeight - 40)}
                dominantBaseline="auto"
                className="fill-muted-foreground text-[10px]"
              >
                {valueFormatter(minValue)}
              </text>
            </g>
          )}
        </svg>
      </div>

      {/* Tooltip */}
      {showTooltip &&
        hoveredFeature &&
        (() => {
          const value = getFeatureValue(hoveredFeature)
          const tooltipWidth = 160
          const tooltipHeight = 60
          const padding = 10

          const showOnLeft = tooltipPos.x + tooltipWidth + padding > width
          const showBelow = tooltipPos.y - tooltipHeight - padding < 0

          return (
            <div
              className="pointer-events-none absolute z-50"
              style={{
                left: showOnLeft
                  ? tooltipPos.x - padding
                  : tooltipPos.x + padding,
                top: showBelow
                  ? tooltipPos.y + padding
                  : tooltipPos.y - padding,
                transform: `translate(${showOnLeft ? "-100%" : "0"}, ${showBelow ? "0" : "-100%"})`,
              }}
            >
              <div className="bg-background rounded-lg border px-3 py-2 shadow-lg">
                <p className="text-foreground text-sm font-medium">
                  {String(
                    hoveredFeature.properties.name ||
                      hoveredFeature.properties.NAME ||
                      hoveredFeature.properties.nom ||
                      hoveredFeature.properties.STNAME_SH ||
                      hoveredFeature.id ||
                      "Unknown"
                  )}
                </p>
                <p className="text-muted-foreground text-sm">
                  {value !== undefined ? (
                    <>
                      {legendTitle}: {valueFormatter(value)}
                    </>
                  ) : (
                    "No data"
                  )}
                </p>
              </div>
            </div>
          )
        })()}
    </div>
  )
}

"use client"

import * as React from "react"
import { scaleBand, scaleLinear } from "d3-scale"
import { arc } from "d3-shape"

import { cn } from "@/lib/utils"

export interface PolarDataPoint {
  category: string
  value: number
  color?: string
}

export interface PolarChartProps {
  data: PolarDataPoint[]
  className?: string
  variant?: "rose" | "coxcomb" | "radar-area"
  innerRadius?: number
  showLabels?: boolean
  showValues?: boolean
  showGrid?: boolean
  valueFormatter?: (value: number) => string
  colorScheme?: string[]
}

export function PolarChart({
  data,
  className,
  variant = "rose",
  innerRadius = 0,
  showLabels = true,
  showValues = false,
  showGrid = true,
  valueFormatter = (value) => value.toLocaleString(),
  colorScheme = [
    "#1e40af",
    "#2563eb",
    "#3b82f6",
    "#60a5fa",
    "#93c5fd",
    "#bfdbfe",
  ],
}: PolarChartProps) {
  const [hoveredIndex, setHoveredIndex] = React.useState<number | null>(null)

  const width = 400
  const height = 400
  const centerX = width / 2
  const centerY = height / 2
  const outerRadius = Math.min(width, height) / 2 - 40

  const maxValue = Math.max(...data.map((d) => d.value))

  // Angle scale (categories around the circle)
  const angleScale = scaleBand<string>()
    .domain(data.map((d) => d.category))
    .range([0, 2 * Math.PI])

  // Radius scale (values from center to edge)
  const radiusScale = scaleLinear()
    .domain([0, maxValue])
    .range([innerRadius, outerRadius])

  // Grid circles
  const gridCircles = radiusScale.ticks(4)

  // Arc generator
  const arcGenerator = arc<{
    startAngle: number
    endAngle: number
    innerRadius: number
    outerRadius: number
  }>()

  return (
    <div className={cn("w-full", className)}>
      <svg
        viewBox={`0 0 ${width} ${height}`}
        className="h-auto w-full overflow-visible"
      >
        <g transform={`translate(${centerX}, ${centerY})`}>
          {/* Grid circles */}
          {showGrid &&
            gridCircles.map((tick, i) => (
              <g key={`grid-${i}`}>
                <circle
                  r={radiusScale(tick)}
                  fill="none"
                  stroke="hsl(var(--border))"
                  strokeDasharray="3 3"
                  strokeOpacity={0.5}
                />
                <text
                  x={4}
                  y={-radiusScale(tick) - 2}
                  className="fill-muted-foreground text-[10px]"
                >
                  {valueFormatter(tick)}
                </text>
              </g>
            ))}

          {/* Grid lines (spokes) */}
          {showGrid &&
            data.map((d, i) => {
              const angle =
                (angleScale(d.category) ?? 0) +
                angleScale.bandwidth() / 2 -
                Math.PI / 2
              const x2 = Math.cos(angle) * outerRadius
              const y2 = Math.sin(angle) * outerRadius
              return (
                <line
                  key={`spoke-${i}`}
                  x1={0}
                  y1={0}
                  x2={x2}
                  y2={y2}
                  stroke="hsl(var(--border))"
                  strokeOpacity={0.3}
                />
              )
            })}

          {/* Rose/Coxcomb segments */}
          {data.map((d, index) => {
            const startAngle = angleScale(d.category) ?? 0
            const endAngle = startAngle + angleScale.bandwidth()
            const color = d.color ?? colorScheme[index % colorScheme.length]
            const isHovered = hoveredIndex === index

            let segmentRadius: number
            if (variant === "coxcomb") {
              // Coxcomb: equal angles, radius varies with sqrt(value) for equal area
              segmentRadius = radiusScale(
                Math.sqrt(d.value / maxValue) * maxValue
              )
            } else {
              // Rose: equal angles, radius varies linearly with value
              segmentRadius = radiusScale(d.value)
            }

            const pathData = arcGenerator({
              startAngle: startAngle - Math.PI / 2,
              endAngle: endAngle - Math.PI / 2,
              innerRadius: innerRadius,
              outerRadius: segmentRadius,
            })

            return (
              <g key={d.category}>
                <path
                  d={pathData ?? ""}
                  fill={color}
                  fillOpacity={isHovered ? 0.9 : 0.7}
                  stroke={color}
                  strokeWidth={isHovered ? 2 : 1}
                  className={cn(
                    "cursor-pointer transition-all duration-200",
                    hoveredIndex !== null && !isHovered && "opacity-50"
                  )}
                  onMouseEnter={() => setHoveredIndex(index)}
                  onMouseLeave={() => setHoveredIndex(null)}
                />
              </g>
            )
          })}

          {/* Labels */}
          {showLabels &&
            data.map((d, index) => {
              const angle =
                (angleScale(d.category) ?? 0) +
                angleScale.bandwidth() / 2 -
                Math.PI / 2
              const labelRadius = outerRadius + 20
              const x = Math.cos(angle) * labelRadius
              const y = Math.sin(angle) * labelRadius

              return (
                <text
                  key={`label-${index}`}
                  x={x}
                  y={y}
                  textAnchor="middle"
                  dominantBaseline="middle"
                  className="fill-foreground text-xs font-medium"
                  style={{
                    transform: `rotate(${angle > Math.PI / 2 && angle < (3 * Math.PI) / 2 ? 180 : 0}deg)`,
                    transformOrigin: `${x}px ${y}px`,
                  }}
                >
                  {d.category}
                </text>
              )
            })}
        </g>
      </svg>

      {/* Tooltip */}
      {hoveredIndex !== null && (
        <div className="mt-2 text-center">
          <div className="border-border/50 bg-background mx-auto inline-block rounded-lg border px-3 py-2 text-sm shadow-lg">
            <div className="font-medium">{data[hoveredIndex].category}</div>
            <div className="text-muted-foreground">
              {valueFormatter(data[hoveredIndex].value)}
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

"use client"

import * as React from "react"
import { scaleLinear, scalePoint } from "d3-scale"
import { line } from "d3-shape"

import { cn } from "@/lib/utils"

export interface ParallelCoordinatesDataPoint {
  id: string
  values: Record<string, number>
  color?: string
  group?: string
}

export interface ParallelCoordinatesProps {
  data: ParallelCoordinatesDataPoint[]
  dimensions: string[]
  className?: string
  showLabels?: boolean
  showValues?: boolean
  lineOpacity?: number
  colorScheme?: string[]
}

export function ParallelCoordinates({
  data,
  dimensions,
  className,
  showLabels = true,
  showValues = true,
  lineOpacity = 0.5,
  colorScheme = ["#1e40af", "#2563eb", "#3b82f6", "#60a5fa", "#93c5fd"],
}: ParallelCoordinatesProps) {
  const [hoveredId, setHoveredId] = React.useState<string | null>(null)
  const [brushedDimension, setBrushedDimension] = React.useState<string | null>(
    null
  )

  const width = 600
  const height = 350
  const margin = { top: 40, right: 30, bottom: 30, left: 30 }
  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom

  // Get unique groups
  const groups = React.useMemo(() => {
    return [...new Set(data.map((d) => d.group ?? "default"))]
  }, [data])

  const getGroupColor = (group?: string) => {
    const index = groups.indexOf(group ?? "default")
    return colorScheme[index % colorScheme.length]
  }

  // X scale for dimensions
  const xScale = scalePoint<string>().domain(dimensions).range([0, innerWidth])

  // Y scales for each dimension
  const yScales = React.useMemo(() => {
    const scales: Record<
      string,
      ReturnType<typeof scaleLinear<number, number>>
    > = {}

    dimensions.forEach((dim) => {
      const values = data
        .map((d) => d.values[dim])
        .filter((v) => v !== undefined)
      const minVal = Math.min(...values)
      const maxVal = Math.max(...values)
      const padding = (maxVal - minVal) * 0.1 || 1

      scales[dim] = scaleLinear()
        .domain([minVal - padding, maxVal + padding])
        .range([innerHeight, 0])
        .nice()
    })

    return scales
  }, [data, dimensions, innerHeight])

  // Line generator
  const lineGenerator = line<{ x: number; y: number }>()
    .x((d) => d.x)
    .y((d) => d.y)

  // Generate path for each data point
  const getPath = (d: ParallelCoordinatesDataPoint) => {
    const points = dimensions
      .map((dim) => {
        const x = xScale(dim)
        const y = yScales[dim]?.(d.values[dim])
        if (x === undefined || y === undefined) return null
        return { x, y }
      })
      .filter((p): p is { x: number; y: number } => p !== null)

    return lineGenerator(points)
  }

  return (
    <div className={cn("w-full", className)}>
      <svg
        viewBox={`0 0 ${width} ${height}`}
        className="h-auto w-full overflow-visible"
      >
        <g transform={`translate(${margin.left}, ${margin.top})`}>
          {/* Axes */}
          {dimensions.map((dim) => {
            const x = xScale(dim) ?? 0
            const scale = yScales[dim]
            const ticks = scale?.ticks(5) ?? []

            return (
              <g key={dim} transform={`translate(${x}, 0)`}>
                {/* Axis line */}
                <line
                  y1={0}
                  y2={innerHeight}
                  stroke="hsl(var(--border))"
                  strokeWidth={1}
                />

                {/* Ticks */}
                {showValues &&
                  ticks.map((tick, i) => (
                    <g key={i} transform={`translate(0, ${scale(tick)})`}>
                      <line x1={-4} x2={0} stroke="hsl(var(--border))" />
                      <text
                        x={-8}
                        textAnchor="end"
                        dominantBaseline="middle"
                        className="fill-muted-foreground text-[9px]"
                      >
                        {tick.toFixed(0)}
                      </text>
                    </g>
                  ))}

                {/* Dimension label */}
                {showLabels && (
                  <text
                    y={-15}
                    textAnchor="middle"
                    className="fill-foreground text-xs font-medium"
                  >
                    {dim}
                  </text>
                )}
              </g>
            )
          })}

          {/* Lines */}
          {data.map((d) => {
            const path = getPath(d)
            if (!path) return null

            const color = d.color ?? getGroupColor(d.group)
            const isHovered = hoveredId === d.id

            return (
              <path
                key={d.id}
                d={path}
                fill="none"
                stroke={color}
                strokeWidth={isHovered ? 3 : 1.5}
                strokeOpacity={
                  hoveredId === null ? lineOpacity : isHovered ? 1 : 0.1
                }
                className="cursor-pointer transition-all duration-200"
                onMouseEnter={() => setHoveredId(d.id)}
                onMouseLeave={() => setHoveredId(null)}
              />
            )
          })}
        </g>
      </svg>

      {/* Tooltip */}
      {hoveredId && (
        <div className="mt-2 text-center">
          <div className="border-border/50 bg-background mx-auto inline-block rounded-lg border px-3 py-2 text-sm shadow-lg">
            <div className="font-medium">{hoveredId}</div>
            <div className="text-muted-foreground grid grid-cols-2 gap-x-3 text-xs">
              {dimensions.map((dim) => {
                const item = data.find((d) => d.id === hoveredId)
                return (
                  <React.Fragment key={dim}>
                    <span>{dim}:</span>
                    <span>{item?.values[dim]?.toFixed(1)}</span>
                  </React.Fragment>
                )
              })}
            </div>
          </div>
        </div>
      )}

      {/* Legend */}
      {groups.length > 1 && (
        <div className="mt-3 flex flex-wrap justify-center gap-4">
          {groups.map((group) => (
            <div key={group} className="flex items-center gap-1.5 text-sm">
              <div
                className="h-0.5 w-4"
                style={{ backgroundColor: getGroupColor(group) }}
              />
              <span className="text-muted-foreground">{group}</span>
            </div>
          ))}
        </div>
      )}
    </div>
  )
}

"use client"

import * as React from "react"
import { contourDensity } from "d3-contour"
import { geoPath } from "d3-geo"
import { scaleLinear, scaleSequential } from "d3-scale"
import { interpolateBlues } from "d3-scale-chromatic"

import { cn } from "@/lib/utils"

export interface DensityDataPoint {
  x: number
  y: number
}

export interface DensityChartProps {
  data: DensityDataPoint[]
  className?: string
  showPoints?: boolean
  showContours?: boolean
  bandwidth?: number
  thresholds?: number
  pointRadius?: number
  pointColor?: string
  colorScale?: (t: number) => string
  xAxisLabel?: string
  yAxisLabel?: string
}

export function DensityChart({
  data,
  className,
  showPoints = true,
  showContours = true,
  bandwidth = 20,
  thresholds = 10,
  pointRadius = 3,
  pointColor = "#1e40af",
  colorScale = interpolateBlues,
  xAxisLabel,
  yAxisLabel,
}: DensityChartProps) {
  const [hoveredPoint, setHoveredPoint] = React.useState<number | null>(null)

  const width = 500
  const height = 400
  const margin = { top: 20, right: 20, bottom: 50, left: 60 }
  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom

  // X Scale
  const xExtent = React.useMemo(() => {
    const xValues = data.map((d) => d.x)
    const min = Math.min(...xValues)
    const max = Math.max(...xValues)
    const padding = (max - min) * 0.1
    return [min - padding, max + padding]
  }, [data])

  const xScale = scaleLinear().domain(xExtent).range([0, innerWidth]).nice()

  // Y Scale
  const yExtent = React.useMemo(() => {
    const yValues = data.map((d) => d.y)
    const min = Math.min(...yValues)
    const max = Math.max(...yValues)
    const padding = (max - min) * 0.1
    return [min - padding, max + padding]
  }, [data])

  const yScale = scaleLinear().domain(yExtent).range([innerHeight, 0]).nice()

  // Contour density
  const contours = React.useMemo(() => {
    if (!showContours) return []

    const densityGenerator = contourDensity<DensityDataPoint>()
      .x((d) => xScale(d.x))
      .y((d) => yScale(d.y))
      .size([innerWidth, innerHeight])
      .bandwidth(bandwidth)
      .thresholds(thresholds)

    return densityGenerator(data)
  }, [
    data,
    xScale,
    yScale,
    innerWidth,
    innerHeight,
    bandwidth,
    thresholds,
    showContours,
  ])

  // Color scale for contours
  const densityColorScale = scaleSequential(colorScale).domain([
    0,
    Math.max(...contours.map((c) => c.value)),
  ])

  // Path generator
  const pathGenerator = geoPath()

  // Axis ticks
  const xTicks = xScale.ticks(6)
  const yTicks = yScale.ticks(6)

  return (
    <div className={cn("w-full", className)}>
      <svg
        viewBox={`0 0 ${width} ${height}`}
        className="h-auto w-full overflow-visible"
      >
        <g transform={`translate(${margin.left}, ${margin.top})`}>
          {/* Grid */}
          {xTicks.map((tick) => (
            <line
              key={`x-grid-${tick}`}
              x1={xScale(tick)}
              x2={xScale(tick)}
              y1={0}
              y2={innerHeight}
              stroke="hsl(var(--border))"
              strokeDasharray="3 3"
              strokeOpacity={0.5}
            />
          ))}
          {yTicks.map((tick) => (
            <line
              key={`y-grid-${tick}`}
              x1={0}
              x2={innerWidth}
              y1={yScale(tick)}
              y2={yScale(tick)}
              stroke="hsl(var(--border))"
              strokeDasharray="3 3"
              strokeOpacity={0.5}
            />
          ))}

          {/* Contours */}
          {showContours &&
            contours.map((contour, i) => (
              <path
                key={`contour-${i}`}
                d={pathGenerator(contour) ?? ""}
                fill={densityColorScale(contour.value)}
                fillOpacity={0.6}
                stroke={densityColorScale(contour.value)}
                strokeWidth={0.5}
              />
            ))}

          {/* Points */}
          {showPoints &&
            data.map((d, i) => {
              const isHovered = hoveredPoint === i
              return (
                <circle
                  key={`point-${i}`}
                  cx={xScale(d.x)}
                  cy={yScale(d.y)}
                  r={isHovered ? pointRadius * 1.5 : pointRadius}
                  fill={pointColor}
                  fillOpacity={showContours ? 0.7 : 1}
                  stroke="#fff"
                  strokeWidth={1}
                  className="cursor-pointer transition-all duration-200"
                  onMouseEnter={() => setHoveredPoint(i)}
                  onMouseLeave={() => setHoveredPoint(null)}
                />
              )
            })}

          {/* X Axis */}
          <g transform={`translate(0, ${innerHeight})`}>
            <line x1={0} x2={innerWidth} stroke="hsl(var(--border))" />
            {xTicks.map((tick) => (
              <g key={tick} transform={`translate(${xScale(tick)}, 0)`}>
                <line y2={5} stroke="hsl(var(--border))" />
                <text
                  y={18}
                  textAnchor="middle"
                  className="fill-muted-foreground text-xs"
                >
                  {tick}
                </text>
              </g>
            ))}
            {xAxisLabel && (
              <text
                x={innerWidth / 2}
                y={40}
                textAnchor="middle"
                className="fill-foreground text-xs font-medium"
              >
                {xAxisLabel}
              </text>
            )}
          </g>

          {/* Y Axis */}
          <g>
            <line y1={0} y2={innerHeight} stroke="hsl(var(--border))" />
            {yTicks.map((tick) => (
              <g key={tick} transform={`translate(0, ${yScale(tick)})`}>
                <line x2={-5} stroke="hsl(var(--border))" />
                <text
                  x={-10}
                  textAnchor="end"
                  dominantBaseline="middle"
                  className="fill-muted-foreground text-xs"
                >
                  {tick}
                </text>
              </g>
            ))}
            {yAxisLabel && (
              <text
                transform={`translate(-45, ${innerHeight / 2}) rotate(-90)`}
                textAnchor="middle"
                className="fill-foreground text-xs font-medium"
              >
                {yAxisLabel}
              </text>
            )}
          </g>
        </g>
      </svg>

      {/* Tooltip */}
      {hoveredPoint !== null && (
        <div className="mt-2 text-center">
          <div className="border-border/50 bg-background mx-auto inline-block rounded-lg border px-3 py-2 text-sm shadow-lg">
            <div className="text-muted-foreground">
              x: {data[hoveredPoint].x.toFixed(2)}, y:{" "}
              {data[hoveredPoint].y.toFixed(2)}
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

"use client"

import * as React from "react"
import {
  forceCenter,
  forceCollide,
  forceLink,
  forceManyBody,
  forceSimulation,
  type SimulationLinkDatum,
  type SimulationNodeDatum,
} from "d3-force"

import { cn } from "@/lib/utils"

export interface NetworkNode extends SimulationNodeDatum {
  id: string
  label?: string
  group?: string
  size?: number
  color?: string
}

export interface NetworkLink extends SimulationLinkDatum<NetworkNode> {
  source: string | NetworkNode
  target: string | NetworkNode
  value?: number
  color?: string
}

export interface NetworkGraphProps {
  nodes: NetworkNode[]
  links: NetworkLink[]
  className?: string
  nodeRadius?: number
  linkWidth?: number
  showLabels?: boolean
  showArrows?: boolean
  charge?: number
  linkDistance?: number
  colorScheme?: string[]
}

export function NetworkGraph({
  nodes: initialNodes,
  links: initialLinks,
  className,
  nodeRadius = 8,
  linkWidth = 1.5,
  showLabels = true,
  showArrows = false,
  charge = -300,
  linkDistance = 100,
  colorScheme = ["#1e40af", "#2563eb", "#3b82f6", "#60a5fa", "#93c5fd"],
}: NetworkGraphProps) {
  const svgRef = React.useRef<SVGSVGElement>(null)
  const [nodes, setNodes] = React.useState<NetworkNode[]>([])
  const [links, setLinks] = React.useState<NetworkLink[]>([])
  const [hoveredNode, setHoveredNode] = React.useState<string | null>(null)

  const width = 500
  const height = 400

  // Get unique groups for coloring
  const groups = React.useMemo(() => {
    return [...new Set(initialNodes.map((n) => n.group ?? "default"))]
  }, [initialNodes])

  const getGroupColor = (group?: string) => {
    const index = groups.indexOf(group ?? "default")
    return colorScheme[index % colorScheme.length]
  }

  // Run force simulation
  React.useEffect(() => {
    const nodesCopy = initialNodes.map((n) => ({ ...n }))
    const linksCopy = initialLinks.map((l) => ({ ...l }))

    const simulation = forceSimulation<NetworkNode>(nodesCopy)
      .force(
        "link",
        forceLink<NetworkNode, NetworkLink>(linksCopy)
          .id((d) => d.id)
          .distance(linkDistance)
      )
      .force("charge", forceManyBody().strength(charge))
      .force("center", forceCenter(width / 2, height / 2))
      .force("collide", forceCollide(nodeRadius * 2))

    simulation.on("tick", () => {
      setNodes([...nodesCopy])
      setLinks([...linksCopy])
    })

    simulation.alpha(1).restart()

    return () => {
      simulation.stop()
    }
  }, [
    initialNodes,
    initialLinks,
    charge,
    linkDistance,
    nodeRadius,
    width,
    height,
  ])

  return (
    <div className={cn("w-full", className)}>
      <svg
        ref={svgRef}
        viewBox={`0 0 ${width} ${height}`}
        className="h-auto w-full overflow-visible"
      >
        {/* Arrow marker definition */}
        {showArrows && (
          <defs>
            <marker
              id="arrowhead"
              viewBox="0 -5 10 10"
              refX={20}
              refY={0}
              markerWidth={6}
              markerHeight={6}
              orient="auto"
            >
              <path d="M0,-5L10,0L0,5" fill="#94a3b8" />
            </marker>
          </defs>
        )}

        {/* Links */}
        <g>
          {links.map((link, index) => {
            const sourceNode = link.source as NetworkNode
            const targetNode = link.target as NetworkNode
            if (
              !sourceNode.x ||
              !sourceNode.y ||
              !targetNode.x ||
              !targetNode.y
            )
              return null

            const isConnectedToHovered =
              hoveredNode === sourceNode.id || hoveredNode === targetNode.id

            return (
              <line
                key={`link-${index}`}
                x1={sourceNode.x}
                y1={sourceNode.y}
                x2={targetNode.x}
                y2={targetNode.y}
                stroke={link.color ?? "#94a3b8"}
                strokeWidth={link.value ? linkWidth * link.value : linkWidth}
                strokeOpacity={
                  hoveredNode ? (isConnectedToHovered ? 1 : 0.2) : 0.6
                }
                markerEnd={showArrows ? "url(#arrowhead)" : undefined}
                className="transition-opacity duration-200"
              />
            )
          })}
        </g>

        {/* Nodes */}
        <g>
          {nodes.map((node) => {
            if (!node.x || !node.y) return null
            const color = node.color ?? getGroupColor(node.group)
            const isHovered = hoveredNode === node.id
            const isConnected = links.some(
              (l) =>
                (typeof l.source === "object" ? l.source.id : l.source) ===
                  node.id ||
                (typeof l.target === "object" ? l.target.id : l.target) ===
                  node.id
            )
            const radius = node.size ?? nodeRadius

            return (
              <g key={node.id}>
                <circle
                  cx={node.x}
                  cy={node.y}
                  r={isHovered ? radius * 1.3 : radius}
                  fill={color}
                  stroke="#fff"
                  strokeWidth={2}
                  className={cn(
                    "cursor-pointer transition-all duration-200",
                    hoveredNode && !isHovered && !isConnected && "opacity-30"
                  )}
                  onMouseEnter={() => setHoveredNode(node.id)}
                  onMouseLeave={() => setHoveredNode(null)}
                />
                {showLabels && (
                  <text
                    x={node.x}
                    y={node.y + radius + 14}
                    textAnchor="middle"
                    className={cn(
                      "fill-foreground text-[10px] transition-opacity duration-200",
                      hoveredNode && !isHovered && "opacity-30"
                    )}
                  >
                    {node.label ?? node.id}
                  </text>
                )}
              </g>
            )
          })}
        </g>
      </svg>

      {/* Legend */}
      {groups.length > 1 && (
        <div className="mt-3 flex flex-wrap justify-center gap-4">
          {groups.map((group) => (
            <div key={group} className="flex items-center gap-1.5 text-sm">
              <div
                className="h-3 w-3 rounded-full"
                style={{ backgroundColor: getGroupColor(group) }}
              />
              <span className="text-muted-foreground">{group}</span>
            </div>
          ))}
        </div>
      )}
    </div>
  )
}

"use client"

import * as React from "react"
import { cluster, hierarchy } from "d3-hierarchy"
import { linkHorizontal, linkVertical } from "d3-shape"

import { cn } from "@/lib/utils"

export interface DendrogramNode {
  name: string
  value?: number
  children?: DendrogramNode[]
  color?: string
}

export interface DendrogramProps {
  data: DendrogramNode
  className?: string
  orientation?: "horizontal" | "vertical"
  nodeRadius?: number
  showLabels?: boolean
  showValues?: boolean
  linkColor?: string
  colorScheme?: string[]
}

export function Dendrogram({
  data,
  className,
  orientation = "horizontal",
  nodeRadius = 5,
  showLabels = true,
  showValues = false,
  linkColor = "#94a3b8",
  colorScheme = ["#1e40af", "#2563eb", "#3b82f6", "#60a5fa", "#93c5fd"],
}: DendrogramProps) {
  const [hoveredNode, setHoveredNode] = React.useState<string | null>(null)

  const isHorizontal = orientation === "horizontal"
  const width = isHorizontal ? 600 : 400
  const height = isHorizontal ? 400 : 500
  const margin = isHorizontal
    ? { top: 20, right: 120, bottom: 20, left: 40 }
    : { top: 40, right: 20, bottom: 120, left: 20 }

  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom

  // Create hierarchy and apply cluster layout
  const root = React.useMemo(() => {
    const h = hierarchy(data)
    const clusterLayout = cluster<DendrogramNode>().size(
      isHorizontal ? [innerHeight, innerWidth] : [innerWidth, innerHeight]
    )

    return clusterLayout(h)
  }, [data, innerWidth, innerHeight, isHorizontal])

  // Get all nodes and links
  const nodes = root.descendants()
  const links = root.links()

  // Link generator
  const linkGenerator = isHorizontal
    ? linkHorizontal<any, any>()
        .x((d: any) => d.y)
        .y((d: any) => d.x)
    : linkVertical<any, any>()
        .x((d: any) => d.x)
        .y((d: any) => d.y)

  // Get color based on depth
  const getNodeColor = (depth: number) => {
    return colorScheme[depth % colorScheme.length]
  }

  // Check if node or any of its descendants is hovered
  const isNodeHighlighted = (node: (typeof nodes)[number]): boolean => {
    if (node.data.name === hoveredNode) return true
    if (node.ancestors().some((a) => a.data.name === hoveredNode)) return true
    if (node.descendants().some((d) => d.data.name === hoveredNode)) return true
    return false
  }

  return (
    <div className={cn("w-full", className)}>
      <svg
        viewBox={`0 0 ${width} ${height}`}
        className="h-auto w-full overflow-visible"
      >
        <g transform={`translate(${margin.left}, ${margin.top})`}>
          {/* Links */}
          {links.map((link, index) => {
            const isHighlighted =
              hoveredNode === null ||
              isNodeHighlighted(link.source) ||
              isNodeHighlighted(link.target)

            return (
              <path
                key={`link-${index}`}
                d={linkGenerator(link) ?? ""}
                fill="none"
                stroke={linkColor}
                strokeWidth={isHighlighted ? 2 : 1}
                strokeOpacity={
                  hoveredNode === null ? 0.6 : isHighlighted ? 1 : 0.15
                }
                className="transition-all duration-200"
              />
            )
          })}

          {/* Nodes */}
          {nodes.map((node, index) => {
            const x = isHorizontal ? node.y : node.x
            const y = isHorizontal ? node.x : node.y
            const isLeaf = !node.children
            const color = node.data.color ?? getNodeColor(node.depth)
            const isHovered = hoveredNode === node.data.name
            const isHighlighted =
              hoveredNode === null || isNodeHighlighted(node)

            return (
              <g
                key={`node-${index}`}
                transform={`translate(${x}, ${y})`}
                className={cn(
                  "cursor-pointer transition-opacity duration-200",
                  !isHighlighted && "opacity-20"
                )}
                onMouseEnter={() => setHoveredNode(node.data.name)}
                onMouseLeave={() => setHoveredNode(null)}
              >
                <circle
                  r={isHovered ? nodeRadius * 1.5 : nodeRadius}
                  fill={isLeaf ? color : "#fff"}
                  stroke={color}
                  strokeWidth={2}
                  className="transition-all duration-200"
                />

                {showLabels && (
                  <text
                    x={isHorizontal ? (isLeaf ? 10 : -10) : 0}
                    y={isHorizontal ? 0 : isLeaf ? 15 : -15}
                    textAnchor={
                      isHorizontal ? (isLeaf ? "start" : "end") : "middle"
                    }
                    dominantBaseline={
                      isHorizontal ? "middle" : isLeaf ? "hanging" : "auto"
                    }
                    className="fill-foreground text-[11px]"
                  >
                    {node.data.name}
                  </text>
                )}

                {showValues && node.data.value !== undefined && (
                  <text
                    x={isHorizontal ? (isLeaf ? 10 : -10) : 0}
                    y={isHorizontal ? 12 : isLeaf ? 28 : -28}
                    textAnchor={
                      isHorizontal ? (isLeaf ? "start" : "end") : "middle"
                    }
                    className="fill-muted-foreground text-[9px]"
                  >
                    {node.data.value}
                  </text>
                )}
              </g>
            )
          })}
        </g>
      </svg>

      {/* Tooltip */}
      {hoveredNode && (
        <div className="mt-2 text-center">
          <div className="border-border/50 bg-background mx-auto inline-block rounded-lg border px-3 py-2 text-sm shadow-lg">
            <div className="font-medium">{hoveredNode}</div>
            {nodes.find((n) => n.data.name === hoveredNode)?.data.value !==
              undefined && (
              <div className="text-muted-foreground">
                Value:{" "}
                {nodes.find((n) => n.data.name === hoveredNode)?.data.value}
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  )
}

"use client"

import * as React from "react"
import { scaleLinear } from "d3-scale"

import { cn } from "@/lib/utils"

export interface SplomDataPoint {
  id: string
  values: Record<string, number>
  group?: string
  color?: string
}

export interface SplomChartProps {
  data: SplomDataPoint[]
  dimensions: string[]
  className?: string
  cellSize?: number
  pointRadius?: number
  showLabels?: boolean
  showHistograms?: boolean
  colorScheme?: string[]
}

export function SplomChart({
  data,
  dimensions,
  className,
  cellSize = 100,
  pointRadius = 2.5,
  showLabels = true,
  showHistograms = true,
  colorScheme = ["#1e40af", "#dc2626", "#059669", "#d97706", "#7c3aed"],
}: SplomChartProps) {
  const [hoveredPoint, setHoveredPoint] = React.useState<string | null>(null)

  const n = dimensions.length
  const padding = 20
  const labelSize = showLabels ? 30 : 0
  const width = n * cellSize + labelSize
  const height = n * cellSize + labelSize

  // Get unique groups
  const groups = React.useMemo(() => {
    return [...new Set(data.map((d) => d.group ?? "default"))]
  }, [data])

  const getGroupColor = (group?: string) => {
    const index = groups.indexOf(group ?? "default")
    return colorScheme[index % colorScheme.length]
  }

  // Create scales for each dimension
  const scales = React.useMemo(() => {
    const result: Record<
      string,
      ReturnType<typeof scaleLinear<number, number>>
    > = {}

    dimensions.forEach((dim) => {
      const values = data
        .map((d) => d.values[dim])
        .filter((v) => v !== undefined)
      const min = Math.min(...values)
      const max = Math.max(...values)
      const pad = (max - min) * 0.1 || 1

      result[dim] = scaleLinear()
        .domain([min - pad, max + pad])
        .range([padding, cellSize - padding])
    })

    return result
  }, [data, dimensions, cellSize])

  // Generate histogram data for diagonal cells
  const getHistogramBins = (dim: string, binCount = 10) => {
    const values = data.map((d) => d.values[dim]).filter((v) => v !== undefined)
    const min = Math.min(...values)
    const max = Math.max(...values)
    const binWidth = (max - min) / binCount

    const bins = Array(binCount).fill(0)
    values.forEach((v) => {
      const binIndex = Math.min(Math.floor((v - min) / binWidth), binCount - 1)
      bins[binIndex]++
    })

    const maxBinCount = Math.max(...bins)
    return { bins, min, max, binWidth, maxBinCount }
  }

  return (
    <div className={cn("w-full overflow-auto", className)}>
      <svg
        width={width}
        height={height}
        viewBox={`0 0 ${width} ${height}`}
        className="overflow-visible"
      >
        {/* Matrix cells */}
        {dimensions.map((yDim, row) =>
          dimensions.map((xDim, col) => {
            const x = col * cellSize + labelSize
            const y = row * cellSize

            // Diagonal: histogram
            if (row === col && showHistograms) {
              const { bins, binWidth, min, maxBinCount } =
                getHistogramBins(xDim)
              const barWidth = (cellSize - 2 * padding) / bins.length
              const heightScale = (cellSize - 2 * padding) / maxBinCount

              return (
                <g key={`${row}-${col}`} transform={`translate(${x}, ${y})`}>
                  {/* Cell background */}
                  <rect
                    x={0}
                    y={0}
                    width={cellSize}
                    height={cellSize}
                    fill="hsl(var(--muted))"
                    fillOpacity={0.3}
                    stroke="hsl(var(--border))"
                    strokeWidth={0.5}
                  />
                  {/* Histogram bars */}
                  {bins.map((count, i) => (
                    <rect
                      key={i}
                      x={padding + i * barWidth}
                      y={cellSize - padding - count * heightScale}
                      width={barWidth - 1}
                      height={count * heightScale}
                      fill={colorScheme[0]}
                      fillOpacity={0.6}
                    />
                  ))}
                  {/* Dimension label */}
                  <text
                    x={cellSize / 2}
                    y={cellSize / 2}
                    textAnchor="middle"
                    dominantBaseline="middle"
                    className="fill-foreground text-[10px] font-medium"
                  >
                    {xDim}
                  </text>
                </g>
              )
            }

            // Off-diagonal: scatter plot
            return (
              <g key={`${row}-${col}`} transform={`translate(${x}, ${y})`}>
                {/* Cell background */}
                <rect
                  x={0}
                  y={0}
                  width={cellSize}
                  height={cellSize}
                  fill="hsl(var(--background))"
                  stroke="hsl(var(--border))"
                  strokeWidth={0.5}
                />
                {/* Points */}
                {data.map((d) => {
                  const xVal = d.values[xDim]
                  const yVal = d.values[yDim]
                  if (xVal === undefined || yVal === undefined) return null

                  const cx = scales[xDim](xVal)
                  const cy = cellSize - scales[yDim](yVal) + padding
                  const color = d.color ?? getGroupColor(d.group)
                  const isHovered = hoveredPoint === d.id

                  return (
                    <circle
                      key={d.id}
                      cx={cx}
                      cy={cy}
                      r={isHovered ? pointRadius * 1.8 : pointRadius}
                      fill={color}
                      fillOpacity={hoveredPoint ? (isHovered ? 1 : 0.2) : 0.7}
                      className="cursor-pointer transition-all duration-150"
                      onMouseEnter={() => setHoveredPoint(d.id)}
                      onMouseLeave={() => setHoveredPoint(null)}
                    />
                  )
                })}
              </g>
            )
          })
        )}

        {/* Row labels (left) */}
        {showLabels &&
          dimensions.map((dim, i) => (
            <text
              key={`row-${i}`}
              x={labelSize - 5}
              y={i * cellSize + cellSize / 2}
              textAnchor="end"
              dominantBaseline="middle"
              className="fill-muted-foreground text-[9px]"
            >
              {dim}
            </text>
          ))}

        {/* Column labels (bottom) */}
        {showLabels &&
          dimensions.map((dim, i) => (
            <text
              key={`col-${i}`}
              x={i * cellSize + labelSize + cellSize / 2}
              y={n * cellSize + 15}
              textAnchor="middle"
              className="fill-muted-foreground text-[9px]"
            >
              {dim}
            </text>
          ))}
      </svg>

      {/* Legend */}
      {groups.length > 1 && (
        <div className="mt-3 flex flex-wrap justify-center gap-4">
          {groups.map((group) => (
            <div key={group} className="flex items-center gap-1.5 text-sm">
              <div
                className="h-3 w-3 rounded-full"
                style={{ backgroundColor: getGroupColor(group) }}
              />
              <span className="text-muted-foreground">{group}</span>
            </div>
          ))}
        </div>
      )}

      {/* Tooltip */}
      {hoveredPoint && (
        <div className="mt-2 text-center">
          <div className="border-border/50 bg-background mx-auto inline-block rounded-lg border px-3 py-2 text-sm shadow-lg">
            <div className="font-medium">{hoveredPoint}</div>
            <div className="text-muted-foreground grid grid-cols-2 gap-x-3 text-xs">
              {dimensions.map((dim) => {
                const item = data.find((d) => d.id === hoveredPoint)
                return (
                  <React.Fragment key={dim}>
                    <span>{dim}:</span>
                    <span>{item?.values[dim]?.toFixed(2)}</span>
                  </React.Fragment>
                )
              })}
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

"use client"

import * as React from "react"
import { scaleBand, scalePoint } from "d3-scale"

import { cn } from "@/lib/utils"

export interface ParcatsDataPoint {
  id: string
  categories: Record<string, string>
  value?: number
  color?: string
}

export interface ParcatsChartProps {
  data: ParcatsDataPoint[]
  dimensions: string[]
  className?: string
  bundleColors?: boolean
  showCounts?: boolean
  lineOpacity?: number
  colorScheme?: string[]
}

export function ParcatsChart({
  data,
  dimensions,
  className,
  bundleColors = true,
  showCounts = true,
  lineOpacity = 0.5,
  colorScheme = [
    "#1e40af",
    "#2563eb",
    "#3b82f6",
    "#60a5fa",
    "#93c5fd",
    "#dc2626",
    "#059669",
    "#d97706",
  ],
}: ParcatsChartProps) {
  const [hoveredPath, setHoveredPath] = React.useState<string | null>(null)
  const [hoveredCategory, setHoveredCategory] = React.useState<{
    dim: string
    cat: string
  } | null>(null)

  const width = 600
  const height = 400
  const margin = { top: 40, right: 30, bottom: 30, left: 30 }
  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom

  // Get unique categories for each dimension
  const categoryData = React.useMemo(() => {
    const result: Record<string, string[]> = {}
    dimensions.forEach((dim) => {
      result[dim] = [...new Set(data.map((d) => d.categories[dim]))].sort()
    })
    return result
  }, [data, dimensions])

  // Get first dimension categories for coloring
  const firstDimCategories = categoryData[dimensions[0]] ?? []

  const getCategoryColor = (category: string) => {
    const index = firstDimCategories.indexOf(category)
    return colorScheme[index % colorScheme.length]
  }

  // X scale for dimensions
  const xScale = scalePoint<string>().domain(dimensions).range([0, innerWidth])

  // Y scales for each dimension (band scale for categories)
  const yScales = React.useMemo(() => {
    const scales: Record<string, ReturnType<typeof scaleBand<string>>> = {}

    dimensions.forEach((dim) => {
      scales[dim] = scaleBand<string>()
        .domain(categoryData[dim])
        .range([0, innerHeight])
        .padding(0.1)
    })

    return scales
  }, [dimensions, categoryData, innerHeight])

  // Count occurrences for each category
  const categoryCounts = React.useMemo(() => {
    const counts: Record<string, Record<string, number>> = {}
    dimensions.forEach((dim) => {
      counts[dim] = {}
      categoryData[dim].forEach((cat) => {
        counts[dim][cat] = data.filter((d) => d.categories[dim] === cat).length
      })
    })
    return counts
  }, [data, dimensions, categoryData])

  // Generate paths for each data point
  const paths = React.useMemo(() => {
    return data.map((d) => {
      const points = dimensions.map((dim, i) => {
        const x = xScale(dim) ?? 0
        const yBand = yScales[dim]
        const cat = d.categories[dim]
        const y = (yBand(cat) ?? 0) + yBand.bandwidth() / 2
        return { x, y }
      })

      // Create smooth path
      let pathD = `M ${points[0].x} ${points[0].y}`
      for (let i = 1; i < points.length; i++) {
        const prev = points[i - 1]
        const curr = points[i]
        const midX = (prev.x + curr.x) / 2
        pathD += ` C ${midX} ${prev.y}, ${midX} ${curr.y}, ${curr.x} ${curr.y}`
      }

      const color = bundleColors
        ? getCategoryColor(d.categories[dimensions[0]])
        : (d.color ?? colorScheme[0])

      return {
        id: d.id,
        d: pathD,
        color,
        categories: d.categories,
      }
    })
  }, [data, dimensions, xScale, yScales, bundleColors, colorScheme])

  // Check if path matches hovered category
  const isPathHighlighted = (path: (typeof paths)[0]) => {
    if (hoveredPath === path.id) return true
    if (hoveredCategory) {
      return path.categories[hoveredCategory.dim] === hoveredCategory.cat
    }
    return false
  }

  return (
    <div className={cn("w-full", className)}>
      <svg
        viewBox={`0 0 ${width} ${height}`}
        className="h-auto w-full overflow-visible"
      >
        <g transform={`translate(${margin.left}, ${margin.top})`}>
          {/* Category rectangles and labels */}
          {dimensions.map((dim) => {
            const x = xScale(dim) ?? 0
            const yBand = yScales[dim]

            return (
              <g key={dim}>
                {/* Dimension label */}
                <text
                  x={x}
                  y={-15}
                  textAnchor="middle"
                  className="fill-foreground text-xs font-medium"
                >
                  {dim}
                </text>

                {/* Category boxes */}
                {categoryData[dim].map((cat) => {
                  const y = yBand(cat) ?? 0
                  const h = yBand.bandwidth()
                  const count = categoryCounts[dim][cat]
                  const isHovered =
                    hoveredCategory?.dim === dim && hoveredCategory?.cat === cat

                  return (
                    <g
                      key={`${dim}-${cat}`}
                      className="cursor-pointer"
                      onMouseEnter={() => setHoveredCategory({ dim, cat })}
                      onMouseLeave={() => setHoveredCategory(null)}
                    >
                      <rect
                        x={x - 30}
                        y={y}
                        width={60}
                        height={h}
                        fill={
                          dim === dimensions[0]
                            ? getCategoryColor(cat)
                            : "hsl(var(--muted))"
                        }
                        fillOpacity={isHovered ? 1 : 0.8}
                        stroke="hsl(var(--border))"
                        strokeWidth={isHovered ? 2 : 1}
                        rx={3}
                        className="transition-all duration-150"
                      />
                      <text
                        x={x}
                        y={y + h / 2}
                        textAnchor="middle"
                        dominantBaseline="middle"
                        className="fill-foreground pointer-events-none text-[10px] font-medium"
                      >
                        {cat}
                      </text>
                      {showCounts && (
                        <text
                          x={x}
                          y={y + h / 2 + 10}
                          textAnchor="middle"
                          dominantBaseline="middle"
                          className="fill-muted-foreground pointer-events-none text-[8px]"
                        >
                          ({count})
                        </text>
                      )}
                    </g>
                  )
                })}
              </g>
            )
          })}

          {/* Flow paths */}
          {paths.map((path) => {
            const highlighted =
              hoveredPath !== null || hoveredCategory !== null
                ? isPathHighlighted(path)
                : true

            return (
              <path
                key={path.id}
                d={path.d}
                fill="none"
                stroke={path.color}
                strokeWidth={highlighted ? 2.5 : 1.5}
                strokeOpacity={
                  highlighted
                    ? hoveredPath === path.id || hoveredCategory
                      ? 0.9
                      : lineOpacity
                    : 0.1
                }
                className="cursor-pointer transition-all duration-150"
                onMouseEnter={() => setHoveredPath(path.id)}
                onMouseLeave={() => setHoveredPath(null)}
              />
            )
          })}
        </g>
      </svg>

      {/* Tooltip */}
      {hoveredPath && (
        <div className="mt-2 text-center">
          <div className="border-border/50 bg-background mx-auto inline-block rounded-lg border px-3 py-2 text-sm shadow-lg">
            <div className="font-medium">{hoveredPath}</div>
            <div className="text-muted-foreground text-xs">
              {dimensions.map((dim, i) => (
                <span key={dim}>
                  {paths.find((p) => p.id === hoveredPath)?.categories[dim]}
                  {i < dimensions.length - 1 && " → "}
                </span>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

export interface TernaryDataPoint {
  id: string
  a: number // Bottom-left axis (0-100 or 0-1)
  b: number // Bottom-right axis
  c: number // Top axis
  label?: string
  color?: string
  group?: string
  size?: number
}

export interface TernaryChartProps {
  data: TernaryDataPoint[]
  className?: string
  labels?: [string, string, string] // [A, B, C] axis labels
  showGrid?: boolean
  showLabels?: boolean
  gridLines?: number
  pointRadius?: number
  colorScheme?: string[]
  normalize?: boolean // Auto-normalize to sum=1
}

export function TernaryChart({
  data,
  className,
  labels = ["A", "B", "C"],
  showGrid = true,
  showLabels = true,
  gridLines = 5,
  pointRadius = 6,
  colorScheme = ["#1e40af", "#dc2626", "#059669", "#d97706", "#7c3aed"],
  normalize = true,
}: TernaryChartProps) {
  const [hoveredPoint, setHoveredPoint] = React.useState<string | null>(null)

  const width = 500
  const height = 450
  const margin = { top: 40, right: 40, bottom: 60, left: 40 }

  // Triangle dimensions
  const triangleHeight = height - margin.top - margin.bottom
  const triangleWidth = triangleHeight * (2 / Math.sqrt(3))
  const centerX = width / 2
  const topY = margin.top
  const bottomY = margin.top + triangleHeight

  // Triangle vertices
  const vertices = {
    top: { x: centerX, y: topY }, // C vertex
    bottomLeft: { x: centerX - triangleWidth / 2, y: bottomY }, // A vertex
    bottomRight: { x: centerX + triangleWidth / 2, y: bottomY }, // B vertex
  }

  // Get unique groups
  const groups = React.useMemo(() => {
    return [...new Set(data.map((d) => d.group ?? "default"))]
  }, [data])

  const getGroupColor = (group?: string) => {
    const index = groups.indexOf(group ?? "default")
    return colorScheme[index % colorScheme.length]
  }

  // Convert ternary coordinates to Cartesian
  const ternaryToCartesian = (a: number, b: number, c: number) => {
    // Normalize if needed
    const sum = a + b + c
    const na = normalize ? a / sum : a
    const nb = normalize ? b / sum : b
    const nc = normalize ? c / sum : c

    // Ternary to Cartesian transformation
    const x =
      vertices.bottomLeft.x +
      nb * (vertices.bottomRight.x - vertices.bottomLeft.x) +
      nc * (vertices.top.x - vertices.bottomLeft.x)
    const y =
      vertices.bottomLeft.y + nc * (vertices.top.y - vertices.bottomLeft.y)

    return { x, y }
  }

  // Generate grid lines
  const gridLineData = React.useMemo(() => {
    const lines: { x1: number; y1: number; x2: number; y2: number }[] = []

    for (let i = 1; i < gridLines; i++) {
      const t = i / gridLines

      // Lines parallel to bottom edge (constant C)
      const c1Start = ternaryToCartesian(1 - t, 0, t)
      const c1End = ternaryToCartesian(0, 1 - t, t)
      lines.push({ x1: c1Start.x, y1: c1Start.y, x2: c1End.x, y2: c1End.y })

      // Lines parallel to left edge (constant B)
      const b1Start = ternaryToCartesian(1 - t, t, 0)
      const b1End = ternaryToCartesian(0, t, 1 - t)
      lines.push({ x1: b1Start.x, y1: b1Start.y, x2: b1End.x, y2: b1End.y })

      // Lines parallel to right edge (constant A)
      const a1Start = ternaryToCartesian(t, 1 - t, 0)
      const a1End = ternaryToCartesian(t, 0, 1 - t)
      lines.push({ x1: a1Start.x, y1: a1Start.y, x2: a1End.x, y2: a1End.y })
    }

    return lines
  }, [gridLines, vertices])

  // Generate tick labels
  const tickLabels = React.useMemo(() => {
    const ticks: { x: number; y: number; value: string; anchor: string }[] = []

    for (let i = 0; i <= gridLines; i++) {
      const t = i / gridLines
      const value = Math.round(t * 100)

      // A axis (bottom-left to top)
      const aPos = ternaryToCartesian(1 - t, 0, t)
      ticks.push({
        x: aPos.x - 15,
        y: aPos.y,
        value: `${value}`,
        anchor: "end",
      })

      // B axis (bottom-left to bottom-right)
      const bPos = ternaryToCartesian(1 - t, t, 0)
      ticks.push({
        x: bPos.x,
        y: bPos.y + 18,
        value: `${value}`,
        anchor: "middle",
      })

      // C axis (top to bottom-right)
      const cPos = ternaryToCartesian(0, 1 - t, t)
      ticks.push({
        x: cPos.x + 15,
        y: cPos.y,
        value: `${value}`,
        anchor: "start",
      })
    }

    return ticks
  }, [gridLines, vertices])

  return (
    <div className={cn("w-full", className)}>
      <svg
        viewBox={`0 0 ${width} ${height}`}
        className="h-auto w-full overflow-visible"
      >
        {/* Triangle outline */}
        <polygon
          points={`${vertices.top.x},${vertices.top.y} ${vertices.bottomLeft.x},${vertices.bottomLeft.y} ${vertices.bottomRight.x},${vertices.bottomRight.y}`}
          fill="hsl(var(--muted))"
          fillOpacity={0.2}
          stroke="hsl(var(--border))"
          strokeWidth={1.5}
        />

        {/* Grid lines */}
        {showGrid &&
          gridLineData.map((line, i) => (
            <line
              key={`grid-${i}`}
              x1={line.x1}
              y1={line.y1}
              x2={line.x2}
              y2={line.y2}
              stroke="hsl(var(--border))"
              strokeWidth={0.5}
              strokeOpacity={0.5}
            />
          ))}

        {/* Axis labels */}
        {showLabels && (
          <>
            <text
              x={vertices.bottomLeft.x - 25}
              y={vertices.bottomLeft.y + 35}
              textAnchor="middle"
              className="fill-foreground text-sm font-medium"
            >
              {labels[0]}
            </text>
            <text
              x={vertices.bottomRight.x + 25}
              y={vertices.bottomRight.y + 35}
              textAnchor="middle"
              className="fill-foreground text-sm font-medium"
            >
              {labels[1]}
            </text>
            <text
              x={vertices.top.x}
              y={vertices.top.y - 15}
              textAnchor="middle"
              className="fill-foreground text-sm font-medium"
            >
              {labels[2]}
            </text>
          </>
        )}

        {/* Tick labels */}
        {showGrid &&
          tickLabels.map((tick, i) => (
            <text
              key={`tick-${i}`}
              x={tick.x}
              y={tick.y}
              textAnchor={tick.anchor}
              dominantBaseline="middle"
              className="fill-muted-foreground text-[8px]"
            >
              {tick.value}
            </text>
          ))}

        {/* Data points */}
        {data.map((d) => {
          const pos = ternaryToCartesian(d.a, d.b, d.c)
          const color = d.color ?? getGroupColor(d.group)
          const isHovered = hoveredPoint === d.id
          const radius = d.size ?? pointRadius

          return (
            <g key={d.id}>
              <circle
                cx={pos.x}
                cy={pos.y}
                r={isHovered ? radius * 1.5 : radius}
                fill={color}
                fillOpacity={hoveredPoint ? (isHovered ? 1 : 0.3) : 0.8}
                stroke="#fff"
                strokeWidth={1.5}
                className="cursor-pointer transition-all duration-150"
                onMouseEnter={() => setHoveredPoint(d.id)}
                onMouseLeave={() => setHoveredPoint(null)}
              />
              {isHovered && d.label && (
                <text
                  x={pos.x}
                  y={pos.y - radius - 8}
                  textAnchor="middle"
                  className="fill-foreground text-[10px] font-medium"
                >
                  {d.label}
                </text>
              )}
            </g>
          )
        })}
      </svg>

      {/* Legend */}
      {groups.length > 1 && (
        <div className="mt-3 flex flex-wrap justify-center gap-4">
          {groups.map((group) => (
            <div key={group} className="flex items-center gap-1.5 text-sm">
              <div
                className="h-3 w-3 rounded-full"
                style={{ backgroundColor: getGroupColor(group) }}
              />
              <span className="text-muted-foreground">{group}</span>
            </div>
          ))}
        </div>
      )}

      {/* Tooltip */}
      {hoveredPoint && (
        <div className="mt-2 text-center">
          <div className="border-border/50 bg-background mx-auto inline-block rounded-lg border px-3 py-2 text-sm shadow-lg">
            <div className="font-medium">
              {data.find((d) => d.id === hoveredPoint)?.label ?? hoveredPoint}
            </div>
            <div className="text-muted-foreground text-xs">
              {(() => {
                const point = data.find((d) => d.id === hoveredPoint)
                if (!point) return null
                const sum = point.a + point.b + point.c
                return (
                  <>
                    <div>
                      {labels[0]}: {((point.a / sum) * 100).toFixed(1)}%
                    </div>
                    <div>
                      {labels[1]}: {((point.b / sum) * 100).toFixed(1)}%
                    </div>
                    <div>
                      {labels[2]}: {((point.c / sum) * 100).toFixed(1)}%
                    </div>
                  </>
                )
              })()}
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

"use client"

import * as React from "react"
import { scaleBand, scaleLinear } from "d3-scale"
import { area, line, curveMonotoneX, curveLinear } from "d3-shape"

import { cn } from "@/lib/utils"

export interface RangeDataPoint {
  category: string
  low: number
  high: number
  mid?: number
  color?: string
}

export interface RangeChartProps {
  data: RangeDataPoint[]
  className?: string
  variant?: "area" | "bars" | "errorBars" | "floating"
  orientation?: "vertical" | "horizontal"
  showMidLine?: boolean
  showGrid?: boolean
  showValues?: boolean
  fillColor?: string
  strokeColor?: string
  midLineColor?: string
  lowLabel?: string
  highLabel?: string
  midLabel?: string
  valueFormatter?: (value: number) => string
}

export function RangeChart({
  data,
  className,
  variant = "area",
  orientation = "vertical",
  showMidLine = true,
  showGrid = true,
  showValues = false,
  fillColor = "#3b82f6",
  strokeColor = "#1d4ed8",
  midLineColor = "#1e40af",
  lowLabel = "Low",
  highLabel = "High",
  midLabel = "Average",
  valueFormatter = (v) => v.toLocaleString(),
}: RangeChartProps) {
  const [hoveredIndex, setHoveredIndex] = React.useState<number | null>(null)

  const isHorizontal = orientation === "horizontal"

  const width = isHorizontal ? 500 : 500
  const height = isHorizontal ? Math.max(280, data.length * 45 + 60) : 300
  const margin = isHorizontal
    ? { top: 30, right: 40, bottom: 30, left: 80 }
    : { top: 30, right: 30, bottom: 45, left: 55 }

  const innerWidth = width - margin.left - margin.right
  const innerHeight = height - margin.top - margin.bottom

  // Category Scale
  const categoryScale = React.useMemo(() => {
    const padding = variant === "area" ? 0.1 : variant === "errorBars" ? 0.5 : 0.25
    return scaleBand<string>()
      .domain(data.map((d) => d.category))
      .range(isHorizontal ? [0, innerHeight] : [0, innerWidth])
      .padding(padding)
  }, [data, innerWidth, innerHeight, variant, isHorizontal])

  // Value Scale
  const valueScale = React.useMemo(() => {
    const allValues = data.flatMap((d) => [d.low, d.high])
    if (showMidLine) {
      data.forEach((d) => {
        if (d.mid !== undefined) allValues.push(d.mid)
      })
    }
    const min = Math.min(...allValues)
    const max = Math.max(...allValues)
    const padding = (max - min) * 0.15 || 10

    return scaleLinear()
      .domain([Math.min(0, min - padding), max + padding])
      .range(isHorizontal ? [0, innerWidth] : [innerHeight, 0])
      .nice()
  }, [data, innerWidth, innerHeight, showMidLine, isHorizontal])

  const valueTicks = valueScale.ticks(5)

  // Area path generator
  const areaPath = React.useMemo(() => {
    if (variant !== "area") return ""

    const areaGenerator = area<RangeDataPoint>()
      .x((d) => (categoryScale(d.category) ?? 0) + categoryScale.bandwidth() / 2)
      .y0((d) => valueScale(d.low))
      .y1((d) => valueScale(d.high))
      .curve(curveMonotoneX)

    return areaGenerator(data) ?? ""
  }, [data, categoryScale, valueScale, variant])

  // Mid line path generator
  const midLinePath = React.useMemo(() => {
    if (!showMidLine || variant !== "area") return ""

    const lineGenerator = line<RangeDataPoint>()
      .x((d) => (categoryScale(d.category) ?? 0) + categoryScale.bandwidth() / 2)
      .y((d) => valueScale(d.mid ?? (d.low + d.high) / 2))
      .curve(curveMonotoneX)

    return lineGenerator(data) ?? ""
  }, [data, categoryScale, valueScale, showMidLine, variant])

  // Get position helpers
  const getX = (d: RangeDataPoint, position: "low" | "high" | "mid" | "center") => {
    if (isHorizontal) {
      if (position === "low") return valueScale(d.low)
      if (position === "high") return valueScale(d.high)
      if (position === "mid") return valueScale(d.mid ?? (d.low + d.high) / 2)
      return (categoryScale(d.category) ?? 0) + categoryScale.bandwidth() / 2
    }
    return (categoryScale(d.category) ?? 0) + categoryScale.bandwidth() / 2
  }

  const getY = (d: RangeDataPoint, position: "low" | "high" | "mid" | "center") => {
    if (isHorizontal) {
      return (categoryScale(d.category) ?? 0) + categoryScale.bandwidth() / 2
    }
    if (position === "low") return valueScale(d.low)
    if (position === "high") return valueScale(d.high)
    if (position === "mid") return valueScale(d.mid ?? (d.low + d.high) / 2)
    return (categoryScale(d.category) ?? 0) + categoryScale.bandwidth() / 2
  }

  // Get range display
  const getRangeDisplay = (d: RangeDataPoint) => {
    const range = d.high - d.low
    return `±${valueFormatter(range / 2)}`
  }

  return (
    <div className={cn("relative w-full", className)}>
      {/* Legend */}
      <div className="mb-3 flex items-center justify-center gap-6">
        <div className="flex items-center gap-2">
          <div
            className="h-3 w-6 rounded-sm opacity-40"
            style={{ backgroundColor: fillColor }}
          />
          <span className="text-muted-foreground text-sm">
            {lowLabel} - {highLabel}
          </span>
        </div>
        {showMidLine && (
          <div className="flex items-center gap-2">
            <div
              className="h-0.5 w-6"
              style={{ backgroundColor: midLineColor }}
            />
            <span className="text-muted-foreground text-sm">{midLabel}</span>
          </div>
        )}
      </div>

      <svg
        viewBox={`0 0 ${width} ${height}`}
        className="h-auto w-full overflow-visible"
      >
        <g transform={`translate(${margin.left}, ${margin.top})`}>
          {/* Grid lines */}
          {showGrid &&
            valueTicks.map((tick) => (
              <line
                key={tick}
                x1={isHorizontal ? valueScale(tick) : 0}
                x2={isHorizontal ? valueScale(tick) : innerWidth}
                y1={isHorizontal ? 0 : valueScale(tick)}
                y2={isHorizontal ? innerHeight : valueScale(tick)}
                stroke="#e5e7eb"
                strokeDasharray="3 3"
              />
            ))}

          {/* Baseline */}
          <line
            x1={0}
            x2={isHorizontal ? 0 : innerWidth}
            y1={isHorizontal ? 0 : innerHeight}
            y2={isHorizontal ? innerHeight : innerHeight}
            stroke="#e5e7eb"
          />

          {/* Area variant */}
          {variant === "area" && !isHorizontal && (
            <>
              <path
                d={areaPath}
                fill={fillColor}
                fillOpacity={0.25}
                stroke={strokeColor}
                strokeWidth={1.5}
              />
              {showMidLine && (
                <path
                  d={midLinePath}
                  fill="none"
                  stroke={midLineColor}
                  strokeWidth={2}
                  strokeDasharray="4 2"
                />
              )}
              {/* Hover points */}
              {data.map((d, i) => {
                const x = getX(d, "center")
                const midY = getY(d, "mid")
                const isHovered = hoveredIndex === i

                return (
                  <g
                    key={d.category}
                    className="cursor-pointer"
                    onMouseEnter={() => setHoveredIndex(i)}
                    onMouseLeave={() => setHoveredIndex(null)}
                    style={{
                      opacity: hoveredIndex !== null && !isHovered ? 0.4 : 1,
                      transition: "opacity 150ms",
                    }}
                  >
                    {/* Invisible hit area */}
                    <rect
                      x={x - categoryScale.bandwidth() / 2}
                      y={getY(d, "high")}
                      width={categoryScale.bandwidth()}
                      height={getY(d, "low") - getY(d, "high")}
                      fill="transparent"
                    />
                    {/* Mid point dot */}
                    {showMidLine && (
                      <circle
                        cx={x}
                        cy={midY}
                        r={isHovered ? 6 : 4}
                        fill={midLineColor}
                        stroke="white"
                        strokeWidth={2}
                        style={{ transition: "r 150ms" }}
                      />
                    )}
                    {/* High/Low markers on hover */}
                    {isHovered && (
                      <>
                        <circle cx={x} cy={getY(d, "high")} r={3} fill={strokeColor} />
                        <circle cx={x} cy={getY(d, "low")} r={3} fill={strokeColor} />
                      </>
                    )}
                  </g>
                )
              })}
            </>
          )}

          {/* Bars variant */}
          {variant === "bars" &&
            data.map((d, i) => {
              const isHovered = hoveredIndex === i
              const barColor = d.color ?? fillColor
              const mid = d.mid ?? (d.low + d.high) / 2

              if (isHorizontal) {
                const y = categoryScale(d.category) ?? 0
                const barHeight = categoryScale.bandwidth()
                const x1 = valueScale(d.low)
                const x2 = valueScale(d.high)

                return (
                  <g
                    key={d.category}
                    className="cursor-pointer"
                    onMouseEnter={() => setHoveredIndex(i)}
                    onMouseLeave={() => setHoveredIndex(null)}
                    style={{
                      opacity: hoveredIndex !== null && !isHovered ? 0.4 : 1,
                      transition: "opacity 150ms",
                    }}
                  >
                    <rect
                      x={x1}
                      y={y}
                      width={x2 - x1}
                      height={barHeight}
                      fill={barColor}
                      fillOpacity={isHovered ? 0.5 : 0.35}
                      stroke={strokeColor}
                      strokeWidth={1.5}
                      rx={3}
                      style={{ transition: "fill-opacity 150ms" }}
                    />
                    {showMidLine && (
                      <line
                        x1={valueScale(mid)}
                        x2={valueScale(mid)}
                        y1={y}
                        y2={y + barHeight}
                        stroke={midLineColor}
                        strokeWidth={2}
                      />
                    )}
                  </g>
                )
              }

              const x = categoryScale(d.category) ?? 0
              const barWidth = categoryScale.bandwidth()

              return (
                <g
                  key={d.category}
                  className="cursor-pointer"
                  onMouseEnter={() => setHoveredIndex(i)}
                  onMouseLeave={() => setHoveredIndex(null)}
                  style={{
                    opacity: hoveredIndex !== null && !isHovered ? 0.4 : 1,
                    transition: "opacity 150ms",
                  }}
                >
                  <rect
                    x={x}
                    y={valueScale(d.high)}
                    width={barWidth}
                    height={valueScale(d.low) - valueScale(d.high)}
                    fill={barColor}
                    fillOpacity={isHovered ? 0.5 : 0.35}
                    stroke={strokeColor}
                    strokeWidth={1.5}
                    rx={3}
                    style={{ transition: "fill-opacity 150ms" }}
                  />
                  {showMidLine && (
                    <line
                      x1={x}
                      x2={x + barWidth}
                      y1={valueScale(mid)}
                      y2={valueScale(mid)}
                      stroke={midLineColor}
                      strokeWidth={2}
                    />
                  )}
                </g>
              )
            })}

          {/* Error bars variant */}
          {variant === "errorBars" &&
            data.map((d, i) => {
              const isHovered = hoveredIndex === i
              const barColor = d.color ?? fillColor
              const mid = d.mid ?? (d.low + d.high) / 2
              const capSize = isHorizontal ? 6 : categoryScale.bandwidth() * 0.4

              if (isHorizontal) {
                const y = (categoryScale(d.category) ?? 0) + categoryScale.bandwidth() / 2
                const x1 = valueScale(d.low)
                const x2 = valueScale(d.high)
                const xMid = valueScale(mid)

                return (
                  <g
                    key={d.category}
                    className="cursor-pointer"
                    onMouseEnter={() => setHoveredIndex(i)}
                    onMouseLeave={() => setHoveredIndex(null)}
                    style={{
                      opacity: hoveredIndex !== null && !isHovered ? 0.4 : 1,
                      transition: "opacity 150ms",
                    }}
                  >
                    {/* Main line */}
                    <line
                      x1={x1}
                      x2={x2}
                      y1={y}
                      y2={y}
                      stroke={barColor}
                      strokeWidth={isHovered ? 3 : 2}
                      style={{ transition: "stroke-width 150ms" }}
                    />
                    {/* Low cap */}
                    <line
                      x1={x1}
                      x2={x1}
                      y1={y - capSize}
                      y2={y + capSize}
                      stroke={barColor}
                      strokeWidth={2}
                    />
                    {/* High cap */}
                    <line
                      x1={x2}
                      x2={x2}
                      y1={y - capSize}
                      y2={y + capSize}
                      stroke={barColor}
                      strokeWidth={2}
                    />
                    {/* Mid point */}
                    {showMidLine && (
                      <circle
                        cx={xMid}
                        cy={y}
                        r={isHovered ? 6 : 5}
                        fill={midLineColor}
                        stroke="white"
                        strokeWidth={2}
                        style={{ transition: "r 150ms" }}
                      />
                    )}
                  </g>
                )
              }

              const x = (categoryScale(d.category) ?? 0) + categoryScale.bandwidth() / 2
              const y1 = valueScale(d.high)
              const y2 = valueScale(d.low)
              const yMid = valueScale(mid)

              return (
                <g
                  key={d.category}
                  className="cursor-pointer"
                  onMouseEnter={() => setHoveredIndex(i)}
                  onMouseLeave={() => setHoveredIndex(null)}
                  style={{
                    opacity: hoveredIndex !== null && !isHovered ? 0.4 : 1,
                    transition: "opacity 150ms",
                  }}
                >
                  {/* Main line */}
                  <line
                    x1={x}
                    x2={x}
                    y1={y1}
                    y2={y2}
                    stroke={barColor}
                    strokeWidth={isHovered ? 3 : 2}
                    style={{ transition: "stroke-width 150ms" }}
                  />
                  {/* High cap */}
                  <line
                    x1={x - capSize}
                    x2={x + capSize}
                    y1={y1}
                    y2={y1}
                    stroke={barColor}
                    strokeWidth={2}
                  />
                  {/* Low cap */}
                  <line
                    x1={x - capSize}
                    x2={x + capSize}
                    y1={y2}
                    y2={y2}
                    stroke={barColor}
                    strokeWidth={2}
                  />
                  {/* Mid point */}
                  {showMidLine && (
                    <circle
                      cx={x}
                      cy={yMid}
                      r={isHovered ? 6 : 5}
                      fill={midLineColor}
                      stroke="white"
                      strokeWidth={2}
                      style={{ transition: "r 150ms" }}
                    />
                  )}
                </g>
              )
            })}

          {/* Floating bars variant */}
          {variant === "floating" &&
            data.map((d, i) => {
              const isHovered = hoveredIndex === i
              const barColor = d.color ?? fillColor
              const mid = d.mid ?? (d.low + d.high) / 2

              if (isHorizontal) {
                const y = categoryScale(d.category) ?? 0
                const barHeight = categoryScale.bandwidth()
                const x1 = valueScale(d.low)
                const x2 = valueScale(d.high)

                return (
                  <g
                    key={d.category}
                    className="cursor-pointer"
                    onMouseEnter={() => setHoveredIndex(i)}
                    onMouseLeave={() => setHoveredIndex(null)}
                    style={{
                      opacity: hoveredIndex !== null && !isHovered ? 0.4 : 1,
                      transition: "opacity 150ms",
                    }}
                  >
                    <rect
                      x={x1}
                      y={y}
                      width={x2 - x1}
                      height={barHeight}
                      fill={barColor}
                      fillOpacity={isHovered ? 0.8 : 0.6}
                      rx={4}
                      style={{ transition: "fill-opacity 150ms" }}
                    />
                    {showMidLine && (
                      <circle
                        cx={valueScale(mid)}
                        cy={y + barHeight / 2}
                        r={isHovered ? 5 : 4}
                        fill="white"
                        stroke={midLineColor}
                        strokeWidth={2}
                        style={{ transition: "r 150ms" }}
                      />
                    )}
                  </g>
                )
              }

              const x = categoryScale(d.category) ?? 0
              const barWidth = categoryScale.bandwidth()

              return (
                <g
                  key={d.category}
                  className="cursor-pointer"
                  onMouseEnter={() => setHoveredIndex(i)}
                  onMouseLeave={() => setHoveredIndex(null)}
                  style={{
                    opacity: hoveredIndex !== null && !isHovered ? 0.4 : 1,
                    transition: "opacity 150ms",
                  }}
                >
                  <rect
                    x={x}
                    y={valueScale(d.high)}
                    width={barWidth}
                    height={valueScale(d.low) - valueScale(d.high)}
                    fill={barColor}
                    fillOpacity={isHovered ? 0.8 : 0.6}
                    rx={4}
                    style={{ transition: "fill-opacity 150ms" }}
                  />
                  {showMidLine && (
                    <circle
                      cx={x + barWidth / 2}
                      cy={valueScale(mid)}
                      r={isHovered ? 5 : 4}
                      fill="white"
                      stroke={midLineColor}
                      strokeWidth={2}
                      style={{ transition: "r 150ms" }}
                    />
                  )}
                </g>
              )
            })}

          {/* Category labels */}
          {data.map((d) => {
            if (isHorizontal) {
              const y = (categoryScale(d.category) ?? 0) + categoryScale.bandwidth() / 2
              return (
                <text
                  key={`label-${d.category}`}
                  x={-12}
                  y={y}
                  textAnchor="end"
                  dominantBaseline="middle"
                  fontSize={11}
                  className="fill-foreground"
                >
                  {d.category}
                </text>
              )
            }

            const x = (categoryScale(d.category) ?? 0) + categoryScale.bandwidth() / 2
            return (
              <text
                key={`label-${d.category}`}
                x={x}
                y={innerHeight + 20}
                textAnchor="middle"
                fontSize={11}
                className="fill-foreground"
              >
                {d.category}
              </text>
            )
          })}

          {/* Value axis labels */}
          {valueTicks.map((tick) => (
            <text
              key={`tick-${tick}`}
              x={isHorizontal ? valueScale(tick) : -10}
              y={isHorizontal ? innerHeight + 18 : valueScale(tick)}
              textAnchor={isHorizontal ? "middle" : "end"}
              dominantBaseline={isHorizontal ? "auto" : "middle"}
              fontSize={11}
              className="fill-muted-foreground"
            >
              {valueFormatter(tick)}
            </text>
          ))}
        </g>
      </svg>

      {/* Tooltip */}
      {hoveredIndex !== null && (
        <div className="bg-foreground text-background pointer-events-none absolute left-1/2 top-12 z-50 -translate-x-1/2 rounded-md px-3 py-2 text-xs font-medium shadow-lg">
          <div className="mb-1 font-semibold">{data[hoveredIndex].category}</div>
          <div className="space-y-0.5 opacity-90">
            <div>
              {highLabel}: {valueFormatter(data[hoveredIndex].high)}
            </div>
            {data[hoveredIndex].mid !== undefined && (
              <div>
                {midLabel}: {valueFormatter(data[hoveredIndex].mid!)}
              </div>
            )}
            <div>
              {lowLabel}: {valueFormatter(data[hoveredIndex].low)}
            </div>
          </div>
          <div className="mt-1.5 border-t border-white/20 pt-1.5 text-center opacity-70">
            Range: {getRangeDisplay(data[hoveredIndex])}
          </div>
        </div>
      )}
    </div>
  )
}
